class AspelCOI:
    def __init__(self):
        self.root = tk.Tk()
        # Config / tema lo más temprano posible.
        self.config_parametros = ConfigParametros()
        self._aplicar_tema_ui(self.config_parametros.obtener_ui_theme())
        self.root.title(THEME["app_name"])
        self.root.configure(bg=THEME["bg_root"])
        self._aplicar_icono_ventana()
        try:
            self.root.update_idletasks()
            sw = max(self.root.winfo_screenwidth(), 1024)
            sh = max(self.root.winfo_screenheight(), 600)
            rw = max(1000, int(sw * 0.92))
            rh = max(620, int(sh * 0.88))
            x = max(0, (sw - rw) // 2)
            y = max(0, int((sh - rh) * 0.04))
            self.root.geometry(f"{rw}x{rh}+{x}+{y}")
        except tk.TclError:
            self.root.geometry("1280x768")
        self.root.minsize(1000, 600)
        self.configurar_estilos_globales()
        try:
            self.root.option_add("*Menu.font", (THEME["font_ui"], 8))
        except tk.TclError:
            pass

        # Inicializar modelos
        self.catalogo = CatalogoCuentas()
        self.polizas = SistemaPolizas()
        self.libro_contable = LibroContableManager(db_path=self.polizas.db_path)
        self.reportes = ReportesContables()
        self.impresion = ImpresionManager()
        self.bancos = SistemaBancos()
        self.cfdi_dashboard = CFDIDashboard()
        self.usuarios_sistema = SistemaUsuarios()
        # self.config_parametros ya se inicializó arriba para leer UI_THEME
        self.contabilidad_service = ContabilidadService()
        self.auto_analisis_activo = False
        self.auto_analisis_ms = 5 * 60 * 1000
        self._auto_analisis_after_id = None
        self.cfd_config = CFDConfigManager(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
        # Caché breve para FIX USD/MXN por fecha (evita repetir red al capturar pólizas).
        self._tc_fix_cache = {}  # fecha YYYY-MM-DD -> (time.monotonic, valor, fuente o None)
        self._monedas_after_id = None  # temporizador rejilla Monedas (refresco desde BD)
        self._tipo_cambio_usar = None  # última moneda / TC elegidos con «Usar» en Monedas

