    def _reload_db_models(self):
        """Reinstancia modelos para tomar la BD activa (multiempresa)."""
        self.catalogo = CatalogoCuentas()
        self.polizas = SistemaPolizas()
        self.libro_contable = LibroContableManager(db_path=self.polizas.db_path)
        self.reportes = ReportesContables()
        self.bancos = SistemaBancos()
        self.cfdi_dashboard = CFDIDashboard()
        self.contabilidad_service = ContabilidadService()

        # Mostrar novedades (1 vez por versión) después de dibujar UI.
        try:
            self.root.after(350, self._mostrar_novedades_si_aplica)
        except Exception:
            pass

        # Contabilizar en automático las facturas timbradas que aún no tengan póliza (para que los 116 pesos ya aparezcan)
        self.root.after(1500, self._contabilizar_facturas_timbradas_automatico)
        # Sincroniza tablero CFDI al iniciar para traer historial local.
        self.root.after(2000, self._sync_cfdi_dashboard_startup)
        
    def _contabilizar_facturas_timbradas_automatico(self):
        """Al iniciar el programa, contabiliza los XML en facturas_timbradas que no tengan póliza aún (sin preguntar)."""
        try:
            from backend.modules.contabilizar_xml import contabilizar_carpeta
        except ImportError:
            return
        raiz_proy = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
        folder = os.path.join(raiz_proy, "facturas_timbradas")
        if not os.path.isdir(folder):
            return
        resultados = contabilizar_carpeta(folder)
        creadas = sum(1 for r in resultados if r.get("exito") and "Ya estaba" not in (r.get("mensaje") or ""))
        try:
            self.polizas.recalcular_saldos_mensuales()
        except Exception:
            pass
        if creadas > 0:
            try:
                if hasattr(self, "actualizar_catalogo"):
                    self.actualizar_catalogo()
            except Exception:
                pass
            self.set_status(f"Se contabilizaron {creadas} factura(s) timbrada(s) en automático.")
        
