    def _aplicar_tema_ui(self, modo: str) -> None:
        """Aplica paleta global (claro/oscuro) a THEME."""
        m = (modo or "light").strip().lower()
        if m not in ("light", "dark"):
            m = "light"
        snap = THEME_DARK_SNAP if m == "dark" else THEME_LIGHT_SNAP
        THEME.update(snap)
        self._ui_theme_mode = m

    def _mapa_colores_cambio_tema(self, modo_anterior: str, modo_nuevo: str) -> dict:
        """Hex antiguo → hex nuevo entre dos modos (para repintar widgets tk)."""
        old_s = THEME_LIGHT_SNAP if modo_anterior == "light" else THEME_DARK_SNAP
        new_s = THEME_LIGHT_SNAP if modo_nuevo == "light" else THEME_DARK_SNAP
        skip = {"font_ui", "font_size", "app_name", "app_version", "explorador_alto_default"}
        cmap = {}
        for k in old_s:
            if k in skip:
                continue
            a, b = old_s.get(k), new_s.get(k)
            if isinstance(a, str) and a.startswith("#") and a != b:
                cmap[a] = b
        for k, v in list(cmap.items()):
            cmap[k.lower()] = v
        return cmap

    def _repintar_arbol_tema(self, cmap: dict) -> None:
        """Actualiza colores de widgets tk (no ttk) tras un cambio de tema."""

        def _map_val(c):
            if not c or not isinstance(c, str):
                return None
            c = c.strip()
            if c in cmap:
                return cmap[c]
            cl = c.lower()
            if cl in cmap:
                return cmap[cl]
            u = c.upper()
            if cl in ("black", "#000000"):
                return THEME["text_primary"]
            if cl in ("white", "#ffffff"):
                return THEME["bg_content"]
            if u == "#C0C0C0":
                return THEME["btn_secondary_bg"]
            if u == "#1F2937":
                return THEME["text_primary"]
            if u == "#FEFCE8":
                return THEME.get("tooltip_bg", THEME["row_alt"])
            if getattr(self, "_ui_theme_mode", "light") == "dark":
                if cl in ("systembuttontext", "systemwindowtext", "systemgraytext"):
                    return THEME["text_primary"]
            return None

        def visit(w):
            try:
                if isinstance(w, TtkWidget):
                    for ch in w.winfo_children():
                        visit(ch)
                    return
            except tk.TclError:
                return
            try:
                cls = w.winfo_class()
            except tk.TclError:
                return
            try:
                options = w.configure()
                for opt in ("bg", "highlightbackground", "highlightcolor"):
                    if opt in options:
                        cur = w.cget(opt)
                        nv = _map_val(cur)
                        if nv:
                            w.configure(**{opt: nv})
                if "fg" in options:
                    cur = w.cget("fg")
                    nv = _map_val(cur)
                    if nv:
                        w.configure(fg=nv)
                    elif getattr(self, "_ui_theme_mode", "light") == "dark" and cls in ("Label", "Checkbutton", "Radiobutton"):
                        try:
                            bgv = w.cget("bg")
                        except tk.TclError:
                            bgv = ""
                        dark_surfaces = {
                            THEME["bg_sidebar"],
                            THEME["bg_content"],
                            THEME["bg_root"],
                            THEME["header_bg"],
                            THEME["row_alt"],
                            THEME["row_child"],
                            THEME["btn_secondary_bg"],
                            THEME.get("bg_toolbar", ""),
                        }
                        if bgv in dark_surfaces:
                            try:
                                c2 = (cur or "").strip()
                                if c2 in ("", "black", "#000000") or (
                                    isinstance(c2, str)
                                    and len(c2) == 7
                                    and c2.startswith("#")
                                    and int(c2[1:3], 16) + int(c2[3:5], 16) + int(c2[5:7], 16) < 420
                                ):
                                    w.configure(fg=THEME["text_primary"])
                            except Exception:
                                w.configure(fg=THEME["text_primary"])
                if cls == "Button":
                    for opt in ("activebackground", "activeforeground", "disabledforeground"):
                        if opt in options:
                            cur = w.cget(opt)
                            nv = _map_val(cur)
                            if nv:
                                w.configure(**{opt: nv})
                    if getattr(self, "_ui_theme_mode", "light") == "dark" and "fg" in options:
                        try:
                            fgc = w.cget("fg")
                            bgc = w.cget("bg")
                            if bgc == THEME["btn_secondary_bg"] and (
                                not fgc
                                or (isinstance(fgc, str) and fgc.lower() in ("black", "#000000"))
                                or (
                                    isinstance(fgc, str)
                                    and len(fgc) == 7
                                    and fgc.startswith("#")
                                    and int(fgc[1:3], 16) + int(fgc[3:5], 16) + int(fgc[5:7], 16) < 420
                                )
                            ):
                                w.configure(fg=THEME["text_primary"])
                        except tk.TclError:
                            pass
                if cls in ("Text", "Entry", "Listbox"):
                    for opt in ("insertbackground", "selectbackground", "selectforeground"):
                        if opt in options:
                            cur = w.cget(opt)
                            nv = _map_val(cur)
                            if nv:
                                w.configure(**{opt: nv})
            except tk.TclError:
                pass
            for ch in w.winfo_children():
                visit(ch)

        visit(self.root)

    def refrescar_tema_en_vivo(self, nuevo_modo: str) -> None:
        """Persiste el tema, actualiza THEME, estilos ttk y repinta widgets tk abiertos."""
        m = (nuevo_modo or "light").strip().lower()
        if m not in ("light", "dark"):
            m = "light"
        old = getattr(self, "_ui_theme_mode", "light")
        cmap = self._mapa_colores_cambio_tema(old, m)
        self._aplicar_tema_ui(m)
        self.configurar_estilos_globales()
        try:
            self.root.configure(bg=THEME["bg_root"])
            self.root.option_add("*Background", THEME["bg_content"])
            self.root.option_add("*Foreground", THEME["text_primary"])
        except tk.TclError:
            pass
        self._repintar_arbol_tema(cmap)
        try:
            self._tree_catalogo_refrescar_tags_tema()
        except Exception:
            pass
        try:
            self._refrescar_explorador_tras_tema()
        except Exception:
            pass
        self.set_status("Tema aplicado.")
        try:
            self._asistente_retheme_si_abierto()
        except Exception:
            pass
        # Retheme de barras personalizadas (si existen).
        try:
            for w in self.root.winfo_children():
                if isinstance(w, tk.Toplevel):
                    fn = getattr(w, "_window_controls_retheme", None)
                    if callable(fn):
                        fn()
        except Exception:
            pass
        try:
            self.root.update_idletasks()
        except tk.TclError:
            pass

