    def _asistente_retheme_si_abierto(self) -> None:
        w = getattr(self, "_asistente_win", None)
        if w is None:
            return
        try:
            if not w.winfo_exists():
                self._asistente_win = None
                return
        except tk.TclError:
            self._asistente_win = None
            return
        fn = getattr(w, "_asistente_retheme", None)
        if callable(fn):
            fn()

    def _aplicar_icono_ventana(self) -> None:
        """Icono de ventana y barra de tareas: assets/app.ico o logo.png / ssepi_logo.png."""
        base = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
        self._icon_photo = None
        for name in ("assets/app.ico", "assets/logo.ico"):
            p = os.path.join(base, *name.split("/"))
            if os.path.isfile(p):
                try:
                    self.root.iconbitmap(p)
                    return
                except tk.TclError:
                    pass
        for name in ("assets/logo.png", "logo.png", "assets/ssepi_logo.png"):
            p = os.path.join(base, *name.split("/"))
            if os.path.isfile(p):
                try:
                    self._icon_photo = tk.PhotoImage(file=p)
                    self.root.iconphoto(True, self._icon_photo)
                    return
                except tk.TclError:
                    pass

