    def crear_toolbar(self):
        """Barra de herramientas con estilo moderno."""
        # Un poco más alta para permitir icono + texto sin desperdiciar espacio horizontal.
        toolbar = tk.Frame(self.root, bg=THEME["bg_toolbar"], height=56, relief=tk.FLAT, highlightthickness=1, highlightbackground=THEME["border"])
        toolbar.pack(side=tk.TOP, fill=tk.X)
        toolbar.pack_propagate(False)

        # Logo SSEPI (izquierda)
        try:
            logo_path = os.path.abspath(os.path.join(os.path.dirname(os.path.abspath(__file__)), "..", "assets", "ssepi_logo.png"))
            if os.path.exists(logo_path):
                # Preferir PIL para mantener proporción y buena calidad
                try:
                    from PIL import Image, ImageTk
                    img = Image.open(logo_path)
                    th = 26
                    tw = int((img.width / img.height) * th) if img.height else 90
                    img = img.resize((max(1, tw), th))
                    self._ssepi_logo_img_small = ImageTk.PhotoImage(img)
                except Exception:
                    self._ssepi_logo_img = tk.PhotoImage(file=logo_path)
                    # escalar a altura ~26px (mantiene proporción por subsample)
                    h = max(1, int(self._ssepi_logo_img.height() / 26))
                    w = max(1, int(self._ssepi_logo_img.width() / 26))
                    self._ssepi_logo_img_small = self._ssepi_logo_img.subsample(w, h)
                tk.Label(toolbar, image=self._ssepi_logo_img_small, bg=THEME["bg_toolbar"]).pack(side=tk.LEFT, padx=(8, 8), pady=4)
        except Exception:
            pass
        
        self._btn_toolbar_panel_lateral = tk.Button(
            toolbar,
            text="☰",
            command=self._toggle_panel_lateral_modulo,
            bg=THEME["bg_toolbar"],
            fg=THEME["text_primary"],
            activebackground=THEME["border"],
            relief=tk.FLAT,
            bd=0,
            padx=6,
            pady=6,
            cursor="hand2",
            font=(THEME["font_ui"], 12),
        )
        self._btn_toolbar_panel_lateral.pack(side=tk.LEFT, padx=(4, 2), pady=4)
        self._btn_toolbar_panel_lateral.bind(
            "<Enter>", lambda e, b=self._btn_toolbar_panel_lateral: b.configure(bg=THEME["border"])
        )
        self._btn_toolbar_panel_lateral.bind(
            "<Leave>", lambda e, b=self._btn_toolbar_panel_lateral: b.configure(bg=THEME["bg_toolbar"])
        )
        self.crear_tooltip(self._btn_toolbar_panel_lateral, "Mostrar / ocultar panel lateral de módulo (Ctrl+Shift+L)")
        self._btn_toolbar_explorador = tk.Button(
            toolbar,
            text="▼",
            command=self._toggle_explorador_cuerpo,
            bg=THEME["bg_toolbar"],
            fg=THEME["text_primary"],
            activebackground=THEME["border"],
            relief=tk.FLAT,
            bd=0,
            padx=6,
            pady=6,
            cursor="hand2",
            font=(THEME["font_ui"], 11),
        )
        self._btn_toolbar_explorador.pack(side=tk.LEFT, padx=(0, 8), pady=4)
        self._btn_toolbar_explorador.bind(
            "<Enter>", lambda e, b=self._btn_toolbar_explorador: b.configure(bg=THEME["border"])
        )
        self._btn_toolbar_explorador.bind(
            "<Leave>", lambda e, b=self._btn_toolbar_explorador: b.configure(bg=THEME["bg_toolbar"])
        )
        self.crear_tooltip(self._btn_toolbar_explorador, "Plegar / desplegar iconos del explorador (Ctrl+Shift+E)")
        
        # Botones compactos: icono + texto (2 líneas) para ocupar menos ancho
        botones = [
            ("📁", "Nueva", "Nueva empresa (Ctrl+N)", self.nueva_empresa),
            ("📂", "Abrir", "Abrir empresa (Ctrl+O)", self.abrir_empresa),
            ("💾", "Guardar", "Guardar (Ctrl+G)", self.guardar_cambios),
            ("🔗", "Proveedor", "Seleccionar proveedor de timbrado", self.seleccionar_proveedor),
            ("📄", "Póliza", "Nueva póliza", self.nueva_poliza),
            ("🔍", "Buscar", "Buscar (Ctrl+B)", self.buscar),
            ("🖨️", "Imprimir", "Imprimir (Ctrl+P)", self.imprimir),
            ("⚖️", "Balanza", "Balanza", self.mostrar_balanza),
            ("📊", "Resultados", "Resultados", self.mostrar_resultados),
            ("📈", "Balance", "Balance", self.mostrar_balance),
            ("➕", "Cuenta", "Agregar cuenta", self.nueva_cuenta),
            ("✏️", "Editar", "Editar", self.editar_seleccion),
            ("🗑️", "Eliminar", "Eliminar", self.eliminar_seleccion),
            ("🔁", "Actualizar", "Actualizar", self.actualizar_todo),
            ("🧭", "Guía", "Asistente guiado (Ctrl+Shift+A)", self.mostrar_asistente_gui),
            ("❓", "Ayuda", "Ayuda (F1)", self.acerca_de),
        ]
        
        for icono, nombre, tooltip, comando in botones:
            btn = tk.Button(
                toolbar,
                text=f"{icono}\n{nombre}",
                command=comando,
                bg=THEME["bg_toolbar"],
                fg=THEME["text_primary"],
                activebackground=THEME["border"],
                relief=tk.FLAT,
                bd=0,
                padx=6,
                pady=2,
                cursor="hand2",
                font=(THEME["font_ui"], 8),
                justify="center",
            )
            btn.pack(side=tk.LEFT, padx=1, pady=4)
            btn.bind("<Enter>", lambda e, b=btn: b.configure(bg=THEME["border"]))
            btn.bind("<Leave>", lambda e, b=btn: b.configure(bg=THEME["bg_toolbar"]))
            self.crear_tooltip(btn, tooltip)
    
    def crear_tooltip(self, widget, texto):
        def enter(event):
            x, y, _, _ = widget.bbox("insert")
            x += widget.winfo_rootx() + 25
            y += widget.winfo_rooty() + 25
            self.tooltip = tk.Toplevel(widget)
            self.tooltip.wm_overrideredirect(True)
            self.tooltip.wm_geometry(f"+{x}+{y}")
            label = tk.Label(
                self.tooltip,
                text=texto,
                bg=THEME.get("tooltip_bg", THEME["row_alt"]),
                fg=THEME.get("tooltip_fg", THEME["text_primary"]),
                relief=tk.FLAT,
                padx=6,
                pady=4,
                font=(THEME["font_ui"], 8),
            )
            label.pack()
        
        def leave(event):
            if hasattr(self, 'tooltip'):
                self.tooltip.destroy()
        
        widget.bind("<Enter>", enter)
        widget.bind("<Leave>", leave)

