    def _toplevel_geometry_work_area(self, win: tk.Toplevel) -> None:
        """Ajusta la ventana al área útil del escritorio (no tapa la barra de tareas en Windows)."""
        try:
            try:
                win.state("normal")
            except tk.TclError:
                pass
            if sys.platform == "win32":
                import ctypes
                from ctypes import wintypes

                class _RECT(ctypes.Structure):
                    _fields_ = [
                        ("left", wintypes.LONG),
                        ("top", wintypes.LONG),
                        ("right", wintypes.LONG),
                        ("bottom", wintypes.LONG),
                    ]

                r = _RECT()
                SPI_GETWORKAREA = 48
                if ctypes.windll.user32.SystemParametersInfoW(SPI_GETWORKAREA, 0, ctypes.byref(r), 0):
                    w = max(400, int(r.right - r.left))
                    h = max(300, int(r.bottom - r.top))
                    x = int(r.left)
                    y = int(r.top)
                    try:
                        win.maxsize(w, h)
                    except tk.TclError:
                        pass
                    win.geometry(f"{w}x{h}+{x}+{y}")
                    try:
                        win.update_idletasks()
                    except tk.TclError:
                        pass
                    return
        except Exception:
            pass
        try:
            sw = win.winfo_screenwidth()
            sh = win.winfo_screenheight()
            margin = 52
            try:
                win.maxsize(sw, max(300, sh - margin))
            except tk.TclError:
                pass
            win.geometry(f"{sw}x{sh - margin}+0+0")
        except tk.TclError:
            pass

    def _agregar_controles_ventana(self, win: tk.Toplevel, header_parent: tk.Widget, on_close=None):
        """Agrega botones: minimizar, maximizar, ajustar, cerrar (estilo THEME)."""
        bar = tk.Frame(header_parent, bg=THEME["header_bg"])
        bar.pack(side=tk.RIGHT, padx=8, pady=6)

        def _btn(txt, cmd, danger=False):
            b = tk.Button(
                bar,
                text=txt,
                command=cmd,
                bg=THEME["header_bg"] if not danger else "#991b1b",
                fg=THEME["header_fg"],
                activebackground=THEME["accent"] if not danger else "#dc2626",
                activeforeground=THEME["header_fg"],
                relief=tk.FLAT,
                bd=0,
                padx=10,
                pady=2,
                cursor="hand2",
                font=(THEME["font_ui"], 9, "bold"),
            )
            b.pack(side=tk.LEFT, padx=2)
            return b

        def _min():
            try:
                win.iconify()
            except tk.TclError:
                pass

        def _max():
            try:
                st = str(win.state()).lower()
                if st == "zoomed":
                    win.state("normal")
                else:
                    win.state("zoomed")
            except tk.TclError:
                self._toplevel_geometry_work_area(win)

        def _fit():
            self._toplevel_geometry_work_area(win)

        def _close():
            if callable(on_close):
                try:
                    on_close()
                    return
                except Exception:
                    pass
            try:
                win.destroy()
            except tk.TclError:
                pass

        b_min = _btn("—", _min)
        b_max = _btn("□", _max)
        b_fit = _btn("⤢", _fit)
        b_close = _btn("✕", _close, danger=True)

        def _retheme():
            try:
                bar.configure(bg=THEME["header_bg"])
                for b in (b_min, b_max, b_fit):
                    b.configure(
                        bg=THEME["header_bg"],
                        fg=THEME["header_fg"],
                        activebackground=THEME["accent"],
                        activeforeground=THEME["header_fg"],
                    )
                b_close.configure(
                    bg="#991b1b",
                    fg=THEME["header_fg"],
                    activebackground="#dc2626",
                    activeforeground=THEME["header_fg"],
                )
            except tk.TclError:
                pass

        win._window_controls_retheme = _retheme
        return bar

    def _refrescar_explorador_tras_tema(self) -> None:
        """Repinta carcasa del explorador y reconstruye el contenido con la paleta actual."""
        if not hasattr(self, "_frame_explorador") or not self._frame_explorador.winfo_exists():
            return
        EX = self._explorador_ex_vals()
        try:
            self._frame_explorador.configure(bg=EX["shell"], highlightbackground=THEME["border"])
            if hasattr(self, "_explorador_cuerpo") and self._explorador_cuerpo.winfo_exists():
                self._explorador_cuerpo.configure(bg=EX["body"])
            if hasattr(self, "_explorador_grip") and self._explorador_grip.winfo_exists():
                self._explorador_grip.configure(bg=EX["tile_bd"])
        except tk.TclError:
            pass
        tab = getattr(self, "_explorador_set_tab", None)
        cur = getattr(self, "_explorador_actual", "cuentas_polizas")
        if callable(tab):
            try:
                tab(cur)
            except Exception:
                pass
    
