        """Explorador híbrido: pestañas principales + submódulos Aspel COI con iconos."""
        EX = self._explorador_ex_vals()
        bar = tk.Frame(self.root, bg=EX["shell"], highlightthickness=1, highlightbackground=THEME["border"])
        bar.pack(side=tk.TOP, fill=tk.X)
        self._frame_explorador = bar
        head = tk.Frame(bar, bg=THEME["header_bg"], height=28)
        head.pack(fill=tk.X)
        head.pack_propagate(False)
        self._btn_hamb_panel = None
        tk.Label(
            head,
            text="EXPLORADOR",
            bg=THEME["header_bg"],
            fg=THEME["header_fg"],
            font=(THEME["font_ui"], 8, "bold"),
        ).pack(side=tk.LEFT, padx=6, pady=4)
        self._btn_hamb_expl = None

        self._explorador_cuerpo = tk.Frame(bar, bg=EX["body"], height=self._explorador_alto)

        def _tile_explorador(parent, emoji, titulo_corto, tip, comando, row: int, col: int):
            """Mosaico: un solo azul en todo el recuadro (icono + texto)."""
            EX = self._explorador_ex_vals()
            cell = tk.Frame(
                parent,
                bg=EX["moz"],
                highlightthickness=1,
                highlightbackground=EX["moz_bd"],
            )
            cell.grid(row=row, column=col, padx=3, pady=2, sticky="nw")

            icon_btn_kw = dict(
                command=comando,
                bg=EX["moz"],
                fg=EX["moz_fg"],
                activebackground=EX["moz_hi"],
                activeforeground=EX["moz_fg"],
                relief=tk.FLAT,
                bd=0,
                cursor="hand2",
                font=(THEME["font_ui"], 11),
                width=3,
                padx=0,
                pady=0,
            )
            icon_btn_kw["text"] = emoji
            icon_zone = tk.Frame(cell, bg=EX["moz"], height=26)
            icon_zone.pack(fill=tk.X, pady=(3, 1))
            icon_zone.pack_propagate(False)
            b = tk.Button(icon_zone, **icon_btn_kw)
            b.pack(anchor="center", pady=0)

            lbl = tk.Label(
                cell,
                text=titulo_corto.replace("\n", " "),
                bg=EX["moz"],
                fg=EX["moz_fg"],
                font=(THEME["font_ui"], 8),
                justify=tk.CENTER,
                wraplength=96,
                anchor="n",
                cursor="hand2",
            )
            lbl.pack(fill=tk.X, padx=3, pady=(0, 4))
            lbl.bind("<Button-1>", lambda _e: comando())
            self.crear_tooltip(b, tip)
            self.crear_tooltip(lbl, tip)

        self._explorador_cuerpo.pack(fill=tk.X)
        self._explorador_cuerpo.pack_propagate(False)

        def _render_grupo_en_tab(tab_frame, titulo: str, items, cols: int = 7):
            EX = self._explorador_ex_vals()
            head = tk.Frame(tab_frame, bg=EX["body"])
            head.pack(fill=tk.X, padx=6, pady=(1, 0))
            tk.Label(
                head,
                text=titulo.upper(),
                bg=EX["body"],
                fg=THEME["text_secondary"],
                font=(THEME["font_ui"], 7, "bold"),
                anchor="w",
            ).pack(side=tk.LEFT)
            tk.Frame(head, bg=EX["tile_bd"], height=1).pack(side=tk.LEFT, fill=tk.X, expand=True, padx=6, pady=4)
            gr = tk.Frame(tab_frame, bg=EX["body"])
            gr.pack(anchor="w", padx=6, pady=(0, 2))
            cols_real = max(1, min(cols, len(items)))
            for c in range(cols_real):
                gr.grid_columnconfigure(c, minsize=104)
            for idx, (_em, _txt, _tip, _cmd) in enumerate(items):
                r = idx // cols_real
                c = idx % cols_real
                _tile_explorador(gr, _em, _txt, _tip, _cmd, row=r, col=c)

