    def _toggle_panel_lateral_modulo(self):
        self._aplicar_panel_lateral(not getattr(self, "_panel_lateral_visible", True))

    def _toggle_explorador_cuerpo(self):
        self._aplicar_explorador(not getattr(self, "_explorador_cuerpo_visible", True))

    def _vista_panel_lateral_desde_menu(self):
        self._aplicar_panel_lateral(self._var_panel_lateral.get())

    def _vista_explorador_desde_menu(self):
        self._aplicar_explorador(self._var_barra_explorador.get())

    def _vista_maximizar_area_trabajo(self):
        self._var_panel_lateral.set(False)
        self._var_barra_explorador.set(False)
        self._aplicar_panel_lateral(False)
        self._aplicar_explorador(False)

    def _vista_restaurar_barras(self):
        self._var_panel_lateral.set(True)
        self._var_barra_explorador.set(True)
        self._aplicar_panel_lateral(True)
        self._aplicar_explorador(True)

    def _refrescar_iconos_vista(self):
        exp = getattr(self, "_explorador_cuerpo_visible", True)
        lat = getattr(self, "_panel_lateral_visible", True)
        txt_exp = "▼" if exp else "▶"
        for attr in ("_btn_hamb_expl", "_btn_toolbar_explorador"):
            w = getattr(self, attr, None)
            if w is not None:
                try:
                    w.config(text=txt_exp)
                except tk.TclError:
                    pass
        txt_p = "☰" if lat else "▶"
        for attr in ("_btn_hamb_panel", "_btn_toolbar_panel_lateral"):
            w = getattr(self, attr, None)
            if w is not None:
                try:
                    w.config(text=txt_p)
                except tk.TclError:
                    pass

    def _aplicar_panel_lateral(self, visible: bool):
        if not hasattr(self, "panel_principal"):
            return
        if visible == getattr(self, "_panel_lateral_visible", True):
            self._var_panel_lateral.set(visible)
            return
        self._panel_lateral_visible = visible
        self._var_panel_lateral.set(visible)
        try:
            if visible:
                if hasattr(self, "_strip_lateral") and self._strip_lateral.winfo_ismapped():
                    self._strip_lateral.pack_forget()
                w = getattr(self, "_panel_lateral_ancho_guardado", 228) or 228
                # tkinter.PanedWindow no tiene insert(); add(..., before=) recoloca a la izquierda del área de trabajo
                self.panel_principal.add(
                    self.panel_modulo, minsize=168, width=w, before=self.area_trabajo
                )
            else:
                self.root.update_idletasks()
                try:
                    ww = self.panel_modulo.winfo_width()
                    if ww > 40:
                        self._panel_lateral_ancho_guardado = ww
                except tk.TclError:
                    pass
                self.panel_principal.remove(self.panel_modulo)
                if hasattr(self, "_strip_lateral"):
                    self._strip_lateral.pack(side=tk.LEFT, fill=tk.Y, before=self.panel_principal)
        except tk.TclError:
            pass
        self._refrescar_iconos_vista()

    def _aplicar_explorador(self, visible: bool):
        if not hasattr(self, "_explorador_cuerpo"):
            return
        if visible == getattr(self, "_explorador_cuerpo_visible", True):
            self._var_barra_explorador.set(visible)
            return
        self._explorador_cuerpo_visible = visible
        self._var_barra_explorador.set(visible)
        try:
            if visible:
                if hasattr(self, "_explorador_modulos_head") and not self._explorador_modulos_head.winfo_ismapped():
                    self._explorador_modulos_head.pack(side=tk.LEFT, padx=(10, 0), pady=1)
                self._explorador_cuerpo.pack(fill=tk.X)
                if hasattr(self, "_explorador_grip") and not self._explorador_grip.winfo_ismapped():
                    self._explorador_grip.pack(fill=tk.X)
            else:
                if hasattr(self, "_explorador_modulos_head") and self._explorador_modulos_head.winfo_ismapped():
                    self._explorador_modulos_head.pack_forget()
                self._explorador_cuerpo.pack_forget()
                if hasattr(self, "_explorador_grip") and self._explorador_grip.winfo_ismapped():
                    self._explorador_grip.pack_forget()
        except tk.TclError:
            pass
        self._refrescar_iconos_vista()

    @staticmethod
    def _catalogo_codigo_base3(num_cuenta: str) -> int:
        s = "".join(ch for ch in str(num_cuenta) if ch.isdigit())
        if not s:
            return 0
        return int(s[:3]) if len(s) >= 3 else int(s)

    def _catalogo_rubro_coincide(self, num_cuenta: str, nombre: str, rid: str) -> bool:
        """Filtro estilo Aspel «Todas las cuentas» (heurística por código SAT típico)."""
        if not rid or rid == "all":
            return True
        d = self._catalogo_codigo_base3(num_cuenta)
        u = (nombre or "").upper()
        def rng(a: int, b: int) -> bool:
            return a <= d <= b

        rubros = {
            "r01": lambda: rng(101, 121) or d == 100,
            "r02": lambda: rng(151, 191),
            "r03": lambda: rng(201, 218),
            "r04": lambda: rng(251, 260),
            "r05": lambda: rng(301, 306),
            "r06": lambda: rng(401, 403),
            "r07": lambda: rng(501, 505),
            # 6xx = gastos (601–614 típico Aspel; ampliamos a 699 por subcuentas extendidas)
            "r08": lambda: rng(601, 699),
            "r09": lambda: rng(801, 899) or d == 700,
            "r10": lambda: "ISR" in u or "PTU" in u or rng(551, 559),
            "r11": lambda: rng(101, 104),
            "r12": lambda: rng(105, 109) or "CLIENTE" in u,
            "r13": lambda: rng(115, 116) or "INVENTAR" in u,
            "r14": lambda: rng(107, 107) or "IVA" in u and "ACRED" in u,
            "r15": lambda: rng(151, 191),
            "r16": lambda: rng(117, 119),
            "r17": lambda: rng(201, 205) or "PROVEEDOR" in u,
            "r18": lambda: rng(208, 209) or ("IVA" in u and "PAGAR" in u),
            "r19": lambda: rng(206, 207),
            "r20": lambda: rng(201, 218),
            "r21": lambda: rng(251, 260),
            "r22": lambda: 100 <= d <= 199,
            "r23": lambda: 200 <= d <= 299,
            "r24": lambda: "UTILIDAD" in u or rng(601, 603),
            "r25": lambda: rng(301, 303) or "CAPITAL" in u,
            "r26": lambda: "DEPRECI" in u or d in (171, 681),
            "r27": lambda: "AMORTI" in u or d in (183, 682),
            "r28": lambda: "ISR" in u and "PAGAR" in u,
            "r29": lambda: "ISR" in u and "NOMINA" in u,
            "r30": lambda: "RETENC" in u and "ISR" in u,
            "r31": lambda: "RETENC" in u and "IVA" in u,
            "r32": lambda: "PROVISION" in u,
            "r33": lambda: "NOMINA" in u and "IMP" in u,
            "r34": lambda: d >= 900 or "ORDEN" in u,
        }
        fn = rubros.get(rid)
        return fn() if fn else True

