    def _sidebar_icono(self, parent, emoji: str, texto: str, comando, primario: bool = False, asset_png: str = None):
        bg = THEME["btn_primary_bg"] if primario else THEME["btn_secondary_bg"]
        fg = THEME["btn_primary_fg"] if primario else THEME["text_primary"]
        f = tk.Frame(parent, bg=THEME["bg_sidebar"])
        f.pack(fill=tk.X, pady=1)
        img = None
        if asset_png:
            ruta_icon = os.path.join(
                os.path.dirname(os.path.dirname(os.path.abspath(__file__))), "assets", "toolbar", asset_png
            )
            if os.path.isfile(ruta_icon):
                if not hasattr(self, "_sidebar_photos"):
                    self._sidebar_photos = []
                try:
                    from PIL import Image, ImageTk
                    try:
                        _rs = Image.Resampling.LANCZOS
                    except AttributeError:
                        _rs = Image.LANCZOS
                    im = Image.open(ruta_icon).resize((18, 18), _rs)
                    ph = ImageTk.PhotoImage(im)
                    self._sidebar_photos.append(ph)
                    img = ph
                except Exception:
                    img = None
        btn_kw = dict(
            text=texto if img else f"{emoji}  {texto}",
            command=comando, bg=bg, fg=fg,
            relief=tk.FLAT, anchor="w", padx=6, pady=4, cursor="hand2",
            font=(THEME["font_ui"], 9),
        )
        if img:
            btn_kw["image"] = img
            btn_kw["compound"] = tk.LEFT
        tk.Button(f, **btn_kw).pack(fill=tk.X)

    def _render_sidebar_por_modulo(self, modulo_key: str):
        if modulo_key == "catalogo":
            self._render_controles_catalogo_sidebar()
        elif modulo_key == "polizas":
            self._render_controles_polizas_sidebar()
        elif modulo_key == "bancos":
            self._render_controles_bancos_sidebar()
        elif modulo_key == "balanza":
            if not hasattr(self, "balanza_filtro_tipo"):
                self.balanza_filtro_tipo = tk.StringVar(value="Todos")
            self._render_controles_balanza_sidebar()
        elif modulo_key == "resultados":
            self._render_controles_resultados_sidebar()
        elif modulo_key == "balance":
            self._render_controles_balance_sidebar()
        elif modulo_key == "activos":
            self._render_controles_activos_sidebar()
        elif modulo_key == "sat":
            self._render_controles_sat_sidebar()
        elif modulo_key == "reportes":
            self._render_controles_reportes_sidebar()
        elif modulo_key == "flujo":
            self._render_controles_flujo_sidebar()
        elif modulo_key == "cfdi":
            self._render_controles_cfdi_sidebar()
        elif modulo_key == "monedas":
            self._render_controles_monedas_sidebar()
        elif modulo_key == "deposito":
            self._render_controles_deposito_sidebar()

