    def _render_controles_catalogo_sidebar(self):
        """Solo filtro por rubro (las acciones están en la barra del catálogo)."""
        if not (hasattr(self, "panel_modulo_body") and self.panel_modulo_body.winfo_exists()):
            return
        tk.Label(
            self.panel_modulo_body,
            text="Catálogo: use la barra superior del área principal para alta, edición y actualización.",
            bg=THEME["bg_sidebar"],
            fg=THEME["text_secondary"],
            font=(THEME["font_ui"], 8),
            anchor="w",
            justify=tk.LEFT,
            wraplength=208,
        ).pack(fill=tk.X, pady=(0, 6))
        tk.Label(
            self.panel_modulo_body, text="Filtro por rubro", bg=THEME["bg_sidebar"],
            fg=THEME["text_secondary"], font=(THEME["font_ui"], 8), anchor="w",
        ).pack(fill=tk.X, pady=(0, 4))
        tk.Label(
            self.panel_modulo_body, text="TODAS LAS CUENTAS", bg=THEME["bg_sidebar"],
            fg=THEME["text_primary"], font=(THEME["font_ui"], 9, "bold"), anchor="w",
        ).pack(fill=tk.X, pady=(10, 4))

        lista_frame = tk.Frame(self.panel_modulo_body, bg=THEME["bg_sidebar"])
        lista_frame.pack(fill=tk.BOTH, expand=True)
        sb = tk.Scrollbar(lista_frame)
        sb.pack(side=tk.RIGHT, fill=tk.Y)
        self._listbox_rubros_catalogo = tk.Listbox(
            lista_frame, height=12, width=28, font=(THEME["font_ui"], 8),
            yscrollcommand=sb.set, bg=THEME["bg_content"], fg=THEME["text_primary"],
            selectbackground=THEME["accent"], selectforeground=THEME["header_fg"],
        )
        self._listbox_rubros_catalogo.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        sb.config(command=self._listbox_rubros_catalogo.yview)

        self._rubros_catalogo_ids = []
        for rid, label in self._lista_rubros_catalogo():
            self._rubros_catalogo_ids.append(rid)
            self._listbox_rubros_catalogo.insert(tk.END, label)

        def _aplicar_rubro_seleccionado():
            sel = self._listbox_rubros_catalogo.curselection()
            if not sel:
                return
            idx = int(sel[0])
            self._catalogo_rubro_filtro = self._rubros_catalogo_ids[idx]
            try:
                self.actualizar_catalogo()
                self.set_status(f"Catálogo: filtro {self._listbox_rubros_catalogo.get(idx)}")
            except Exception as ex:
                messagebox.showerror("Error", str(ex))

        self._listbox_rubros_catalogo.bind("<Double-Button-1>", lambda e: _aplicar_rubro_seleccionado())
        tk.Button(
            self.panel_modulo_body, text="Aplicar filtro de rubro", command=_aplicar_rubro_seleccionado,
            bg=THEME["btn_primary_bg"], fg=THEME["btn_primary_fg"], relief=tk.FLAT, cursor="hand2",
        ).pack(fill=tk.X, pady=(4, 0))
        # Seleccionar «Todas» por defecto
        try:
            self._listbox_rubros_catalogo.selection_set(0)
        except Exception:
            pass

