    def _sync_cfdi_dashboard_startup(self):
        """Sincroniza XML de facturas_timbradas hacia la tabla local (sin ventanas al iniciar)."""
        try:
            prov = (self.proveedor_fiscal or "").strip()
            r = self.cfdi_dashboard.sync_from_folder(proveedor=prov)
            self.set_status(
                f"CFDI sincronizado: leídos {r.get('leidos', 0)}, "
                f"nuevos {r.get('insertados', 0)}, actualizados {r.get('actualizados', 0)}."
            )
        except Exception as ex:
            try:
                self.set_status(f"CFDI sync: error — {ex}")
            except Exception:
                pass

    def _cfdi_rfc_empresa_config(self) -> str:
        try:
            with open(self._ruta_config_instituto(), "r", encoding="utf-8") as f:
                cfg = json.load(f)
            for k in ("FINKOK_ISSUER_RFC", "FACTURAMA_ISSUER_RFC", "CONECTIA_SW_RFC"):
                r = (cfg.get(k) or "").strip().upper()
                if r:
                    return r
        except Exception:
            pass
        return ""

    def _rfc_empresa_para_xml(self) -> str:
        """
        RFC del contribuyente para XML de contabilidad electrónica e informes:
        primero el capturado en Datos de empresa / configuración general (BD),
        luego el del proveedor de timbrado en config_instituto.json.
        """
        try:
            from backend.modules.configuracion_general import ConfiguracionGeneral

            r = (ConfiguracionGeneral(db_path=self.polizas.db_path).obtener().get("rfc") or "").strip().upper()
            if r:
                return r
        except Exception:
            pass
        return (self._cfdi_rfc_empresa_config() or "").strip().upper()

    def _refrescar_tablero_cfdi_tree(self):
        if not hasattr(self, "_tree_tablero_cfdi") or not self._tree_tablero_cfdi.winfo_exists():
            return
        tree = self._tree_tablero_cfdi
        filtro = ""
        try:
            if hasattr(self, "_cfdi_filtro_entry") and self._cfdi_filtro_entry.winfo_exists():
                filtro = self._cfdi_filtro_entry.get().strip()
        except Exception:
            pass
        for i in tree.get_children():
            tree.delete(i)
        try:
            if getattr(self, "_cfdi_tablero_modo_filtrado", False):
                rows = self.cfdi_dashboard.listar_cfdi_filtrado(
                    texto=filtro,
                    periodo=self._cfdi_var_periodo.get(),
                    flujo=self._cfdi_var_flujo.get(),
                    tipo_cfdi=self._cfdi_var_tipo.get(),
                    estado=self._cfdi_var_estado.get(),
                    efos=self._cfdi_var_efos.get(),
                    rfc_empresa=self._rfc_empresa_para_xml(),
                    limit=800,
                )
            else:
                rows = self.cfdi_dashboard.listar_cfdi(filtro=filtro, limit=800)
        except Exception:
            rows = []
        for r in rows:
            xm = r.get("xml_path") or ""
            nom_arch = os.path.basename(xm) if xm else ""
            tipo = (r.get("tipo_cfdi") or "—")[:3]
            est = (r.get("estado_comprobante") or r.get("status_sat") or "")[:16]
            tree.insert(
                "",
                "end",
                iid=str(r.get("id")),
                values=(
                    (r.get("fecha_cfdi") or "")[:10],
                    (r.get("serie") or ""),
                    r.get("folio") or "",
                    (r.get("uuid") or "")[:13] + "…" if len((r.get("uuid") or "")) > 13 else (r.get("uuid") or ""),
                    r.get("rfc_emisor") or "",
                    (r.get("nombre_emisor") or "")[:28],
                    tipo,
                    f"{float(r.get('total') or 0):,.2f}",
                    est,
                    nom_arch[:24],
                        "Sí" if (r.get("en_contabilidad") or 0) else "No",
                ),
            )
        try:
            if hasattr(self, "_lbl_cfdi_resumen") and self._lbl_cfdi_resumen.winfo_exists():
                s = self.cfdi_dashboard.resumen()
                self._lbl_cfdi_resumen.config(
                    text=(
                        f"Registros: {s.get('total_cfdi', 0)}  |  "
                        f"Monto total: ${s.get('monto_total', 0):,.2f}  |  "
                        f"Sin UUID: {s.get('sin_uuid', 0)}"
                    )
                )
        except Exception:
            pass

