    def _cfdi_llenar_panel_detalle(self, cid: int):
        if not getattr(self, "_cfdi_detalle_meta", None):
            return
        try:
            row = self.cfdi_dashboard.obtener_por_id(int(cid))
        except Exception:
            row = None
        for w in self._cfdi_conceptos_tree.get_children():
            self._cfdi_conceptos_tree.delete(w)
        self._cfdi_detalle_meta.delete("1.0", tk.END)
        if not row:
            self._cfdi_detalle_meta.insert(tk.END, "Seleccione un comprobante en la tabla.")
            return
        xm = row.get("xml_path") or ""
        p_lines = [
            f"Emisor: {row.get('nombre_emisor') or '—'}  RFC: {row.get('rfc_emisor') or '—'}",
            f"Receptor: {row.get('nombre_receptor') or '—'}  RFC: {row.get('rfc_receptor') or '—'}",
            f"UUID: {row.get('uuid') or '—'}",
            f"Fecha: {(row.get('fecha_cfdi') or '')[:19]}   Serie/Folio: {row.get('serie') or ''} {row.get('folio') or ''}",
            f"Tipo: {row.get('tipo_cfdi') or '—'}   Versión CFDI: {row.get('version_cfdi') or '—'}",
            f"Total: {float(row.get('total') or 0):,.2f} {row.get('moneda') or 'MXN'}",
            f"Estado: {row.get('estado_comprobante') or '—'}   Archivo: {os.path.basename(xm) if xm else '—'}",
            "",
        ]
        self._cfdi_detalle_meta.insert(tk.END, "\n".join(p_lines))
        for ln in self.cfdi_dashboard.lineas_conceptos_desde_xml(xm):
            self._cfdi_conceptos_tree.insert(
                "",
                "end",
                values=(
                    ln.get("clave", ""),
                    ln.get("cantidad", ""),
                    ln.get("clave_unidad", ""),
                    ln.get("unidad", ""),
                    (ln.get("descripcion") or "")[:80],
                ),
            )

    def _cfdi_on_tablero_select(self, _evt=None):
        sel = self._tree_tablero_cfdi.selection()
        if not sel:
            return
        try:
            self._cfdi_llenar_panel_detalle(int(sel[0]))
        except (ValueError, TypeError):
            pass

    def _cfdi_importar_xml_tablero(self):
        p = filedialog.askopenfilename(
            title="Importar CFDI (XML)",
            filetypes=[("CFDI XML", "*.xml"), ("Todos los archivos", "*.*")],
        )
        if not p:
            return
        prov = self._cargar_proveedor_fiscal()
        r = self.cfdi_dashboard.importar_archivo_externo(p, proveedor=prov, copiar_a_carpeta=True)
        if not r.get("exito"):
            messagebox.showerror("Importar XML", r.get("error") or "No se pudo importar.")
            return
        cid = r.get("id")
        if cid:
            try:
                self.cfdi_dashboard.aplicar_validacion_local_a_ids([int(cid)])
            except Exception:
                pass
        self._refrescar_tablero_cfdi_tree()
        self._refrescar_diario_cfdi_text()
        if cid:
            iid = str(int(cid))
            try:
                self._tree_tablero_cfdi.selection_set(iid)
                self._tree_tablero_cfdi.focus(iid)
                self._tree_tablero_cfdi.see(iid)
            except tk.TclError:
                pass
            self._cfdi_llenar_panel_detalle(int(cid))
            try:
                res = self.cfdi_dashboard.validacion_local_resumen([int(cid)])
                self._cfdi_mostrar_resultados_validacion(res)
            except Exception:
                pass
        self.set_status("Tablero de comprobantes — Importación y validación local completadas.")

    def _cfdi_importar_xml_masivo(self, rutas):
        """Importa múltiples XML al tablero CFDI."""
        if not rutas:
            return {"ok": 0, "error": 0, "ids": []}
        prov = self._cargar_proveedor_fiscal()
        ok = 0
        err = 0
        ids = []
        for p in rutas:
            p = os.path.abspath(str(p or "").strip())
            if not p.lower().endswith(".xml") or not os.path.isfile(p):
                err += 1
                continue
            r = self.cfdi_dashboard.importar_archivo_externo(p, proveedor=prov, copiar_a_carpeta=True)
            if r.get("exito"):
                ok += 1
                if r.get("id"):
                    try:
                        ids.append(int(r.get("id")))
                    except Exception:
                        pass
            else:
                err += 1
        if ids:
            try:
                self.cfdi_dashboard.aplicar_validacion_local_a_ids(ids)
            except Exception:
                pass
        self._refrescar_tablero_cfdi_tree()
        self._refrescar_diario_cfdi_text()
        return {"ok": ok, "error": err, "ids": ids}

    def _cfdi_parse_dnd_files(self, raw: str):
        """
        Parsea formato DND_FILES de Tk (paths con llaves si tienen espacios).
        """
        s = (raw or "").strip()
        if not s:
            return []
        out = []
        buff = []
        in_brace = False
        for ch in s:
            if ch == "{":
                if not in_brace:
                    in_brace = True
                    if buff:
                        part = "".join(buff).strip()
                        if part:
                            out.append(part)
                        buff = []
                    continue
            if ch == "}":
                if in_brace:
                    in_brace = False
                    part = "".join(buff).strip()
                    if part:
                        out.append(part)
                    buff = []
                    continue
            if ch == " " and not in_brace:
                part = "".join(buff).strip()
                if part:
                    out.append(part)
                buff = []
                continue
            buff.append(ch)
        part = "".join(buff).strip()
        if part:
            out.append(part)
        # Limpieza de comillas
        out2 = []
        for p in out:
            pp = p.strip().strip('"').strip("'")
            if pp:
                out2.append(pp)
        return out2

    def _cfdi_dialog_importar_arrastre(self):
        """Importación masiva por arrastrar/soltar (o pegar rutas)."""
        d = tk.Toplevel(self.root)
        d.title("Importar CFDI por arrastre")
        d.transient(self.root)
        d.resizable(True, True)

        main = tk.Frame(d, bg=THEME["bg_content"], padx=12, pady=12)
        main.pack(fill=tk.BOTH, expand=True)

        tk.Label(
            main,
            text="Arrastre uno o varios XML aquí. También puede pegar rutas (Ctrl+V).",
            bg=THEME["bg_content"],
            fg=THEME["text_primary"],
            anchor="w",
            justify=tk.LEFT,
        ).pack(fill=tk.X, pady=(0, 8))

        drop_box = tk.Text(main, height=8, wrap=tk.WORD, font=(THEME["font_ui"], 9))
        drop_box.pack(fill=tk.BOTH, expand=True)
        drop_box.insert("1.0", "Suelte archivos .xml aquí…\n")

        rutas = []

        def _mostrar_rutas(rs):
            drop_box.delete("1.0", tk.END)
            if not rs:
                drop_box.insert("1.0", "Suelte archivos .xml aquí…\n")
                return
            for p in rs:
                drop_box.insert(tk.END, p + "\n")

        def _agregar_desde_raw(raw):
            nonlocal rutas
            parsed = self._cfdi_parse_dnd_files(raw)
            # expandir directorios
            expanded = []
            for p in parsed:
                p = os.path.abspath(p)
                if os.path.isdir(p):
                    try:
                        for n in os.listdir(p):
                            fp = os.path.join(p, n)
                            if os.path.isfile(fp) and fp.lower().endswith(".xml"):
                                expanded.append(fp)
                    except Exception:
                        pass
                else:
                    expanded.append(p)
            # merge sin duplicados
            seen = {x.lower() for x in rutas}
            for p in expanded:
                if p.lower() not in seen:
                    rutas.append(p)
                    seen.add(p.lower())
            _mostrar_rutas(rutas)

        # Intentar habilitar DnD real (opcional)
        dnd_habilitado = False
        try:
            from tkinterdnd2 import DND_FILES  # type: ignore
            try:
                drop_box.drop_target_register(DND_FILES)
                drop_box.dnd_bind("<<Drop>>", lambda e: _agregar_desde_raw(getattr(e, "data", "")))
                dnd_habilitado = True
            except Exception:
                dnd_habilitado = False
        except Exception:
            dnd_habilitado = False

        if not dnd_habilitado:
            tk.Label(
                main,
                text="Nota: arrastrar/soltar no disponible en este entorno. Use Ctrl+V con rutas o Examinar…",
                bg=THEME["bg_content"],
                fg=THEME["text_secondary"],
                anchor="w",
                justify=tk.LEFT,
                font=(THEME["font_ui"], 8),
            ).pack(fill=tk.X, pady=(6, 0))

        # Pegar rutas
        drop_box.bind(
            "<Control-v>",
            lambda _e: (self.root.after(10, lambda: _agregar_desde_raw(drop_box.get("1.0", tk.END))), "break"),
        )

        status = tk.Label(main, text="", bg=THEME["bg_content"], fg=THEME["text_secondary"], anchor="w")
        status.pack(fill=tk.X, pady=(8, 2))

        bf = tk.Frame(main, bg=THEME["bg_content"])
        bf.pack(fill=tk.X, pady=(6, 0))

        def _examinar():
            files = filedialog.askopenfilenames(
                title="Seleccionar XML CFDI",
                filetypes=[("CFDI XML", "*.xml"), ("Todos los archivos", "*.*")],
            )
            if files:
                _agregar_desde_raw(" ".join([f"{{{p}}}" if " " in p else p for p in files]))

        def _importar():
            if not rutas:
                messagebox.showwarning("Importar CFDI", "No hay rutas para importar.")
                return
            r = self._cfdi_importar_xml_masivo(rutas)
            status.config(text=f"Importados: {r.get('ok',0)} | Errores: {r.get('error',0)}")
            self.set_status("Tablero de comprobantes — Importación masiva completada.")
            messagebox.showinfo("Importar CFDI", f"Importados: {r.get('ok',0)}\nErrores: {r.get('error',0)}")

        tk.Button(bf, text="Examinar…", command=_examinar, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=12, pady=6, cursor="hand2").pack(side=tk.LEFT)
