        tk.Button(bf, text="Limpiar", command=lambda: (rutas.clear(), _mostrar_rutas(rutas)), bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=12, pady=6, cursor="hand2").pack(side=tk.LEFT, padx=4)
