    def _cfdi_validar_seleccion_tablero(self):
        sel = self._tree_tablero_cfdi.selection()
        if not sel:
            messagebox.showwarning("Validar CFDI", "Seleccione uno o más comprobantes en la tabla.")
            return
        cids = []
        for s in sel:
            try:
                cids.append(int(s))
            except (ValueError, TypeError):
                continue
        if not cids:
            return
        try:
            self.cfdi_dashboard.aplicar_validacion_local_a_ids(cids)
        except Exception as e:
            messagebox.showerror("Validar", str(e))
            return
        self._refrescar_tablero_cfdi_tree()
        res = self.cfdi_dashboard.validacion_local_resumen(cids)
        self._cfdi_mostrar_resultados_validacion(res)
        self.set_status("Validación local aplicada a comprobantes seleccionados.")

    def _cfdi_toggle_detalle_tablero(self):
        self._cfdi_detalle_visible = not getattr(self, "_cfdi_detalle_visible", True)
        if self._cfdi_detalle_visible:
            self._cfdi_detalle_outer.grid(row=0, column=2, sticky="nsew", padx=(4, 8), pady=4)
            self._cfdi_toggle_detalle_btn.config(text="Ocultar detalle ☰")
        else:
            self._cfdi_detalle_outer.grid_remove()
            self._cfdi_toggle_detalle_btn.config(text="Mostrar detalle ☰")

