        tk.Label(
            wrap,
            text="RFC: se toma de Datos de empresa; si no está, del timbrado configurado.",
            bg=THEME["bg_sidebar"], fg=THEME["text_secondary"], font=(THEME["font_ui"], 7), wraplength=200, justify=tk.LEFT,
        ).pack(anchor="w", pady=8)
