    def _analizar_cfdi_manual(self):
        try:
            r = self.cfdi_dashboard.ejecutar_analisis()
            messagebox.showinfo(
                "Análisis CFDI",
                f"Revisados: {r.get('revisados', 0)}\nAlertas registradas: {r.get('alertas', 0)}",
            )
            self.set_status(
                f"Análisis CFDI: {r.get('revisados', 0)} documentos, {r.get('alertas', 0)} alerta(s)."
            )
            if hasattr(self, "_txt_cfdi_diario") and self._txt_cfdi_diario.winfo_exists():
                self._refrescar_diario_cfdi_text()
        except Exception as ex:
            messagebox.showerror("Análisis CFDI", str(ex))

    def _refrescar_diario_cfdi_text(self):
        if not hasattr(self, "_txt_cfdi_diario") or not self._txt_cfdi_diario.winfo_exists():
            return
        self._txt_cfdi_diario.delete("1.0", tk.END)
        try:
            lineas = self.cfdi_dashboard.obtener_diario(limit=200)
        except Exception:
            lineas = []
        for ev in lineas:
            fh = ev.get("fecha_hora") or ""
            cat = ev.get("categoria") or ""
            sev = ev.get("severidad") or ""
            msg = ev.get("mensaje") or ""
            ref = ev.get("referencia") or ""
            self._txt_cfdi_diario.insert(tk.END, f"{fh} [{sev}] {cat}: {msg}  {ref}\n")

    def _toggle_auto_analisis(self):
        self.auto_analisis_activo = not getattr(self, "auto_analisis_activo", False)
        if getattr(self, "_auto_analisis_after_id", None):
            try:
                self.root.after_cancel(self._auto_analisis_after_id)
            except Exception:
                pass
            self._auto_analisis_after_id = None
        if not self.auto_analisis_activo:
            self.set_status("Auto análisis CFDI: desactivado.")
            return
        self.set_status("Auto análisis CFDI: activado (cada 5 min).")

        def _tick():
            if not getattr(self, "auto_analisis_activo", False):
                return
            try:
                self.cfdi_dashboard.ejecutar_analisis()
                if hasattr(self, "_txt_cfdi_diario") and self._txt_cfdi_diario.winfo_exists():
                    self._refrescar_diario_cfdi_text()
            except Exception:
                pass
            if getattr(self, "auto_analisis_activo", False):
                self._auto_analisis_after_id = self.root.after(
                    getattr(self, "auto_analisis_ms", 300000), _tick
                )

        _tick()

