    def _cfdi_descarga_interna_dialog(self):
        """COI 11: Servicio interno — cola por ventanas (4 meses), bitácora y reintentos."""
        try:
            from backend.modules.cfdi_descarga_interna import ejecutar_descarga_interna_desde_carpeta
            from backend.modules.cfdi_servicio_interno import (
                guardar_config_si,
                listar_trabajos_si,
                obtener_config_si,
                procesar_cola_si,
                reintentar_trabajo,
                solicitar_lote,
            )
        except Exception as e:
            messagebox.showerror("CFDI", f"No se pudo cargar descarga interna:\n{e}")
            return

        d = tk.Toplevel(self.root)
        d.title("Servicio interno CFDI (COI 11)")
        d.transient(self.root)
        d.resizable(True, True)
        main = tk.Frame(d, bg=THEME["bg_content"], padx=12, pady=12)
        main.pack(fill=tk.BOTH, expand=True)

        tk.Label(
            main,
            text="Fuente: carpeta XML (simula PAC/SI). Puede encolar ventanas de hasta 4 meses y procesar la cola con bitácora en el diario CFDI.",
            bg=THEME["bg_content"],
            fg=THEME["text_secondary"],
            font=(THEME["font_ui"], 8),
            wraplength=560,
            justify=tk.LEFT,
        ).pack(anchor="w", pady=(0, 8))

        cfg = obtener_config_si(db_path=self.polizas.db_path)

        row1 = tk.Frame(main, bg=THEME["bg_content"])
        row1.pack(fill=tk.X, pady=2)
        tk.Label(row1, text="Desde (YYYY-MM-DD):", bg=THEME["bg_content"]).pack(side=tk.LEFT)
        e_desde = tk.Entry(row1, width=12)
        e_desde.insert(0, f"{datetime.now().year}-01-01")
        e_desde.pack(side=tk.LEFT, padx=6)
        tk.Label(row1, text="Hasta:", bg=THEME["bg_content"]).pack(side=tk.LEFT, padx=(12, 0))
        e_hasta = tk.Entry(row1, width=12)
        e_hasta.insert(0, datetime.now().strftime("%Y-%m-%d"))
        e_hasta.pack(side=tk.LEFT, padx=6)

        row2 = tk.Frame(main, bg=THEME["bg_content"])
        row2.pack(fill=tk.X, pady=2)
        tk.Label(row2, text="Carpeta XML:", bg=THEME["bg_content"]).pack(side=tk.LEFT)
        e_folder = tk.Entry(row2, width=52)
        if cfg.get("default_carpeta_xml"):
            e_folder.insert(0, cfg["default_carpeta_xml"])
        e_folder.pack(side=tk.LEFT, padx=6)

        def browse():
            p = filedialog.askdirectory(parent=d, title="Carpeta con XMLs CFDI")
            if p:
                e_folder.delete(0, tk.END)
                e_folder.insert(0, p)

        tk.Button(row2, text="Examinar…", command=browse, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=10, cursor="hand2").pack(side=tk.LEFT)

        fiel_fr = tk.LabelFrame(main, text="FIEL (rutas; independiente del CSD — uso futuro conector SAT)", bg=THEME["bg_content"], padx=8, pady=6)
        fiel_fr.pack(fill=tk.X, pady=(6, 4))
        rfc_row = tk.Frame(fiel_fr, bg=THEME["bg_content"])
        rfc_row.pack(fill=tk.X)
        tk.Label(rfc_row, text="Certificado (.cer):", bg=THEME["bg_content"]).pack(side=tk.LEFT)
        e_fiel_cer = tk.Entry(rfc_row, width=48)
        e_fiel_cer.insert(0, cfg.get("fiel_cer_path", ""))
