    def _cfdi_generar_poliza_auto_seleccion(self):
        """COI 11: genera póliza automáticamente desde CFDI seleccionado(s)."""
        tree = getattr(self, "_tree_tablero_cfdi", None)
        if not tree or not tree.winfo_exists():
            return
        sel = list(tree.selection() or [])
        if not sel:
            messagebox.showinfo("CFDI", "Seleccione uno o más CFDIs.")
            return
        try:
            from backend.modules.cfdi_poliza_auto import generar_poliza_desde_cfdi_tablero
        except Exception as e:
            messagebox.showerror("CFDI", f"No se pudo cargar generación automática:\n{e}")
            return

        ok = 0
        err = 0
        msgs = []
        for iid in sel[:50]:
            try:
                cid = int(iid)
            except ValueError:
                continue
            r = generar_poliza_desde_cfdi_tablero(cfdi_id=cid, usuario=self.usuario_actual, db_path=self.polizas.db_path)
            if r.get("exito"):
                ok += 1
                msgs.append(f"OK {r.get('uuid') or cid}: {r.get('mensaje') or 'Listo'}")
            else:
                err += 1
                msgs.append(f"ERR {cid}: {r.get('error')}")
        self._refrescar_tablero_cfdi_tree()
        self._refrescar_diario_cfdi_text()
        messagebox.showinfo("Generación automática", f"OK: {ok}  |  Errores: {err}\n\n" + "\n".join(msgs[:12]))
    
    def limpiar_area_trabajo(self):
        for widget in self.area_trabajo.winfo_children():
            widget.destroy()
    
    def _ruta_config_instituto(self):
        """Ruta al archivo config_instituto.json en la raíz del proyecto."""
        return os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), "config_instituto.json")

    def _cargar_proveedor_fiscal(self):
        """Carga el proveedor guardado desde config_instituto.json."""
        ruta = self._ruta_config_instituto()
        if not os.path.isfile(ruta):
            return "facturama"
        try:
            with open(ruta, "r", encoding="utf-8") as f:
                data = json.load(f)
            p = (data.get("PROVEEDOR_FISCAL") or "").strip().lower()
            if p in ("facturama", "facturapi", "conectia", "finkok", "dof", "doff"):
                return p
        except Exception:
            pass
        return "facturama"

    def _guardar_proveedor_fiscal(self, proveedor):
        """Guarda el proveedor seleccionado en config_instituto.json."""
        ruta = self._ruta_config_instituto()
        try:
            data = {}
            if os.path.isfile(ruta):
                with open(ruta, "r", encoding="utf-8") as f:
                    data = json.load(f)
            data["PROVEEDOR_FISCAL"] = proveedor
            with open(ruta, "w", encoding="utf-8") as f:
                json.dump(data, f, indent=2, ensure_ascii=False)
            return True
        except Exception as e:
            messagebox.showerror("Error", f"No se pudo guardar la configuración:\n{e}")
            return False

    def _ruta_tipos_cambio_historico(self):
        return os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), "tipos_cambio_historico.txt")

    def _tipo_cambio_fix_para_fecha(self, fecha_ymd: str):
        import time as _time

        from backend.modules.banxico_tipo_cambio import (
            cargar_token_desde_config,
            consultar_fix_usd_mxn,
            leer_ultimo_fix_desde_historico,
        )
        from backend.modules.tipo_cambio_dof import consultar_dof_usd_mxn

        f = (fecha_ymd or "")[:10]
        try:
            datetime.strptime(f, "%Y-%m-%d")
        except ValueError:
            return None, None
        u = getattr(self, "_tipo_cambio_usar", None)
        if isinstance(u, dict) and (u.get("clave_fiscal") or "").strip().upper()[:3] == "USD":
            try:
                val_u = float(u.get("tipo_cambio"))
                if val_u > 0:
                    return val_u, "TC del catálogo (Usar)"
            except (TypeError, ValueError):
                pass
        ttl = 120.0
        ent = self._tc_fix_cache.get(f)
        if ent and (_time.monotonic() - ent[0]) < ttl:
            return ent[1], ent[2]

        ruta = self._ruta_tipos_cambio_historico()
        v = leer_ultimo_fix_desde_historico(ruta, f)
        if v is not None:
            self._tc_fix_cache[f] = (_time.monotonic(), v, "histórico local")
            return v, "histórico local"
        tok = cargar_token_desde_config(self._ruta_config_instituto())
        if tok:
            try:
                val, iso, _ = consultar_fix_usd_mxn(tok, f)
                self._tc_fix_cache[f] = (_time.monotonic(), val, f"Banxico ({iso})")
                return val, f"Banxico ({iso})"
            except Exception:
                pass
        try:
            val, iso, _fu = consultar_dof_usd_mxn(f)
            self._tc_fix_cache[f] = (_time.monotonic(), val, f"DOF ({iso})")
            return val, f"DOF ({iso})"
        except Exception:
            self._tc_fix_cache[f] = (_time.monotonic(), None, None)
            return None, None

    def _tipo_cambio_catalogo_por_iso_fecha(self, iso: str, fecha_ymd: str):
        """
        Obtiene TC para moneda ISO y fecha.
        USD intenta FIX por fecha; resto usa catálogo de monedas.
        """
        code = (iso or "MXN").strip().upper()[:3]
        if code == "MXN":
            return 1.0, "MXN fijo"
        f = (fecha_ymd or "")[:10]
        try:
            datetime.strptime(f, "%Y-%m-%d")
        except ValueError:
            f = datetime.now().strftime("%Y-%m-%d")

        if code == "USD":
            val, src = self._tipo_cambio_fix_para_fecha(f)
            if val and float(val) > 0:
                return float(val), src or "FIX"
        try:
            from backend.models.monedas_catalogo import CatalogoMonedas

            mgr = CatalogoMonedas()
            for r in mgr.listar() or []:
                if (str(r.get("clave_fiscal") or "").strip().upper()[:3]) == code:
                    tc = float(r.get("tipo_cambio") or 0.0)
                    if tc > 0:
                        return tc, "Catálogo monedas"
        except Exception:
            pass
        return None, None

    def _resolve_centro_costo_id_poliza(self, centro_disp, num_cuenta, cc_map):
        """Centro elegido en UI o, si va vacío, el predeterminado de la cuenta."""
        d = (centro_disp or "").strip()
        if d not in ("", "—"):
            return cc_map.get(d)
        return self.catalogo.obtener_centro_costo_default((num_cuenta or "").strip())

    def _valores_monedas_activas_catalogo(self):
        try:
            from backend.models.monedas_catalogo import CatalogoMonedas

            dbp = getattr(getattr(self, "polizas", None), "db_path", None)
            return CatalogoMonedas(db_path=dbp).listar_claves_activas()
        except Exception:
            return ["MXN", "USD", "EUR", "GBP"]

    def set_status(self, mensaje):
        self.status_label.config(text=f"  {mensaje}  ")
        self.root.update()

    def _tick_reloj_barra_estado(self):
        """Actualiza el reloj y el resumen de sincronización de tipo de cambio (DOFF)."""
        try:
            now = datetime.now()
            if hasattr(self, "_lbl_reloj_inferior") and self._lbl_reloj_inferior.winfo_exists():
                self._lbl_reloj_inferior.config(
                    text=f"  {now.strftime('%d/%m/%Y')}    {now.strftime('%H:%M:%S')}  ",
                )
            if hasattr(self, "_lbl_tc_sync") and self._lbl_tc_sync.winfo_exists():
                try:
                    from backend.modules.tipo_cambio_sync_state import texto_resumen_barra

                    self._lbl_tc_sync.config(text=f"TC DOFF  |  {texto_resumen_barra()}")
                except Exception:
                    self._lbl_tc_sync.config(text="TC DOFF  |  Sincronización automática 08:00 y 14:00.")
        except tk.TclError:
            return
        self._after_reloj_id = self.root.after(1000, self._tick_reloj_barra_estado)

    def _schedule_next_tc_sync(self):
        """Programa la próxima ejecución automática a las 08:00 o 14:00 (hora local)."""
        from backend.modules.tipo_cambio_horario import ms_hasta_proxima_sync

        if getattr(self, "_after_tc_sync_id", None):
            try:
                self.root.after_cancel(self._after_tc_sync_id)
            except tk.TclError:
                pass
        ms = ms_hasta_proxima_sync()
        self._after_tc_sync_id = self.root.after(ms, self._ejecutar_sync_agendada_tipos_cambio)

    def _iniciar_programacion_tipos_cambio_automatica(self):
        """Primera programación del ciclo 08:00 / 14:00 (sin consultar al abrir la ventana)."""
        self._schedule_next_tc_sync()

    def _ejecutar_sync_agendada_tipos_cambio(self):
        """Consulta Banxico/referencia, histórico y catálogo Monedas en segundo plano (ventana horaria)."""
        from backend.models.monedas_catalogo import CatalogoMonedas
        from backend.modules.tipo_cambio_jobs import ejecutar_fetch_completo_en_hilo
        from backend.modules.tipo_cambio_sync_state import guardar_resultado

        fecha = datetime.now().strftime("%Y-%m-%d")
        ruta_tc = self._ruta_tipos_cambio_historico()
        cfg = self._ruta_config_instituto()
        db_path = CatalogoMonedas().db_path

        def on_done(ok, datos, ncat, err):
            def ui():
                try:
                    if ok:
                        guardar_resultado(
                            True,
                            monedas=len(datos) if datos else 0,
                            filas_catalogo=ncat,
                        )
                        self._tc_fix_cache.clear()
                    else:
                        guardar_resultado(False, error=str(err) if err else "Error desconocido")
                    cb = getattr(self, "_refrescar_catalogo_monedas", None)
                    if callable(cb):
                        try:
                            cb()
                        except tk.TclError:
                            pass
                    self.set_status("Tipos de cambio DOFF actualizados automáticamente (08:00 / 14:00).")
                finally:
                    self._schedule_next_tc_sync()

            self.root.after(0, ui)

        ejecutar_fetch_completo_en_hilo(
            fecha_ui=fecha,
            ruta_historico=ruta_tc,
            ruta_config=cfg,
            db_path=db_path,
            on_done=on_done,
        )

