    def nueva_empresa(self):
        dialog = tk.Toplevel(self.root)
        dialog.title("Nueva empresa")
        dialog.transient(self.root)
        dialog.grab_set()
        dialog.resizable(True, True)
        
        tk.Label(dialog, text="CREAR NUEVA EMPRESA", font=('Arial', 12, 'bold')).pack(pady=10)
        
        frame = tk.Frame(dialog)
        frame.pack(pady=10, padx=20, fill=tk.BOTH, expand=True)
        
        campos = [
            ("Nombre de la empresa:", "entry_nombre"),
            ("RFC:", "entry_rfc"),
            ("Razón social:", "entry_razon"),
            ("Dirección:", "entry_dir"),
            ("Colonia:", "entry_col"),
            ("Ciudad:", "entry_ciudad"),
            ("Estado:", "entry_edo"),
            ("CP:", "entry_cp"),
            ("Teléfono:", "entry_tel"),
            ("Email:", "entry_email")
        ]
        
        entries = {}
        for i, (label, key) in enumerate(campos):
            tk.Label(frame, text=label).grid(row=i, column=0, sticky='w', pady=2)
            entry = tk.Entry(frame, width=40)
            entry.grid(row=i, column=1, pady=2, padx=5)
            entries[key] = entry
        
        def guardar():
            nombre = (entries['entry_nombre'].get() or "").strip()
            if not nombre:
                messagebox.showwarning("Validación", "Capture el nombre de la empresa.")
                return
            try:
                from backend.modules.empresas import EmpresasManager
                em = EmpresasManager()
                r = em.crear_empresa(nombre)
                if not r.get("exito"):
                    messagebox.showerror("Error", r.get("error", "No se pudo crear la empresa"))
                    return
                em.seleccionar_empresa(nombre)
            except Exception as e:
                messagebox.showerror("Error", f"No se pudo crear empresa: {e}")
                return

            self.empresa_actual = nombre
            try:
                self._reload_db_models()
            except Exception:
                pass
            self.set_status(f"Empresa {self.empresa_actual} creada")
            messagebox.showinfo("Éxito", "Empresa creada y activada correctamente")
            dialog.destroy()
            self.empresa_label.config(text=f"  Empresa: {self.empresa_actual}  |  Usuario: {self.usuario_actual}  |  Fecha: {datetime.now().strftime('%d/%m/%Y')}  ")
        
        tk.Button(dialog, text="Crear empresa", command=guardar,
                 bg='lightblue', padx=20, pady=5).pack(pady=10)
        self._fit_toplevel(dialog, 0.48, 0.55, 440, 380)
    
    def abrir_empresa(self):
        dialog = tk.Toplevel(self.root)
        dialog.title("Abrir empresa")
        dialog.transient(self.root)
        dialog.grab_set()
        dialog.resizable(True, True)
        
        tk.Label(dialog, text="SELECCIONAR EMPRESA", font=('Arial', 12, 'bold')).pack(pady=10)
        
        empresas = tk.Listbox(dialog, height=10)
        empresas.pack(pady=10, padx=20, fill=tk.BOTH, expand=True)
        try:
            from backend.modules.empresas import EmpresasManager
            em = EmpresasManager()
            items = [e.get("nombre") for e in (em.listar() or []) if (e.get("nombre") or "").strip()]
        except Exception:
            em = None
            items = []
        if not items:
            items = [self.empresa_actual]
        for i, nombre in enumerate(items):
            empresas.insert(tk.END, nombre)
            if str(nombre).strip() == str(self.empresa_actual).strip():
                try:
                    empresas.select_clear(0, tk.END)
                    empresas.select_set(i)
                except Exception:
                    pass
        
        def _seleccion_actual() -> str:
            try:
                return str(empresas.get(empresas.curselection())).strip()
            except Exception:
                return ""
        
        def abrir():
            seleccion = _seleccion_actual()
            if not seleccion:
                return
            self.empresa_actual = seleccion
            try:
                if em is not None:
                    r = em.seleccionar_empresa(seleccion)
                    if not r.get("exito"):
                        messagebox.showerror("Error", r.get("error", "No se pudo activar la empresa"))
                        return
            except Exception:
                pass
            try:
                self._reload_db_models()
            except Exception:
                pass
            self.set_status(f"Empresa {seleccion} abierta")
            messagebox.showinfo("Éxito", f"Empresa {seleccion} abierta correctamente")
            dialog.destroy()
            self.empresa_label.config(text=f"  Empresa: {self.empresa_actual}  |  Usuario: {self.usuario_actual}  |  Fecha: {datetime.now().strftime('%d/%m/%Y')}  ")
        
        def copiar_catalogo():
            destino = _seleccion_actual()
            if not destino:
                return
            if em is None:
                messagebox.showwarning("Copiar catálogo", "Multiempresa no disponible.")
                return
            # Dialogo para elegir origen
            d2 = tk.Toplevel(dialog)
            d2.title("Copiar catálogo")
            d2.transient(dialog)
            d2.grab_set()
            tk.Label(d2, text=f"Destino: {destino}", font=('Arial', 10, 'bold')).pack(padx=12, pady=(10, 6))
            tk.Label(d2, text="Origen:", font=('Arial', 9)).pack(padx=12, anchor="w")
            cb = ttk.Combobox(d2, values=[n for n in items if n != destino], state="readonly", width=34)
            if [n for n in items if n != destino]:
                cb.set([n for n in items if n != destino][0])
            cb.pack(padx=12, pady=(0, 10))
            var_rep = tk.BooleanVar(value=True)
            tk.Checkbutton(d2, text="Reemplazar catálogo existente en destino", variable=var_rep).pack(padx=12, anchor="w")

            def _do():
                origen = (cb.get() or "").strip()
                if not origen:
                    return
                r = em.copiar_catalogo(origen, destino, reemplazar=bool(var_rep.get()))
                if not r.get("exito"):
                    messagebox.showerror("Error", r.get("error", "No se pudo copiar"))
                    return
                c = r.get("copiados") or {}
                messagebox.showinfo("Copiar catálogo", f"Listo.\nSAT: {c.get('codigos_sat', 0)}\nCuentas: {c.get('catalogo_cuentas', 0)}\nCentros: {c.get('centros_costo', 0)}")
                d2.destroy()

            bf = tk.Frame(d2)
            bf.pack(fill=tk.X, padx=12, pady=10)
            tk.Button(bf, text="Copiar", command=_do, width=12, bg='lightblue').pack(side=tk.LEFT)
            tk.Button(bf, text="Cerrar", command=d2.destroy, width=12).pack(side=tk.RIGHT)
            self._fit_toplevel(d2, 0.42, 0.28, 380, 220)

        bf = tk.Frame(dialog)
        bf.pack(pady=10)
        tk.Button(bf, text="Abrir", command=abrir, width=15).pack(side=tk.LEFT, padx=6)
        tk.Button(bf, text="Copiar catálogo…", command=copiar_catalogo, width=15).pack(side=tk.LEFT, padx=6)
        self._fit_toplevel(dialog, 0.4, 0.42, 360, 300)
    
