    def imprimir(self):
        self.set_status("Preparando vista previa...")
        
        try:
            if hasattr(self, 'tree_balanza') and self.tree_balanza.winfo_exists():
                datos = []
                for item in self.tree_balanza.get_children():
                    valores = self.tree_balanza.item(item)['values']
                    if valores and valores[0] != "TOTALES":
                        datos.append(valores)
                self.impresion.imprimir_balanza(self.root, datos)
                
            elif hasattr(self, 'tree_catalogo') and self.tree_catalogo.winfo_exists():
                datos = []
                # Recorrer recursivamente para incluir nodos de clientes (hijos).
                def _recorrer(iid):
                    item = self.tree_catalogo.item(iid)
                    datos.append(item.get('values') or [])
                    for child in self.tree_catalogo.get_children(iid):
                        _recorrer(child)

                for top in self.tree_catalogo.get_children():
                    _recorrer(top)
                self.impresion.imprimir_catalogo(self.root, datos)
                
            elif hasattr(self, 'tree_polizas') and self.tree_polizas.winfo_exists():
                datos = []
                for item in self.tree_polizas.get_children():
                    datos.append(self.tree_polizas.item(item)['values'])
                self.impresion.imprimir_polizas(self.root, datos)
                
            elif hasattr(self, 'res_frame') and self.res_frame.winfo_exists():
                messagebox.showinfo("Imprimir", "Vista previa de Estado de Resultados")
            
            self.set_status("Listo")
            
        except Exception as e:
            messagebox.showerror("Error", f"Error al imprimir: {str(e)}")
            self.set_status("Error")
    
