    # Nota: el PDF se genera dentro de la app (no se abre HTML).
    
    def exportar_excel(self):
        """Exporta la tabla visible a CSV compatible con Excel."""
        try:
            tree, headers, rows = self._tabla_visible_como_tabla()
            if tree is None:
                messagebox.showwarning("Exportar", "No hay una tabla para exportar en este momento.")
                return
            default_name = "export_coi.csv"
            path = filedialog.asksaveasfilename(
                title="Exportar tabla a CSV (Excel)",
                initialfile=default_name,
                defaultextension=".csv",
                filetypes=[("CSV", "*.csv"), ("Todos", "*.*")],
            )
            if not path:
                return
            self._exportar_rows_csv(path, headers, rows)
            messagebox.showinfo("Exportar", f"Exportación completada.\nArchivo: {path}")
            self.set_status("Exportación completada")
        except Exception as ex:
            messagebox.showerror("Exportar", str(ex))
            self.set_status("Error exportando")

    def _tabla_visible_como_tabla(self):
        """Devuelve (tree, headers, rows) de la tabla visible más relevante."""
        # Preferencia explícita: último Treeview activo (evita que "otra tabla visible"
        # se exporte/imprima por accidente cuando hay varias ventanas abiertas).
        try:
            t = getattr(self, "_tabla_activa_tree", None)
            if t is not None and hasattr(t, "get_children") and t.winfo_exists():
                if t.winfo_viewable() and t.winfo_ismapped():
                    cols = list(t["columns"]) if "columns" in t.keys() else []
                    if cols:
                        # Reutilizamos el extractor normal más abajo.
                        tree = t
                    else:
                        tree = None
                else:
                    tree = None
            else:
                tree = None
        except Exception:
            tree = None

        candidates = [
            "tree_auxiliar",
            "tree_balanza",
            "tree_polizas",
            "tree_catalogo",
            "_tree_tablero_cfdi",
            "_cfdi_conceptos_tree",
        ]
        if tree is None:
            for attr in candidates:
                t = getattr(self, attr, None)
                if not t or not hasattr(t, "get_children"):
                    continue
                try:
                    if t.winfo_exists() and (len(t.get_children()) > 0):
                        tree = t
                        break
                except Exception:
                    continue
        # Fallback: buscar Treeview visible (para tablas locales en toplevels).
        if tree is None:
            try:
                def _iter_widgets(w):
                    yield w
                    try:
                        for ch in w.winfo_children():
                            yield from _iter_widgets(ch)
                    except Exception:
                        return

                best = None
                best_rows = -1
                # Root + cualquier Toplevel abierto.
                roots = [self.root]
                try:
                    for w in self.root.winfo_children():
                        if isinstance(w, tk.Toplevel):
                            roots.append(w)
                except Exception:
                    pass

                for r in roots:
                    for w in _iter_widgets(r):
                        if not isinstance(w, ttk.Treeview):
                            continue
                        try:
                            if not w.winfo_exists():
                                continue
                            # Si no está mapeado/visible, no exportar.
                            if not (w.winfo_viewable() and w.winfo_ismapped()):
                                continue
                            n = len(w.get_children())
                            if n > best_rows:
                                best = w
                                best_rows = n
                        except Exception:
                            continue
                tree = best
            except Exception:
                tree = None
        if tree is None:
            return None, [], []

        cols = list(tree["columns"]) if "columns" in tree.keys() else []
        if not cols:
            cols = list(getattr(tree, "columns", []))
        if not cols:
            return None, [], []

        headers = []
        for c in cols:
            try:
                headers.append(tree.heading(c).get("text") or c)
            except Exception:
                headers.append(c)

        def iter_ids(parent=""):
            for iid in tree.get_children(parent):
                yield iid
                yield from iter_ids(iid)

        rows = []
        for iid in iter_ids():
            vals = tree.item(iid).get("values") or []
            if len(vals) < len(cols):
                vals = list(vals) + [""] * (len(cols) - len(vals))
            rows.append(list(vals[: len(cols)]))
        return tree, headers, rows

    def _set_tabla_activa(self, tree):
        try:
            if tree is not None and hasattr(tree, "get_children"):
                self._tabla_activa_tree = tree
        except Exception:
            pass

    def _exportar_rows_csv(self, path: str, headers, rows):
        import csv as _csv

        with open(path, "w", encoding="utf-8-sig", newline="") as f:
            w = _csv.writer(f, delimiter=";")
            if headers:
                w.writerow(headers)
            for r in rows or []:
                w.writerow(r)

    def vista_previa_tabla_visible(self, titulo: str = "Reporte"):
        """Abre Vista previa / Imprimir / Guardar PDF para la tabla visible."""
        try:
            _tree, headers, rows = self._tabla_visible_como_tabla()
            if not rows:
                messagebox.showwarning("Vista previa", "No hay datos para mostrar.")
                return
            self.impresion.vista_previa_reportes_avanzados(
                self.root,
                titulo,
                rows,
                columnas=headers,
                empresa=self.empresa_actual,
            )
        except Exception as ex:
            messagebox.showerror("Vista previa", str(ex))

    @staticmethod
    def _treeview_encabezados_y_filas(tree) -> tuple:
        """Encabezados visibles y filas de valores para exportar / PDF."""
        cols = tree["columns"]
        headers = []
        for c in cols:
            try:
                t = tree.heading(c, "text")
            except Exception:
                t = ""
            headers.append(t if t else str(c))
        rows = [tuple(tree.item(iid, "values")) for iid in tree.get_children("")]
        return headers, rows
    
    def mostrar_bloqueo_periodos(self):
        """Ventana para bloquear/desbloquear periodos contables (Fase 1 - Informe Aspel COI)."""
        if not self._requiere_permiso("auditoria", "Bloqueo de periodos"):
            return
        try:
            from backend.modules.periodos_bloqueados import PeriodosBloqueados
        except ImportError:
            messagebox.showerror("Error", "Modulo periodos_bloqueados no disponible.")
            return
        win = tk.Toplevel(self.root)
        win.title("Bloquear / Desbloquear periodo")
        win.transient(self.root)
        win.resizable(True, True)
        main = tk.Frame(win, bg='white', padx=10, pady=10)
        main.pack(fill=tk.BOTH, expand=True)
        tk.Label(main, text="Periodos bloqueados (no se pueden registrar polizas en estos periodos):",
                 font=('Arial', 10, 'bold'), bg='white').pack(anchor='w')
        tree = ttk.Treeview(main, columns=("Anio", "Mes", "Bloqueado", "Fecha", "Usuario"), show="headings", height=8)
        for c in ("Anio", "Mes", "Bloqueado", "Fecha", "Usuario"):
            tree.heading(c, text=c)
        tree.pack(fill=tk.BOTH, expand=True, pady=5)
        pb = PeriodosBloqueados()
        def refrescar():
            for i in tree.get_children():
                tree.delete(i)
            for r in pb.listar():
                tree.insert("", "end", values=(
                    r["anio"], r["mes"], "Si" if r["bloqueado"] else "No",
                    r.get("fecha_bloqueo") or "", r.get("usuario") or ""
                ))
        refrescar()
        f = tk.Frame(main, bg='white')
        f.pack(fill=tk.X, pady=5)
        tk.Label(f, text="Anio:", bg='white').pack(side=tk.LEFT, padx=2)
        e_anio = tk.Entry(f, width=6)
        e_anio.pack(side=tk.LEFT, padx=2)
        e_anio.insert(0, str(datetime.now().year))
        tk.Label(f, text="Mes:", bg='white').pack(side=tk.LEFT, padx=2)
        try:
            _mx_mes = int(pb._mes_max_permitido())
        except Exception:
            _mx_mes = 12
        e_mes = ttk.Combobox(f, values=[str(i) for i in range(1, _mx_mes + 1)], width=3)
        e_mes.set(str(datetime.now().month))
        e_mes.pack(side=tk.LEFT, padx=2)
        def bloquear():
            try:
                anio, mes = int(e_anio.get()), int(e_mes.get())
                r = pb.bloquear(anio, mes, self.usuario_actual)
                if r.get("exito"):
                    messagebox.showinfo("OK", r["mensaje"])
                    refrescar()
                else:
                    messagebox.showerror("Error", r.get("error", ""))
            except ValueError:
                messagebox.showerror("Error", "Anio y mes numericos")
        def reapertura_supervisor():
            sel = tree.selection()
            if not sel:
                messagebox.showwarning("Aviso", "Seleccione un periodo en la lista")
                return
            item = tree.item(sel[0])
            v = item["values"]
            if not v or v[2] != "Si":
                messagebox.showinfo("Info", "Seleccione un periodo bloqueado")
                return
            anio, mes = int(v[0]), int(v[1])
            pw = simpledialog.askstring("Supervisor", "Contraseña de supervisor:", show="*", parent=win)
            if pw is None:
                return
            motivo = simpledialog.askstring("Bitácora", "Motivo de reapertura (mín. 5 caracteres):", parent=win)
            if motivo is None:
                return
            r = pb.desbloquear_con_supervisor(
                anio, mes, password_supervisor=pw, usuario=self.usuario_actual, motivo=motivo
            )
            if r.get("exito"):
                messagebox.showinfo("OK", r["mensaje"])
                refrescar()
            else:
                messagebox.showerror("Error", r.get("error", ""))

        def ver_bitacora_reapertura():
            bi = tk.Toplevel(win)
            bi.title("Bitácora de reaperturas")
            bi.transient(win)
            tr = ttk.Treeview(bi, columns=("fecha", "anio", "mes", "usuario", "motivo"), show="headings", height=12)
            for c, t in zip(("fecha", "anio", "mes", "usuario", "motivo"), ("Fecha", "Año", "Mes", "Usuario", "Motivo")):
                tr.heading(c, text=t)
                tr.column(c, width=280 if c == "motivo" else 90)
            tr.pack(fill=tk.BOTH, expand=True, padx=8, pady=8)
            for row in pb.listar_reaperturas(300):
                tr.insert("", tk.END, values=(row.get("fecha"), row.get("anio"), row.get("mes"), row.get("usuario"), (row.get("motivo") or "")[:200]))
            tk.Button(bi, text="Cerrar", command=bi.destroy).pack(pady=6)
            self._fit_toplevel(bi, 0.55, 0.5, 720, 400)

        tk.Button(f, text="Bloquear periodo", command=bloquear, bg='#ffcccc').pack(side=tk.LEFT, padx=5)
        tk.Button(f, text="Reabrir con supervisor…", command=reapertura_supervisor, bg='#ccffcc').pack(side=tk.LEFT, padx=5)
        tk.Button(f, text="Bitácora reaperturas", command=ver_bitacora_reapertura, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=8, cursor="hand2").pack(side=tk.LEFT, padx=5)
        tk.Button(
            f,
            text="Vista previa / PDF",
            command=lambda: self.vista_previa_tabla_visible("Periodos bloqueados"),
            bg=THEME["btn_secondary_bg"],
            relief=tk.FLAT,
            padx=10,
            cursor="hand2",
        ).pack(side=tk.LEFT, padx=8)
        tk.Button(
            f,
            text="Exportar CSV (Excel)",
            command=self.exportar_excel,
            bg=THEME["btn_secondary_bg"],
            relief=tk.FLAT,
            padx=10,
            cursor="hand2",
        ).pack(side=tk.LEFT, padx=4)
        tk.Button(f, text="Cerrar", command=win.destroy).pack(side=tk.LEFT, padx=5)
        self._fit_toplevel(win, 0.52, 0.42, 480, 300)
    
