    def exportar_xml_balanza_desde_vista(self):
        """Exporta XML Balanza SAT (Anexo 24) desde la vista Balanza."""
        if not hasattr(self, 'mes_balanza') or not self.mes_balanza.winfo_exists():
            messagebox.showwarning("Aviso", "Abra la vista Balanza de comprobacion primero.")
