    def exportar_xml_catalogo_desde_vista(self):
        """Exporta XML Catalogo de cuentas SAT (Anexo 24). RFC se puede elegir del catálogo de clientes o escribir manualmente."""
        d = tk.Toplevel(self.root)
        d.title("Exportar XML Catalogo SAT")
        d.transient(self.root)
        tk.Label(d, text="Esta ventana solo exporta el catálogo de cuentas. No sube certificados (CSD).").pack(pady=4)
        tk.Label(d, text="RFC del contribuyente:").pack(pady=2)
        try:
            from backend.models.clientes import CatalogoClientes
            clientes_list = CatalogoClientes().listar_para_combo()
            valores_combo = [disp for _rfc, disp in clientes_list]
        except Exception:
            clientes_list = []
            valores_combo = []
        rfc_combo = ttk.Combobox(d, values=valores_combo, width=40)
        rfc_combo.pack(pady=2)
        _rfc_def = self._rfc_empresa_para_xml()
        if _rfc_def:
            rfc_combo.set(_rfc_def)
        elif valores_combo:
            rfc_combo.set(valores_combo[0])
        else:
            rfc_combo.set("SSE-123456-ABC")
        tk.Label(d, text="(Prioridad: Datos de empresa; o elija cliente; o escriba otro RFC)").pack()
        f2 = tk.Frame(d)
        f2.pack(pady=8)
        tk.Label(f2, text="Mes:").pack(side=tk.LEFT, padx=5)
        mes_combo = ttk.Combobox(f2, values=[f"{i:02d}" for i in range(1, 13)], width=5)
        mes_combo.set(f"{datetime.now().month:02d}")
        mes_combo.pack(side=tk.LEFT, padx=2)
        tk.Label(f2, text="Anio:").pack(side=tk.LEFT, padx=5)
        anio_entry = tk.Entry(f2, width=6)
        anio_entry.insert(0, str(datetime.now().year))
        anio_entry.pack(side=tk.LEFT, padx=2)
        def hacer():
            sel = rfc_combo.get().strip()
            if " - " in sel:
                rfc = sel.split(" - ", 1)[0].strip()
            else:
                rfc = sel
            if not rfc:
                messagebox.showerror("Error", "Indique RFC")
                return
            try:
                mes = int(mes_combo.get())
                anio = int(anio_entry.get())
            except Exception:
                messagebox.showerror("Error", "Mes y anio numericos")
                return
            try:
                from backend.modules.fiscal import FiscalSAT
                f = FiscalSAT(db_path=self.polizas.db_path, proveedor=self.proveedor_fiscal)
                xml = f.generar_xml_catalogo_cuentas(mes, anio, rfc)
                ruta = f.guardar_xml(xml, f"Catalogo_{rfc}_{anio}{mes:02d}.xml")
                messagebox.showinfo("Listo", f"XML guardado en:\n{ruta}")
                d.destroy()
            except Exception as e:
                messagebox.showerror("Error", str(e))
        tk.Button(d, text="Exportar", command=hacer).pack(pady=10)
        self._fit_toplevel(d, 0.45, 0.32, 400, 220)

