    def _deptos_abrir_balanza_con_centro(self):
        """Abre la balanza e indica usar el filtro Centro (departamento)."""
        if not self._requiere_permiso("reportes", "Balanza de comprobación"):
            return
        self.mostrar_balanza()
        self.set_status(
            "Balanza por departamento: elija «Centro» junto a Fuente (TODOS o un departamento) y pulse Generar. "
            "Exportar XML SAT / Excel respeta la vista."
        )

    def mostrar_estado_resultados_por_departamento_menu(self):
        """ER por centro sin pasar por la tabla de catálogo de centros."""
        if not self._requiere_permiso("reportes", "Estado de resultados"):
            return
        try:
            from backend.modules.centros_costo import CentrosCosto
            from backend.modules.reportes_centros_costo import ReportesCentrosCosto
        except Exception as ex:
            messagebox.showerror("Departamentos", str(ex))
            return
        cc = CentrosCosto(db_path=self.polizas.db_path)
        items = cc.listar_para_combo() or []
        if not items:
            messagebox.showwarning(
                "Departamentos",
                "No hay centros de costo. Alta en Cuentas y pólizas → Centros de costo.",
            )
            return
        rc = ReportesCentrosCosto(db_path=self.polizas.db_path)
        d = tk.Toplevel(self.root)
        d.title("Estado de resultados por departamento")
        d.transient(self.root)
        d.resizable(True, True)
        main = tk.Frame(d, padx=12, pady=12, bg=THEME["bg_content"])
        main.pack(fill=tk.BOTH, expand=True)
        top = tk.Frame(main, bg=THEME["bg_sidebar"], padx=10, pady=8)
        top.pack(fill=tk.X, pady=(0, 8))
        tk.Label(top, text="Departamento / centro:", bg=THEME["bg_sidebar"]).pack(side=tk.LEFT, padx=(0, 4))
        cb_centro = ttk.Combobox(top, values=[disp for _id, disp in items], width=40, state="readonly")
        cb_centro.set(items[0][1] if items else "")
        cb_centro.pack(side=tk.LEFT, padx=4)
        tk.Label(top, text="Mes:", bg=THEME["bg_sidebar"]).pack(side=tk.LEFT, padx=(12, 4))
        mes_r = ttk.Combobox(top, values=[f"{i:02d}" for i in range(1, 13)], width=5, state="readonly")
        mes_r.set(f"{datetime.now().month:02d}")
        mes_r.pack(side=tk.LEFT, padx=4)
        tk.Label(top, text="Año:", bg=THEME["bg_sidebar"]).pack(side=tk.LEFT, padx=(8, 4))
        anio_r = tk.Entry(top, width=8)
        anio_r.insert(0, str(datetime.now().year))
        anio_r.pack(side=tk.LEFT, padx=4)
        cvf = tk.Frame(main, bg="white", relief=tk.SUNKEN, bd=1)
        cvf.pack(fill=tk.BOTH, expand=True, pady=(0, 8))

        def _id_desde_combo():
            sel = (cb_centro.get() or "").strip()
            for _id, disp in items:
                if disp == sel:
                    return int(_id), disp
            return None

        def generar_r():
            for w in cvf.winfo_children():
                w.destroy()
            got = _id_desde_combo()
            if not got:
                messagebox.showerror("Error", "Seleccione un departamento.")
                return
            centro_id, centro_disp = got
            try:
                p = int(mes_r.get())
                e = int(anio_r.get().strip())
            except Exception:
                messagebox.showerror("Error", "Mes/Año inválidos.")
                return
            resultados = rc.estado_resultados_por_centro(p, e, centro_id)
            canvas = tk.Canvas(cvf, bg="white")
            canvas.pack(fill=tk.BOTH, expand=True)
            y = 24
            canvas.create_text(
                40,
                y,
                text="ESTADO DE RESULTADOS (por departamento)",
                font=(THEME["font_ui"], 13, "bold"),
                anchor="w",
                fill="#000080",
            )
            y += 28
            sub = (
                f"Del 1 al {self.ultimo_dia_mes(p, e)} de {self.nombre_mes(p)} de {e} · {centro_disp} · Moneda: MXN"
            )
            canvas.create_text(40, y, text=sub, font=(THEME["font_ui"], 9), anchor="w")
            y += 36
            for label, key in (
                ("Ventas:", "ventas"),
                ("Costo de ventas:", "costos"),
            ):
                canvas.create_text(40, y, text=label, font=(THEME["font_ui"], 10), anchor="w")
                canvas.create_text(420, y, text=f"${float(resultados.get(key) or 0):,.2f}", font=(THEME["font_ui"], 10), anchor="e")
                y += 22
            canvas.create_line(40, y, 430, y, fill="black")
            y += 20
            canvas.create_text(40, y, text="Utilidad bruta:", font=(THEME["font_ui"], 10, "bold"), anchor="w")
            canvas.create_text(
                420,
                y,
                text=f"${float(resultados.get('utilidad_bruta') or 0):,.2f}",
                font=(THEME["font_ui"], 10, "bold"),
                anchor="e",
            )
            y += 28
            canvas.create_text(40, y, text="Gastos de operación:", font=(THEME["font_ui"], 10), anchor="w")
            canvas.create_text(
                420, y, text=f"${float(resultados.get('gastos') or 0):,.2f}", font=(THEME["font_ui"], 10), anchor="e"
            )
            y += 22
            canvas.create_line(40, y, 430, y, fill="black", width=2)
            y += 24
            canvas.create_text(40, y, text="UTILIDAD NETA:", font=(THEME["font_ui"], 11, "bold"), anchor="w")
            canvas.create_text(
                420,
                y,
                text=f"${float(resultados.get('utilidad_neta') or 0):,.2f}",
                font=(THEME["font_ui"], 11, "bold"),
                anchor="e",
                fill="#006400",
            )

        bf2 = tk.Frame(main, bg=THEME["bg_content"])
        bf2.pack(fill=tk.X)
        tk.Button(
            bf2,
            text="Generar",
            command=generar_r,
            bg=THEME["btn_primary_bg"],
            fg=THEME["btn_primary_fg"],
            relief=tk.FLAT,
            padx=12,
            pady=6,
            cursor="hand2",
        ).pack(side=tk.LEFT)
        tk.Button(bf2, text="Cerrar", command=d.destroy).pack(side=tk.RIGHT)
        generar_r()
        self._fit_toplevel(d, 0.55, 0.52, 560, 440)

    
