        naturaleza_var = tk.StringVar(value=str(c.get('naturaleza') or 'DEUDORA').upper())
        tk.Radiobutton(naturaleza_frame, text="Deudora", variable=naturaleza_var, value="DEUDORA", bg='white').grid(row=1, column=0, sticky='w', padx=20, pady=2)
        tk.Radiobutton(naturaleza_frame, text="Acreedora", variable=naturaleza_var, value="ACREEDORA", bg='white').grid(row=1, column=1, sticky='w', padx=20, pady=2)

        nivel_frame = tk.Frame(tab_atributos, bg='white')
        nivel_frame.pack(fill=tk.X, padx=10, pady=5)
        tk.Label(nivel_frame, text="Nivel:", bg='white').pack(side=tk.LEFT, padx=5)
