    def mostrar_polizas(self):
        if not self._requiere_permiso("polizas", "Captura de pólizas"):
            return
        self._sincronizar_panel_lateral_modulo("Pólizas", "polizas")
        self.limpiar_area_trabajo()
        self.set_status("Pólizas - Listo")
        
        main_frame = tk.Frame(self.area_trabajo, bg='white')
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        titulo_frame = tk.Frame(main_frame, bg=THEME["header_bg"])
        titulo_frame.pack(fill=tk.X)
        tk.Label(titulo_frame, text=f"PÓLIZAS - {self.empresa_actual}", 
                bg=THEME["header_bg"], fg=THEME["header_fg"], font=(THEME["font_ui"], 10, 'bold'),
                anchor='w').pack(side=tk.LEFT, padx=16, pady=10)
        
        periodo_frame = tk.Frame(main_frame, bg=THEME["bg_sidebar"], relief=tk.FLAT, padx=12, pady=10)
        periodo_frame.pack(fill=tk.X)
        
        tk.Label(periodo_frame, text="Período:", bg=THEME["bg_sidebar"], fg=THEME["text_primary"]).pack(side=tk.LEFT, padx=5)
        self.mes_polizas = ttk.Combobox(periodo_frame, values=[f"{i:02d}" for i in range(1,13)], width=5)
        self.mes_polizas.set(f"{datetime.now().month:02d}")
        self.mes_polizas.pack(side=tk.LEFT, padx=2)
        
        tk.Label(periodo_frame, text="/", bg=THEME["bg_sidebar"], fg=THEME["text_primary"]).pack(side=tk.LEFT)
        self.anio_polizas = tk.Entry(periodo_frame, width=6)
        self.anio_polizas.insert(0, datetime.now().year)
        self.anio_polizas.pack(side=tk.LEFT, padx=2)

        def _ref_polizas_lista(_=None):
            try:
                self.actualizar_lista_polizas()
            except Exception:
                pass

