        def _lista_cuentas_para_combo():
            cuentas = self.catalogo.obtener_cuentas(incluir_inactivas=False)
            out = []
            for c in cuentas:
                num = c[0]
                agrup = (c[6] if len(c) > 6 and c[6] else self.catalogo._codigo_agrupador_sat(num))
                nom = c[1] or ""
                out.append(f"{num}  {agrup}  {nom}")
            return out
        _valores_cuentas = _lista_cuentas_para_combo()
        
        tk.Label(add_frame, text="Cuenta:", bg='#E0E0E0').grid(row=0, column=0, padx=2)
        entry_cuenta = ttk.Combobox(add_frame, width=42, values=_valores_cuentas)
        entry_cuenta.grid(row=0, column=1, padx=2)
        def filtrar_cuentas(event=None):
            txt = (entry_cuenta.get() or "").strip().upper()
            if not txt:
                entry_cuenta["values"] = _valores_cuentas
                return
            entry_cuenta["values"] = [v for v in _valores_cuentas if txt in v.upper()]
        entry_cuenta.bind('<KeyRelease>', filtrar_cuentas)
        entry_cuenta["values"] = _valores_cuentas
        def abrir_catalogo_cuentas():
            w = tk.Toplevel(dialog)
