        entry_conc = tk.Entry(add_frame, width=24)
        entry_conc.grid(row=0, column=11, padx=2)
        
        tk.Label(add_frame, text="Cargo:", bg='#E0E0E0').grid(row=0, column=12, padx=2)
        entry_cargo = tk.Entry(add_frame, width=10)
        entry_cargo.grid(row=0, column=13, padx=2)
        
        tk.Label(add_frame, text="Abono:", bg='#E0E0E0').grid(row=0, column=14, padx=2)
        entry_abono = tk.Entry(add_frame, width=10)
