        self._sincronizar_panel_lateral_modulo("Balanza de comprobación", "balanza")
        self.limpiar_area_trabajo()
        self.set_status("Balanza de comprobación - Listo")
        
        main_frame = tk.Frame(self.area_trabajo, bg='white')
