        self.tc_balanza = tk.Entry(periodo_frame, width=8)
        self.tc_balanza.insert(0, "1.0")
        self.tc_balanza.pack(side=tk.LEFT, padx=2)

        def _autofill_tc_balanza(_event=None):
            try:
                mon = (self.moneda_balanza.get() or "MXN").strip().upper()
                if mon == "MXN":
                    self.tc_balanza.delete(0, tk.END)
                    self.tc_balanza.insert(0, "1.0")
                    return
                mes = int(self.mes_balanza.get())
                anio = int(self.anio_balanza.get())
                f = f"{anio:04d}-{mes:02d}-{self.ultimo_dia_mes(mes, anio):02d}"
                v, _src = self._tipo_cambio_catalogo_por_iso_fecha(mon, f)
                if v and float(v) > 0:
                    self.tc_balanza.delete(0, tk.END)
                    self.tc_balanza.insert(0, f"{float(v):.6f}")
            except Exception:
                pass

        self.moneda_balanza.bind("<<ComboboxSelected>>", _autofill_tc_balanza)
        self.mes_balanza.bind("<<ComboboxSelected>>", _autofill_tc_balanza)
        self.anio_balanza.bind("<FocusOut>", _autofill_tc_balanza)
        
