        tk.Button(periodo_frame, text="Imprimir", command=self.imprimir,
                 bg=THEME["btn_secondary_bg"], fg=THEME["text_primary"], relief=tk.FLAT, padx=12, cursor="hand2").pack(side=tk.LEFT, padx=5)
        tk.Button(periodo_frame, text="Exportar XML SAT", command=self.exportar_xml_balanza_desde_vista,
                 bg=THEME["btn_secondary_bg"], fg=THEME["text_primary"], relief=tk.FLAT, padx=12, cursor="hand2").pack(side=tk.LEFT, padx=5)
        tk.Button(periodo_frame, text="Exportar Excel", command=self.exportar_balanza_xlsx,
                 bg=THEME["btn_secondary_bg"], fg=THEME["text_primary"], relief=tk.FLAT, padx=10, cursor="hand2").pack(side=tk.LEFT, padx=2)

        # Fuente de datos: sistema o Excel externo (BALANZA.xls)
        tk.Label(periodo_frame, text="Fuente:", bg=THEME["bg_sidebar"], fg=THEME["text_primary"]).pack(side=tk.LEFT, padx=(14, 4))
        self.balanza_fuente = ttk.Combobox(periodo_frame, values=["Sistema", "Excel (BALANZA.xls)"], width=20, state="readonly")
        self.balanza_fuente.set("Sistema")
