        tk.Label(periodo_frame, text="Centro:", bg=THEME["bg_sidebar"], fg=THEME["text_primary"]).pack(side=tk.LEFT, padx=(12, 4))
        self.balanza_centro = ttk.Combobox(periodo_frame, values=["TODOS"] + [disp for _id, disp in _cc_items], width=26, state="readonly")
        self.balanza_centro.set("TODOS")
