        tabla_frame = tk.Frame(main_frame, bg='white')
        tabla_frame.pack(fill=tk.BOTH, expand=True, padx=5, pady=5)
        
        vsb = tk.Scrollbar(tabla_frame, orient=tk.VERTICAL)
        hsb = tk.Scrollbar(tabla_frame, orient=tk.HORIZONTAL)
        
        columns = ("Cuenta", "Tipo / clase", "Descripción", "Saldo Inicial", "Debe", "Haber", "Saldo Final")
        self.tree_balanza = ttk.Treeview(tabla_frame, columns=columns, show="headings",
                                        yscrollcommand=vsb.set, xscrollcommand=hsb.set)
        
        vsb.config(command=self.tree_balanza.yview)
        hsb.config(command=self.tree_balanza.xview)
        
        for col in columns:
            self.tree_balanza.heading(col, text=col)
            if col == "Descripción":
                self.tree_balanza.column(col, width=260)
            elif col == "Tipo / clase":
                self.tree_balanza.column(col, width=150, anchor="w")
            else:
                self.tree_balanza.column(col, width=120, anchor='e' if col not in ["Cuenta", "Descripción"] else 'w')
        
        self.tree_balanza.grid(row=0, column=0, sticky='nsew')
        vsb.grid(row=0, column=1, sticky='ns')
        hsb.grid(row=1, column=0, sticky='ew')
        
        tabla_frame.grid_rowconfigure(0, weight=1)
        tabla_frame.grid_columnconfigure(0, weight=1)

        # Resumen inferior estilo COI: al seleccionar una fila en Balanza
        def _on_select_balanza(event=None):
            try:
                sel = self.tree_balanza.selection()
                if not sel:
                    return
                iid = sel[0]
                item = self.tree_balanza.item(iid)
                vals = item.get("values") or []
                if len(vals) < 7:
                    return
                num_cuenta = str(vals[0]).strip()
                nombre_cuenta = str(vals[2]).strip()
                if not num_cuenta or num_cuenta in ("TOTALES", "Error"):
                    if hasattr(self, "lbl_resumen_balanza_select"):
                        self.lbl_resumen_balanza_select.config(text="Detalle: —")
                    return

                adeudo_final = self._parse_money(vals[6] if len(vals) > 6 else 0)
                nombre_upper = nombre_cuenta.upper()
                cuenta_upper = num_cuenta.upper()

                # Apartado (coincide con filtros)
                apartado = "—"
                if cuenta_upper.startswith("115") or "CLIENTE" in nombre_upper:
                    apartado = "Clientes"
                elif cuenta_upper.startswith("102") or cuenta_upper.startswith("112") or "BANCO" in nombre_upper:
                    apartado = "Bancos"
                elif "IVA" in nombre_upper and ("ACREDIT" in nombre_upper or "ACREDITAR" in nombre_upper):
                    apartado = "IVA acreditable"
                elif "IVA" in nombre_upper and ("TRASLAD" in nombre_upper or "COBR" in nombre_upper or "NO COBR" in nombre_upper):
                    apartado = "IVA trasladado"
                elif cuenta_upper.startswith("60") or cuenta_upper.startswith("5"):
                    apartado = "Costos"

                # Cliente(s) desde movimientos (si existe en la BD)
                clientes = []
                try:
                    clientes = self.catalogo.obtener_clientes_desglose(num_cuenta, max_items=None) or []
                except Exception:
                    clientes = []

                if clientes:
                    top = clientes[:3]
                    clientes_txt = ", ".join(
                        [
                            f"{(it.get('cliente_nombre') or '').strip() or '—'}"
                            f"{' (' + (it.get('cliente_rfc') or '').strip() + ')' if (it.get('cliente_rfc') or '').strip() else ''}: ${float(it.get('adeudo') or 0.0):,.2f}"
                            for it in top
                        ]
                    )
                    if len(clientes) > 3:
                        clientes_txt += f" (+{len(clientes)-3} más)"
                else:
                    # Si venimos de Excel, normalmente no hay desglose por cliente en BD.
                    clientes_txt = nombre_cuenta[:60] if apartado == "Clientes" else "—"

                # Bancos / IVA (en COI se muestran como "apartado" del catálogo; usamos la descripción de la cuenta)
                bancos_txt = nombre_cuenta[:60] if (
                    cuenta_upper.startswith("102") or cuenta_upper.startswith("112") or "BANCO" in nombre_upper
                ) else "—"
                iva_txt = nombre_cuenta[:60] if "IVA" in nombre_upper else "—"
                tipo_sat = "—"
                naturaleza = "—"
                tipo_cuenta = "—"
                try:
                    cta = self.catalogo.obtener_cuenta(num_cuenta)
                    if cta:
                        tipo_sat = str(cta.get("codigo_agrupador_sat") or "—")
                        naturaleza = str(cta.get("naturaleza") or "—")
                        tipo_cuenta = str(cta.get("tipo_cuenta") or "—")
                except Exception:
                    pass

                if hasattr(self, "lbl_resumen_balanza_select"):
                    self.lbl_resumen_balanza_select.config(
                        text=(
                            f"Detalle: {apartado} | Cuenta {num_cuenta} | "
                            f"Tipo: {tipo_sat} | Naturaleza: {naturaleza} | Clase: {tipo_cuenta} | "
                            f"Cliente(s): {clientes_txt} | Bancos: {bancos_txt} | IVA: {iva_txt} | "
                            f"Adeudo: ${adeudo_final:,.2f}"
                        )
                    )
            except Exception:
                try:
                    if hasattr(self, "lbl_resumen_balanza_select"):
                        self.lbl_resumen_balanza_select.config(text="Detalle: —")
                except Exception:
                    pass

        self.tree_balanza.bind("<<TreeviewSelect>>", _on_select_balanza)
        
        # Barra rápida de filtros (más parecido a COI)
        filtros_frame = tk.Frame(main_frame, bg=THEME["bg_sidebar"], relief=tk.FLAT, padx=12, pady=8)
        filtros_frame.pack(fill=tk.X, before=tabla_frame)
        
        # Variable de filtro (seguimos usando el combobox internamente)
        self.balanza_filtro_tipo = tk.StringVar(value="Todos")

        barra1 = tk.Frame(filtros_frame, bg=THEME["bg_sidebar"])
        barra1.pack(fill=tk.X)
        tk.Label(barra1, text="Filtrar por:", bg=THEME["bg_sidebar"], fg=THEME["text_primary"], font=(THEME["font_ui"], 9, 'bold')).pack(side=tk.LEFT, padx=(0, 10))

        botones_refs = []
        def _set_filtro_tipo(val: str):
            self.balanza_filtro_tipo.set(val)
            # Resaltar visualmente el botón activo
            for ref, ref_val in botones_refs:
                if ref_val == val:
                    ref.configure(bg=THEME["btn_primary_bg"], fg=THEME["btn_primary_fg"])
                else:
                    ref.configure(bg=THEME["btn_secondary_bg"], fg=THEME["text_primary"])
            self.aplicar_filtros_balanza()

        botones = [
            ("Todos", "Todos"),
            ("👥 Clientes", "Clientes"),
            ("🏦 Bancos", "Bancos"),
            ("💳 IVA acreditable", "IVA acreditable"),
            ("↗️ IVA trasladado", "IVA trasladado"),
            ("🧮 Costos", "Costos"),
        ]
        for label, val in botones:
            b = tk.Button(
                barra1,
                text=label,
                command=lambda v=val: _set_filtro_tipo(v),
                bg=THEME["btn_secondary_bg"],
                fg=THEME["text_primary"],
                relief=tk.RAISED,
                padx=10,
                pady=2,
                cursor="hand2",
                font=(THEME["font_ui"], 8, "bold"),
            )
            b.pack(side=tk.LEFT, padx=4)
            botones_refs.append((b, val))

            # Ajustar resalte inicial si coincide con el valor default.
            if val == self.balanza_filtro_tipo.get():
                b.configure(bg=THEME["btn_primary_bg"], fg=THEME["btn_primary_fg"])

        # Fila 2: búsqueda y rangos
        barra2 = tk.Frame(filtros_frame, bg=THEME["bg_sidebar"])
        barra2.pack(fill=tk.X, pady=(8, 0))
        tk.Label(barra2, text="Desglose:", bg=THEME["bg_sidebar"], fg=THEME["text_primary"], font=(THEME["font_ui"], 9, "bold")).pack(side=tk.LEFT, padx=(0, 6))
        self.balanza_nivel_combo = ttk.Combobox(
            barra2,
            values=[
                "Detalle (todas las cuentas)",
                "Nivel 1 (más comprimido)",
                "Nivel 2 (ejecutiva)",
                "Nivel 3",
                "Nivel 4",
                "Nivel 5 (más detalle)",
            ],
            width=28,
            state="readonly",
        )
        self.balanza_nivel_combo.set("Detalle (todas las cuentas)")
        self.balanza_nivel_combo.pack(side=tk.LEFT, padx=4)
        self.balanza_nivel_combo.bind("<<ComboboxSelected>>", lambda _e: self.aplicar_filtros_balanza())

        tk.Label(barra2, text="Buscar (cuenta/desc):", bg=THEME["bg_sidebar"], fg=THEME["text_primary"]).pack(side=tk.LEFT, padx=(14, 4))
        self.balanza_buscar = tk.Entry(barra2, width=26)
        self.balanza_buscar.pack(side=tk.LEFT, padx=4)
        
        tk.Label(barra2, text="Monto min:", bg=THEME["bg_sidebar"], fg=THEME["text_primary"]).pack(side=tk.LEFT, padx=(10, 4))
