        tk.Button(bf, text="Exportar CSV (Excel)", command=self.exportar_excel, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=12, pady=6, cursor="hand2").pack(side=tk.LEFT, padx=4)
