    def cuadre_rapido_balanza(self):
        """Validación inmediata Debe/Haber y Σ saldos Deudor vs Acreedor; sugerencias si no cuadra."""
        try:
            mes = int(self.mes_balanza.get()) if hasattr(self, "mes_balanza") else datetime.now().month
            anio = int(self.anio_balanza.get()) if hasattr(self, "anio_balanza") else datetime.now().year
            mon = (self.moneda_balanza.get() if hasattr(self, "moneda_balanza") else "MXN") or "MXN"
            mon = mon.strip().upper()
            try:
                tc = float((self.tc_balanza.get() if hasattr(self, "tc_balanza") else "1").replace(",", ""))
            except Exception:
                tc = 1.0
            if tc <= 0:
                tc = 1.0
        except Exception:
            messagebox.showerror("Cuadre rápido", "Parámetros inválidos.")
            return

        r = self.reportes.verificacion_cuadre(mes, anio, moneda_reporte=mon, tipo_cambio=tc)
        if not r.get("exito"):
            messagebox.showerror("Cuadre rápido", "No se pudo calcular el cuadre.")
            return

        b_ok = bool(r.get("balanza_cuadra"))
        s_ok = bool(r.get("saldos_cuadra")) if r.get("saldos_cuadra") is not None else (
            abs(float(r.get("saldos_diferencia") or 0)) <= 0.01
        )
        if b_ok and s_ok:
            messagebox.showinfo(
                "Cuadre rápido",
                f"Movimientos: Debe = Haber.\n"
                f"Debe: ${float(r.get('balanza_debe') or 0):,.2f}  |  Haber: ${float(r.get('balanza_haber') or 0):,.2f}\n\n"
                f"Saldos (columnas): Σ Deudor = Σ Acreedor.\n"
                f"Deudor: ${float(r.get('saldos_deudor') or 0):,.2f}  |  Acreedor: ${float(r.get('saldos_acreedor') or 0):,.2f}",
            )
            return

        lines = []
        if not b_ok:
            dif = float(r.get("balanza_diferencia") or 0)
            lines.append(f"Movimientos no cuadran (Debe − Haber): ${dif:,.2f}")
            lines.append("Candidatas (Debe/Haber):")
            for it in (r.get("candidatos_balanza") or [])[:6]:
                lines.append(
                    f"  • {it.get('num_cuenta', '')} — |Debe−Haber|: ${float(it.get('score') or 0):,.2f}"
                )
            lines.append("")
        if not s_ok:
            difs = float(r.get("saldos_diferencia") or 0)
            lines.append(f"Saldos no cuadran (Σ Deudor − Σ Acreedor): ${difs:,.2f}")
            lines.append("Candidatas (columnas saldo):")
            for it in (r.get("candidatos_saldos") or [])[:6]:
                lines.append(
                    f"  • {it.get('num_cuenta', '')} — max col.: ${float(it.get('score') or 0):,.2f}"
                )
        messagebox.showwarning("Cuadre rápido", "\n".join(lines))

    def exportar_balanza_xlsx(self):
        """Exporta la balanza visible (desglose + filtros) a .xlsx con formato."""
        if not hasattr(self, "tree_balanza") or not self.tree_balanza.winfo_exists():
            messagebox.showwarning("Balanza", "Abra la vista Balanza de comprobación primero.")
            return
        try:
            from openpyxl import Workbook
            from openpyxl.styles import Font, Alignment, PatternFill, Border, Side
            from openpyxl.utils import get_column_letter
        except Exception:
            messagebox.showerror("Excel", "Instale openpyxl: pip install openpyxl")
            return

        try:
            mes = int(self.mes_balanza.get())
            anio = int(self.anio_balanza.get())
            moneda_rep = (self.moneda_balanza.get() if hasattr(self, "moneda_balanza") else "MXN") or "MXN"
            moneda_rep = moneda_rep.strip().upper()
            try:
                tc_rep = float((self.tc_balanza.get() if hasattr(self, "tc_balanza") else "1").replace(",", ""))
            except Exception:
                tc_rep = 1.0
        except Exception:
            mes, anio, moneda_rep, tc_rep = datetime.now().month, datetime.now().year, "MXN", 1.0

        filtrada = self._balanza_filtrar_rows(self._balanza_rows_vista_agrupada())
        nv = self._balanza_nivel_desglose()
        desglose_txt = "Detalle" if nv >= 99 else f"Nivel {nv}"

        sugerido = f"balanza_{anio}{mes:02d}_{desglose_txt.replace(' ', '_')}.xlsx"
        ruta = filedialog.asksaveasfilename(
            parent=self.root,
            title="Guardar balanza (Excel)",
            defaultextension=".xlsx",
            initialfile=sugerido,
            filetypes=[("Excel", "*.xlsx")],
        )
        if not ruta:
            return

        wb = Workbook()
        ws = wb.active
        ws.title = "Balanza"

        head_fill = PatternFill("solid", fgColor="1E3A5F")
        head_font = Font(bold=True, color="FFFFFF")
        thin = Side(style="thin", color="CBD5E1")
        border = Border(left=thin, right=thin, top=thin, bottom=thin)

        r = 1
        ws.merge_cells(start_row=r, start_column=1, end_row=r, end_column=7)
        ws.cell(r, 1, f"Balanza de comprobación — {getattr(self, 'empresa_actual', '') or ''}").font = Font(bold=True, size=12)
        r += 1
        ws.merge_cells(start_row=r, start_column=1, end_row=r, end_column=7)
        ley = f"Periodo {mes:02d}/{anio} · Desglose: {desglose_txt} · Moneda: {moneda_rep}"
        if moneda_rep != "MXN":
            ley += f" (TC {tc_rep:,.6f})"
        ws.cell(r, 1, ley).font = Font(size=9, color="64748B")
        r += 2

        headers = ["Cuenta", "Tipo / clase", "Descripción", "Saldo inicial", "Debe", "Haber", "Saldo final"]
        for col, h in enumerate(headers, start=1):
            c = ws.cell(r, col, h)
            c.font = head_font
            c.fill = head_fill
            c.alignment = Alignment(horizontal="center" if col > 3 else "left")
            c.border = border
        r += 1

        alt1 = PatternFill("solid", fgColor="F7FBFF")
        alt2 = PatternFill("solid", fgColor="EDF4FB")
        for idx, reg in enumerate(filtrada):
            tipo_txt = str(reg.get("tipo_clase") or "").strip()
            if not tipo_txt:
                try:
                    c = self.catalogo.obtener_cuenta(str(reg.get("num_cuenta", "")))
                    if c:
                        tipo_txt = etiqueta_tipo_cuenta_ui(c.get("tipo_cuenta"), str(reg.get("num_cuenta", "")))
                except Exception:
                    tipo_txt = "—"
            if not tipo_txt:
                tipo_txt = "—"
            fila = (
                reg.get("num_cuenta", ""),
                tipo_txt,
                reg.get("nombre_cuenta", ""),
                float(reg.get("saldo_inicial") or 0),
                float(reg.get("debe") or 0),
                float(reg.get("haber") or 0),
                float(reg.get("saldo_final") or 0),
            )
            fill = alt1 if idx % 2 == 0 else alt2
            for col, val in enumerate(fila, start=1):
                c = ws.cell(r, col, val)
                c.border = border
                c.fill = fill
                if col >= 4:
                    c.number_format = "#,##0.00"
                    c.alignment = Alignment(horizontal="right")
                else:
                    c.alignment = Alignment(horizontal="left")
            r += 1

        tot_si = sum(float(x.get("saldo_inicial") or 0) for x in filtrada)
        tot_d = sum(float(x.get("debe") or 0) for x in filtrada)
        tot_h = sum(float(x.get("haber") or 0) for x in filtrada)
        tot_sf = sum(float(x.get("saldo_final") or 0) for x in filtrada)
        tot_fill = PatternFill("solid", fgColor="DBEAFE")
        for col, val in enumerate(["TOTALES", "", "", tot_si, tot_d, tot_h, tot_sf], start=1):
            c = ws.cell(r, col, val)
            c.font = Font(bold=True)
            c.fill = tot_fill
            c.border = border
            if col >= 4:
                c.number_format = "#,##0.00"
                c.alignment = Alignment(horizontal="right")

        for col, w in enumerate([14, 18, 42, 16, 16, 16, 16], start=1):
            ws.column_dimensions[get_column_letter(col)].width = w

        try:
            wb.save(ruta)
            messagebox.showinfo("Balanza", f"Archivo guardado:\n{ruta}")
            self.set_status(f"Balanza exportada: {ruta}")
        except Exception as e:
            messagebox.showerror("Excel", f"No se pudo guardar:\n{e}")

    def cargar_excel_balanza(self):
        """Carga un archivo .xls/.xlsx de balanza y lo usa como fuente para la vista."""
        try:
            from tkinter import filedialog
            ruta = filedialog.askopenfilename(
                title="Seleccionar balanza de Excel",
                filetypes=[("Excel", "*.xls *.xlsx"), ("Todos", "*.*")]
            )
            if not ruta:
                return
            rows = self._cargar_balanza_excel(ruta)
            self._balanza_excel_rows = rows
            self._balanza_excel_ruta = ruta
            try:
                import os
                self._balanza_excel_mtime_loaded = os.path.getmtime(ruta)
            except Exception:
                self._balanza_excel_mtime_loaded = None
            self.balanza_fuente.set("Excel (BALANZA.xls)")
            self._balanza_rows_full = rows
            self.aplicar_filtros_balanza()
            self.set_status(f"Balanza Excel cargada: {len(rows)} cuentas")
        except Exception as e:
            messagebox.showerror("Error", f"No se pudo cargar Excel de balanza.\n{e}")

    def _parse_money(self, v) -> float:
        s = str(v or "").strip()
        if s in ("", "-", "—", "None", "none"):
            return 0.0

        # Quitar símbolos comunes de moneda
        s = s.replace("$", "").replace("MXN", "").replace("USD", "").strip()
        # Quitar espacios
        s = "".join(s.split())

        # Manejar formatos europeos (ej. 1.234,56) y decimales con coma (ej. 123,45)
        # Estrategia:
        # - Si hay '.' y ',' => '.' miles, ',' decimal => quitar '.' y cambiar ',' por '.'
        # - Si solo hay ',' => ',' decimal => cambiar ',' por '.'
        if "," in s and "." in s:
            s = s.replace(".", "").replace(",", ".")
        elif "," in s and "." not in s:
            s = s.replace(",", ".")
        else:
            # Si vienen separadores de miles con ',', nos queda un '.' decimal (o número entero)
            # Quitamos comas para no romper enteros como 1,000
            if "," in s:
                s = s.replace(",", "")

        try:
            return float(s)
        except Exception:
            return 0.0

    def _cargar_balanza_excel(self, ruta: str):
        """Lee BALANZA.xls y devuelve lista de dict compatible con balanza del sistema."""
        import xlrd
        wb = xlrd.open_workbook(ruta)
        sh = wb.sheet_by_index(0)
        rows = []

        # Detectar índices de columnas por nombre (si el excel trae encabezados)
        header = []
        try:
            header = [str(x).strip().lower() for x in sh.row_values(0)]
        except Exception:
            header = []

        def _find_idx(keywords):
            for idx, h in enumerate(header):
                hh = (h or "")
                if any(k in hh for k in keywords):
                    return idx
            return None

        idx_si = _find_idx(["saldo inicial", "saldo ini", "si", "inicial"]) if header else None
        idx_debe = _find_idx(["debe"]) if header else None
        idx_haber = _find_idx(["haber"]) if header else None
        idx_sf = _find_idx(["saldo final", "saldo fin", "sf", "final"]) if header else None
        idx_desc = _find_idx(["descrip", "nombre", "concepto"]) if header else None

        # Fallback a índices antiguos si no se encontró nada
        if idx_si is None:
            idx_si = 5
        if idx_debe is None:
            idx_debe = 6
        if idx_haber is None:
            idx_haber = 7
        if idx_sf is None:
            idx_sf = 8
        if idx_desc is None:
            idx_desc = 4

        import re
        cuenta_pat = re.compile(r"^\d{2,4}(\.\d{1,2})?$")

        for i in range(1, sh.nrows):
            r = sh.row_values(i)

            # Cuenta puede venir en cualquiera de las primeras columnas (COI/Balanza suele manejar esto).
            # Buscamos la primera celda con patrón de cuenta (ej. 604.10).
            cols_cta = [str(r[j]).strip() if j < len(r) else "" for j in range(min(8, len(r)))]
            num_cuenta = ""
            for cta in cols_cta:
                if cta and cta not in ("-", "—") and cuenta_pat.match(cta):
                    num_cuenta = cta
                    break
            if not num_cuenta:
                continue

            nombre = str(r[idx_desc]).strip() if idx_desc is not None and idx_desc < len(r) else ""
            si = self._parse_money(r[idx_si] if idx_si < len(r) else 0)
            debe = self._parse_money(r[idx_debe] if idx_debe < len(r) else 0)
            haber = self._parse_money(r[idx_haber] if idx_haber < len(r) else 0)
            sf = self._parse_money(r[idx_sf] if idx_sf < len(r) else 0)

            rows.append({
                "num_cuenta": num_cuenta,
                "nombre_cuenta": nombre,
                "saldo_inicial": si,
                "debe": debe,
                "haber": haber,
                "saldo_final": sf,
            })
        return rows

    def _match_filtro_contable_balanza(self, reg: dict, filtro_tipo: str) -> bool:
        cuenta = str(reg.get("num_cuenta", "")).upper()
        nombre = str(reg.get("nombre_cuenta", "")).upper()
        if filtro_tipo == "Clientes":
            return cuenta.startswith("115") or "CLIENTE" in nombre
        if filtro_tipo == "Bancos":
            return (
                cuenta.startswith("102")
                or cuenta.startswith("112")
                or "BANCO" in nombre
            )
        if filtro_tipo == "Costos":
            # En COI, "Costos" corresponde a cuentas de la familia 5xx/6xx (ej. 604.xx, 50x.xx).
            # Lo aproximamos por prefijo para filtrar.
            return cuenta.startswith("5") or cuenta.startswith("60")
        if filtro_tipo == "IVA acreditable":
            return "IVA" in nombre and ("ACREDITABLE" in nombre or "ACREDITAR" in nombre)
        if filtro_tipo == "IVA trasladado":
            return "IVA" in nombre and ("TRASLAD" in nombre or "COBRAD" in nombre or "NO COBR" in nombre or "POR PAGAR" in nombre)
        if filtro_tipo == "IVA (todos)":
            return "IVA" in nombre
        return True

    def _balanza_nivel_desglose(self) -> int:
        """1–5 agrupa por segmentos de cuenta; 99 = detalle sin agrupar."""
        cb = getattr(self, "balanza_nivel_combo", None)
        if not cb:
            return 99
        try:
            if not cb.winfo_exists():
                return 99
        except Exception:
            return 99
        s = (cb.get() or "").strip()
        if s.startswith("Detalle"):
            return 99
        if "Nivel 1" in s:
            return 1
        if "Nivel 2" in s:
            return 2
        if "Nivel 3" in s:
            return 3
        if "Nivel 4" in s:
            return 4
        if "Nivel 5" in s:
            return 5
        return 99

    def _balanza_rows_vista_agrupada(self):
        raw = list(getattr(self, "_balanza_rows_full", []) or [])
        n = self._balanza_nivel_desglose()
        if n >= 99:
            return raw
        return self.reportes.balanza_agrupar_nivel(raw, n)

    def _balanza_filtrar_rows(self, data):
        filtro_tipo = (self.balanza_filtro_tipo.get().strip() if getattr(self, "balanza_filtro_tipo", None) else "Todos")
        buscar = (self.balanza_buscar.get().strip().upper() if getattr(self, "balanza_buscar", None) else "")
        min_monto = self._parse_money(self.balanza_monto_min.get().strip()) if getattr(self, "balanza_monto_min", None) else 0.0
        max_txt = self.balanza_monto_max.get().strip() if getattr(self, "balanza_monto_max", None) else ""
        max_monto = self._parse_money(max_txt) if max_txt else None
        solo_mov = bool(self.balanza_solo_mov.get()) if getattr(self, "balanza_solo_mov", None) else False

        filtrada = []
        for reg in data:
            if not self._match_filtro_contable_balanza(reg, filtro_tipo):
                continue
            cuenta = str(reg.get("num_cuenta", "")).upper()
            nombre = str(reg.get("nombre_cuenta", "")).upper()
            if buscar and (buscar not in cuenta and buscar not in nombre):
                continue
            si = float(reg.get("saldo_inicial") or 0.0)
            debe = float(reg.get("debe") or 0.0)
            haber = float(reg.get("haber") or 0.0)
            sf = float(reg.get("saldo_final") or 0.0)
            if solo_mov and abs(debe) < 0.009 and abs(haber) < 0.009:
                continue
            amt = abs(sf)
            if amt < min_monto:
                continue
            if max_monto is not None and amt > max_monto:
                continue
            filtrada.append(reg)
        return filtrada

    def aplicar_filtros_balanza(self):
        """Aplica nivel de desglose, filtros por tipo contable, texto y monto."""
        for row in self.tree_balanza.get_children():
            self.tree_balanza.delete(row)

        data = self._balanza_rows_vista_agrupada()
        filtrada = self._balanza_filtrar_rows(data)

        total_si = total_debe = total_haber = total_sf = 0.0
        for idx, reg in enumerate(filtrada):
            tag = "par" if idx % 2 == 0 else "impar"
            tipo_txt = str(reg.get("tipo_clase") or "").strip()
            if not tipo_txt:
                try:
                    c = self.catalogo.obtener_cuenta(str(reg.get("num_cuenta", "")))
                    if c:
                        tipo_txt = etiqueta_tipo_cuenta_ui(c.get("tipo_cuenta"), str(reg.get("num_cuenta", "")))
                except Exception:
                    tipo_txt = "—"
            if not tipo_txt:
                tipo_txt = "—"
            self.tree_balanza.insert("", "end", values=(
                reg["num_cuenta"],
                tipo_txt,
                reg["nombre_cuenta"],
                f"${float(reg['saldo_inicial']):,.2f}",
                f"${float(reg['debe']):,.2f}",
                f"${float(reg['haber']):,.2f}",
                f"${float(reg['saldo_final']):,.2f}",
            ), tags=(tag,))
            total_si += float(reg["saldo_inicial"] or 0.0)
            total_debe += float(reg["debe"] or 0.0)
            total_haber += float(reg["haber"] or 0.0)
            total_sf += float(reg["saldo_final"] or 0.0)

        self.tree_balanza.insert("", "end", values=(
            "TOTALES", "", "",
            f"${total_si:,.2f}",
            f"${total_debe:,.2f}",
            f"${total_haber:,.2f}",
            f"${total_sf:,.2f}",
        ), tags=("total",))

        try:
            self.tree_balanza.tag_configure("par", background="#f7fbff")
            self.tree_balanza.tag_configure("impar", background="#edf4fb")
            self.tree_balanza.tag_configure("total", background="#dbeafe", foreground="#0f172a")
        except Exception:
            pass

        if hasattr(self, "lbl_totales_balanza") and self.lbl_totales_balanza.winfo_exists():
            self.lbl_totales_balanza.config(
                text=f"Totales: SI ${total_si:,.2f} | Debe ${total_debe:,.2f} | Haber ${total_haber:,.2f} | SF ${total_sf:,.2f}"
            )
        self.set_status(f"Balanza: {len(filtrada)} cuentas filtradas")
    
    # ==================== MÓDULO ESTADO RESULTADOS ====================
    
    def mostrar_resultados(self):
        if not self._requiere_permiso("reportes", "Estado de resultados"):
            return
        self._sincronizar_panel_lateral_modulo("Estado de resultados", "resultados")
        self.limpiar_area_trabajo()
        self.set_status("Estado de Resultados - Listo")
        
        main_frame = tk.Frame(self.area_trabajo, bg='white')
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        titulo_frame = tk.Frame(main_frame, bg='#000080')
        titulo_frame.pack(fill=tk.X)
        tk.Label(titulo_frame, text=f"ESTADO DE RESULTADOS - {self.empresa_actual}", 
                bg='#000080', fg='white', font=('Segoe UI', 9, 'bold'),
                anchor='w').pack(side=tk.LEFT, padx=5, pady=2)
        
        sel_frame = tk.Frame(main_frame, bg='#E0E0E0', relief=tk.SUNKEN, bd=1)
        sel_frame.pack(fill=tk.X, padx=5, pady=5)
        
        tk.Label(sel_frame, text="Mes:", bg='#E0E0E0').pack(side=tk.LEFT, padx=5)
        self.mes_res = ttk.Combobox(sel_frame, values=list(range(1,13)), width=5)
        self.mes_res.set(datetime.now().month)
        self.mes_res.pack(side=tk.LEFT, padx=2)
        
        tk.Label(sel_frame, text="Año:", bg='#E0E0E0').pack(side=tk.LEFT, padx=5)
        self.anio_res = tk.Entry(sel_frame, width=6)
        self.anio_res.insert(0, datetime.now().year)
        self.anio_res.pack(side=tk.LEFT, padx=2)
        tk.Label(sel_frame, text="Moneda:", bg='#E0E0E0').pack(side=tk.LEFT, padx=(12, 4))
        self.moneda_res = ttk.Combobox(sel_frame, values=self._valores_monedas_activas_catalogo(), width=8, state="readonly")
        self.moneda_res.set("MXN")
        self.moneda_res.pack(side=tk.LEFT, padx=2)
        tk.Label(sel_frame, text="TC:", bg='#E0E0E0').pack(side=tk.LEFT, padx=(8, 4))
        self.tc_res = tk.Entry(sel_frame, width=8)
        self.tc_res.insert(0, "1.0")
        self.tc_res.pack(side=tk.LEFT, padx=2)

        def _autofill_tc_resultados(_event=None):
            try:
                mon = (self.moneda_res.get() or "MXN").strip().upper()
                if mon == "MXN":
                    self.tc_res.delete(0, tk.END)
                    self.tc_res.insert(0, "1.0")
                    return
                mes = int(self.mes_res.get())
                anio = int(self.anio_res.get())
                f = f"{anio:04d}-{mes:02d}-{self.ultimo_dia_mes(mes, anio):02d}"
                v, _src = self._tipo_cambio_catalogo_por_iso_fecha(mon, f)
                if v and float(v) > 0:
                    self.tc_res.delete(0, tk.END)
                    self.tc_res.insert(0, f"{float(v):.6f}")
            except Exception:
                pass

        self.moneda_res.bind("<<ComboboxSelected>>", _autofill_tc_resultados)
        self.mes_res.bind("<<ComboboxSelected>>", _autofill_tc_resultados)
        self.anio_res.bind("<FocusOut>", _autofill_tc_resultados)

        # Centro de costo (opcional)
        try:
            from backend.modules.centros_costo import CentrosCosto
            _cc = CentrosCosto(db_path=self.polizas.db_path)
            _cc_items = _cc.listar_para_combo() or []
        except Exception:
            _cc_items = []
        self._res_cc_id_by_disp = {disp: int(_id) for _id, disp in _cc_items}
        tk.Label(sel_frame, text="Centro:", bg='#E0E0E0').pack(side=tk.LEFT, padx=(12, 4))
        self.res_centro = ttk.Combobox(sel_frame, values=["TODOS"] + [disp for _id, disp in _cc_items], width=26, state="readonly")
        self.res_centro.set("TODOS")
        self.res_centro.pack(side=tk.LEFT, padx=2)
        self.res_acumulado_ytd = tk.BooleanVar(value=False)
        tk.Checkbutton(
            sel_frame,
            text="Acumulado YTD (ene → mes)",
            variable=self.res_acumulado_ytd,
            command=self.mostrar_resultados_calculo,
            bg="#E0E0E0",
            fg=THEME["text_primary"],
            activebackground="#E0E0E0",
        ).pack(side=tk.LEFT, padx=(12, 4))
        
        tk.Button(sel_frame, text="Calcular", command=self.mostrar_resultados_calculo,
                 bg='#C0C0C0', relief=tk.RAISED, bd=2).pack(side=tk.LEFT, padx=10)
        
        self.res_frame = tk.Frame(main_frame, bg='white', relief=tk.SUNKEN, bd=2)
        self.res_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        
        try:
            _autofill_tc_resultados()
        except Exception:
            pass
        self.mostrar_resultados_calculo()
    
    def mostrar_resultados_calculo(self):
        if not hasattr(self, "res_frame") or not self.res_frame.winfo_exists():
            return
        for widget in self.res_frame.winfo_children():
            widget.destroy()
        
        try:
            mes = int(self.mes_res.get())
            anio = int(self.anio_res.get())
            moneda_rep = (self.moneda_res.get() if hasattr(self, "moneda_res") else "MXN") or "MXN"
            moneda_rep = moneda_rep.strip().upper()
            try:
                tc_rep = float((self.tc_res.get() if hasattr(self, "tc_res") else "1").replace(",", ""))
            except Exception:
                tc_rep = 1.0
            if tc_rep <= 0:
                tc_rep = 1.0

            cc_sel = (self.res_centro.get() if hasattr(self, "res_centro") else "TODOS") or "TODOS"
            cc_sel = cc_sel.strip()
            if cc_sel and cc_sel != "TODOS":
                from backend.modules.reportes_centros_costo import ReportesCentrosCosto
                rc = ReportesCentrosCosto(db_path=self.polizas.db_path)
                cc_id = int((getattr(self, "_res_cc_id_by_disp", {}) or {}).get(cc_sel))
                resultados = rc.estado_resultados_por_centro(mes, anio, cc_id)
                if moneda_rep != "MXN":
                    for _k in ("ventas", "costos", "utilidad_bruta", "gastos", "utilidad_operacion", "otros_ingresos", "otros_gastos", "utilidad_neta"):
                        if _k in resultados:
                            resultados[_k] = float(resultados.get(_k) or 0.0) / float(tc_rep or 1.0)
            else:
                from backend.modules.estados_financieros_motor import EstadosFinancierosMotor
                em = EstadosFinancierosMotor(db_path=self.polizas.db_path)
                acum = bool(getattr(self, "res_acumulado_ytd", None) and self.res_acumulado_ytd.get())
                if acum:
                    er = em.estado_resultados_acumulado(
                        mes, anio, moneda_reporte=moneda_rep, tipo_cambio=tc_rep, incluir_detalle_cuentas=False
                    )
                else:
                    er = em.estado_resultados_mensual(
                        mes, anio, moneda_reporte=moneda_rep, tipo_cambio=tc_rep, incluir_detalle_cuentas=False
                    )
                if er.get("exito"):
                    s = er.get("secciones") or {}
                    resultados = {
                        "ventas": float(s.get("ingresos") or 0),
                        "costos": float(s.get("costo_de_ventas") or 0),
                        "utilidad_bruta": float(s.get("utilidad_bruta") or 0),
                        "gastos": float(s.get("gastos_operativos") or 0),
                        "utilidad_operacion": float(s.get("utilidad_de_operacion") or 0),
                        "otros_ingresos": float(s.get("otros_ingresos") or 0),
                        "otros_gastos": float(s.get("otros_gastos") or 0),
                        "isr_ptu": float(s.get("isr_y_ptu") or 0),
                        "utilidad_antes_imp": float(s.get("utilidad_antes_de_isr_ptu") or 0),
                        "utilidad_neta": float(s.get("utilidad_neta") or 0),
                    }
                else:
                    resultados = self.reportes.estado_resultados(mes, anio, moneda_reporte=moneda_rep, tipo_cambio=tc_rep)
                    resultados.setdefault("isr_ptu", 0.0)
                    resultados.setdefault("utilidad_antes_imp", resultados.get("utilidad_operacion", 0))
            
            canvas = tk.Canvas(self.res_frame, bg='white')
            canvas.pack(fill=tk.BOTH, expand=True)
            
            y = 30
            canvas.create_text(50, y, text=f"ESTADO DE RESULTADOS", 
                              font=('Arial', 14, 'bold'), anchor='w', fill='#000080')
            y += 30
            acum_txt = bool(getattr(self, "res_acumulado_ytd", None) and self.res_acumulado_ytd.get())
            if acum_txt and (not cc_sel or cc_sel == "TODOS"):
                sub = f"Acumulado del 1/ene al {self.ultimo_dia_mes(mes, anio)} de {self.nombre_mes(mes)} de {anio}"
            else:
                sub = f"Del 1 al {self.ultimo_dia_mes(mes, anio)} de {self.nombre_mes(mes)} de {anio}"
            if cc_sel and cc_sel != "TODOS":
                sub += f" · Centro: {cc_sel}"
            sub += f" · Moneda: {moneda_rep}" + (f" (TC {tc_rep:,.4f})" if moneda_rep != "MXN" else "")
            canvas.create_text(50, y, text=sub,
                              font=('Arial', 10), anchor='w')
            y += 40
            
            canvas.create_text(50, y, text="Ventas:", font=('Arial', 10), anchor='w')
            canvas.create_text(400, y, text=f"${resultados['ventas']:,.2f}", 
                              font=('Arial', 10), anchor='e')
            y += 25
            
            canvas.create_text(50, y, text="Costo de Ventas:", font=('Arial', 10), anchor='w')
            canvas.create_text(400, y, text=f"${resultados['costos']:,.2f}", 
                              font=('Arial', 10), anchor='e')
            y += 25
            
            canvas.create_line(50, y, 450, y, fill='black')
            y += 25
            
            canvas.create_text(50, y, text="Utilidad Bruta:", font=('Arial', 10, 'bold'), anchor='w')
            canvas.create_text(400, y, text=f"${resultados['utilidad_bruta']:,.2f}", 
                              font=('Arial', 10, 'bold'), anchor='e')
            y += 30
            
            canvas.create_text(50, y, text="Gastos de Operación:", font=('Arial', 10), anchor='w')
            canvas.create_text(400, y, text=f"${resultados['gastos']:,.2f}", 
                              font=('Arial', 10), anchor='e')
            y += 25
            
            canvas.create_text(50, y, text="Utilidad de operación:", font=('Arial', 10, 'bold'), anchor='w')
            canvas.create_text(400, y, text=f"${resultados.get('utilidad_operacion', resultados['utilidad_neta']):,.2f}",
                              font=('Arial', 10, 'bold'), anchor='e')
            y += 28
            
            oi = float(resultados.get('otros_ingresos') or 0)
            og = float(resultados.get('otros_gastos') or 0)
            if abs(oi) > 0.009 or abs(og) > 0.009:
                canvas.create_text(50, y, text="Otros ingresos:", font=('Arial', 10), anchor='w')
                canvas.create_text(400, y, text=f"${oi:,.2f}", font=('Arial', 10), anchor='e')
                y += 22
                canvas.create_text(50, y, text="Otros gastos:", font=('Arial', 10), anchor='w')
                canvas.create_text(400, y, text=f"${og:,.2f}", font=('Arial', 10), anchor='e')
                y += 22
            
            uai = float(resultados.get('utilidad_antes_imp', resultados.get('utilidad_operacion', 0)) or 0)
            canvas.create_text(50, y, text="Utilidad antes de ISR/PTU:", font=('Arial', 10), anchor='w')
            canvas.create_text(400, y, text=f"${uai:,.2f}", font=('Arial', 10), anchor='e')
            y += 22
            
            isr = float(resultados.get('isr_ptu') or 0)
            canvas.create_text(50, y, text="ISR y PTU (periodo):", font=('Arial', 10), anchor='w')
            canvas.create_text(400, y, text=f"${isr:,.2f}", font=('Arial', 10), anchor='e')
            y += 25
            
            canvas.create_line(50, y, 450, y, fill='black', width=2)
            y += 30
            
            canvas.create_text(50, y, text="UTILIDAD NETA:", font=('Arial', 12, 'bold'), anchor='w')
            canvas.create_text(400, y, text=f"${resultados['utilidad_neta']:,.2f}", 
                              font=('Arial', 12, 'bold'), anchor='e', fill='#006400')
            
            self.set_status(f"Resultados calculados - Utilidad: ${resultados['utilidad_neta']:,.2f}")
            
        except Exception as e:
            canvas.create_text(50, 50, text=f"Error: {str(e)}", fill='red')
    
    # ==================== MÓDULO BALANCE GENERAL ====================
    
    def mostrar_balance(self):
        if not self._requiere_permiso("reportes", "Balance general"):
            return
        self._sincronizar_panel_lateral_modulo("Balance general", "balance")
        self.limpiar_area_trabajo()
        self.set_status("Balance General - Listo")
        
        main_frame = tk.Frame(self.area_trabajo, bg='white')
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        titulo_frame = tk.Frame(main_frame, bg='#000080')
        titulo_frame.pack(fill=tk.X)
        tk.Label(titulo_frame, text=f"BALANCE GENERAL - {self.empresa_actual}", 
                bg='#000080', fg='white', font=('Segoe UI', 9, 'bold'),
                anchor='w').pack(side=tk.LEFT, padx=5, pady=2)
        
        fecha_frame = tk.Frame(main_frame, bg='#E0E0E0', relief=tk.SUNKEN, bd=1)
        fecha_frame.pack(fill=tk.X, padx=5, pady=5)
        
        tk.Label(fecha_frame, text="Fecha:", bg='#E0E0E0').pack(side=tk.LEFT, padx=5)
        self.fecha_balance = tk.Entry(fecha_frame, width=12)
        self.fecha_balance.insert(0, datetime.now().strftime("%Y-%m-%d"))
        self.fecha_balance.pack(side=tk.LEFT, padx=2)
        tk.Label(fecha_frame, text="Moneda:", bg='#E0E0E0').pack(side=tk.LEFT, padx=(12, 4))
        self.moneda_balance = ttk.Combobox(
            fecha_frame, values=self._valores_monedas_activas_catalogo(), width=8, state="readonly"
        )
        self.moneda_balance.set("MXN")
        self.moneda_balance.pack(side=tk.LEFT, padx=2)
        tk.Label(fecha_frame, text="TC:", bg='#E0E0E0').pack(side=tk.LEFT, padx=(8, 4))
        self.tc_balance = tk.Entry(fecha_frame, width=8)
        self.tc_balance.insert(0, "1.0")
        self.tc_balance.pack(side=tk.LEFT, padx=2)

        def _autofill_tc_balance(_event=None):
            try:
                mon = (self.moneda_balance.get() or "MXN").strip().upper()
                if mon == "MXN":
                    self.tc_balance.delete(0, tk.END)
                    self.tc_balance.insert(0, "1.0")
                    return
                f = (self.fecha_balance.get() or "").strip()[:10]
                try:
                    datetime.strptime(f, "%Y-%m-%d")
                except Exception:
                    f = datetime.now().strftime("%Y-%m-%d")
                v, _src = self._tipo_cambio_catalogo_por_iso_fecha(mon, f)
                if v and float(v) > 0:
                    self.tc_balance.delete(0, tk.END)
                    self.tc_balance.insert(0, f"{float(v):.6f}")
            except Exception:
                pass

        self.moneda_balance.bind("<<ComboboxSelected>>", _autofill_tc_balance)
        self.fecha_balance.bind("<FocusOut>", _autofill_tc_balance)
        
        tk.Button(fecha_frame, text="Actualizar", command=self.mostrar_balance_calculo,
                 bg='#C0C0C0', relief=tk.RAISED, bd=2).pack(side=tk.LEFT, padx=10)
        
        self.balance_frame = tk.Frame(main_frame, bg='white', relief=tk.SUNKEN, bd=2)
        self.balance_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        
        try:
            _autofill_tc_balance()
        except Exception:
            pass
        self.mostrar_balance_calculo()
    
    def mostrar_balance_calculo(self):
        if not hasattr(self, "balance_frame") or not self.balance_frame.winfo_exists():
            return
        for widget in self.balance_frame.winfo_children():
            widget.destroy()
        
        try:
            moneda_rep = (self.moneda_balance.get() if hasattr(self, "moneda_balance") else "MXN") or "MXN"
            moneda_rep = moneda_rep.strip().upper()
            try:
                tc_rep = float((self.tc_balance.get() if hasattr(self, "tc_balance") else "1").replace(",", ""))
            except Exception:
                tc_rep = 1.0
            if tc_rep <= 0:
                tc_rep = 1.0
            balance = self.reportes.balance_general(self.fecha_balance.get(), moneda_reporte=moneda_rep, tipo_cambio=tc_rep)
            
            canvas = tk.Canvas(self.balance_frame, bg='white')
            canvas.pack(fill=tk.BOTH, expand=True)
            
            y = 30
            canvas.create_text(50, y, text=f"BALANCE GENERAL", 
                              font=('Arial', 14, 'bold'), anchor='w', fill='#000080')
            y += 30
            canvas.create_text(50, y, text=f"Al {self.fecha_balance.get()}",
                              font=('Arial', 10), anchor='w')
            y += 40
            canvas.create_text(50, y, text=f"Moneda: {moneda_rep}" + (f" (TC {tc_rep:,.4f})" if moneda_rep != "MXN" else ""),
                              font=('Arial', 10), anchor='w')
            y += 30
            
            canvas.create_text(50, y, text="ACTIVO", font=('Arial', 11, 'bold'), anchor='w')
            y += 25
            canvas.create_text(100, y, text="Total Activo:", font=('Arial', 10), anchor='w')
            canvas.create_text(400, y, text=f"${balance['activo']:,.2f}", 
                              font=('Arial', 10), anchor='e')
            y += 40
            
            canvas.create_text(50, y, text="PASIVO", font=('Arial', 11, 'bold'), anchor='w')
            y += 25
            canvas.create_text(100, y, text="Total Pasivo:", font=('Arial', 10), anchor='w')
            canvas.create_text(400, y, text=f"${balance['pasivo']:,.2f}", 
                              font=('Arial', 10), anchor='e')
            y += 40
            
            canvas.create_text(50, y, text="CAPITAL CONTABLE", font=('Arial', 11, 'bold'), anchor='w')
            y += 25
            canvas.create_text(100, y, text="Total Capital:", font=('Arial', 10), anchor='w')
            canvas.create_text(400, y, text=f"${balance['capital']:,.2f}", 
                              font=('Arial', 10), anchor='e')
            y += 30
            
            canvas.create_line(50, y, 450, y, fill='black')
            y += 30
            
            canvas.create_text(100, y, text="TOTAL PASIVO + CAPITAL:", font=('Arial', 10, 'bold'), anchor='w')
            canvas.create_text(400, y, text=f"${balance['total_pasivo_capital']:,.2f}", 
                              font=('Arial', 10, 'bold'), anchor='e')
            y += 40
            
            if abs(balance['activo'] - balance['total_pasivo_capital']) < 0.01:
                canvas.create_text(50, y, text="✓ BALANCE CUADRADO", 
                                  font=('Arial', 12, 'bold'), anchor='w', fill='green')
            else:
                diff = balance['activo'] - balance['total_pasivo_capital']
                canvas.create_text(50, y, text=f"✗ DIFERENCIA: ${diff:,.2f}", 
                                  font=('Arial', 12, 'bold'), anchor='w', fill='red')
            
            self.set_status(f"Balance generado - Activo: ${balance['activo']:,.2f}")
            
        except Exception as e:
            canvas.create_text(50, 50, text=f"Error: {str(e)}", fill='red')
    
    def mostrar_estados_financieros_motor(self):
        """Estados financieros completos: ER, balance, flujo, capital, comparativos, por centro, formatos y exportación."""
        if not self._requiere_permiso("reportes", "Estados financieros (motor completo)"):
            return
        try:
            from backend.modules.estados_financieros_motor import EstadosFinancierosMotor
            from backend.modules.export_estados_libros import export_docx_tabla, export_pdf_tabla, export_xlsx_tabla
        except Exception as ex:
            messagebox.showerror("Estados financieros", str(ex))
            return

        em = EstadosFinancierosMotor(db_path=self.polizas.db_path)
        cache = {"titulo": "", "headers": (), "filas": [], "subtitulo": ""}
        rfc_exp = (self._rfc_empresa_para_xml() or "").strip()

        d = tk.Toplevel(self.root)
        d.title("Estados financieros (motor completo)")
        d.transient(self.root)
        d.resizable(True, True)
        try:
            d.minsize(920, 560)
        except Exception:
            pass
        d.grid_rowconfigure(3, weight=1)
        d.grid_columnconfigure(0, weight=1)

        top = tk.Frame(d, padx=10, pady=8, bg=THEME["bg_content"])
        top.grid(row=0, column=0, sticky="ew")

        tipos = (
            "ER mensual",
            "ER acumulado (YTD)",
            "Balance general",
            "Flujo efectivo (indirecto)",
            "Cambios en el capital",
            "Comparativo — Estado de resultados",
            "Comparativo — Balance",
            "Comparativo — Flujo operación",
            "Comparativo — Capital",
            "Paquete por departamento (4 estados)",
        )
        tk.Label(top, text="Informe:", bg=THEME["bg_content"]).grid(row=0, column=0, sticky="w")
        tipo_cb = ttk.Combobox(top, values=tipos, width=42, state="readonly")
        tipo_cb.set(tipos[0])
        tipo_cb.grid(row=0, column=1, padx=4, sticky="w")

        tk.Label(top, text="Mes:", bg=THEME["bg_content"]).grid(row=0, column=2, padx=(12, 0))
        mes_e = ttk.Combobox(top, values=[f"{i:02d}" for i in range(1, 13)], width=4, state="readonly")
        mes_e.set(f"{datetime.now().month:02d}")
        mes_e.grid(row=0, column=3, padx=4)

        tk.Label(top, text="Año:", bg=THEME["bg_content"]).grid(row=0, column=4)
        anio_e = tk.Entry(top, width=7)
        anio_e.insert(0, str(datetime.now().year))
        anio_e.grid(row=0, column=5, padx=4)

        tk.Label(top, text="Mes / año ant. (comparativo):", bg=THEME["bg_content"]).grid(row=1, column=0, columnspan=2, sticky="e", pady=(6, 0))
        mes_ant = ttk.Combobox(top, values=[f"{i:02d}" for i in range(1, 13)], width=4, state="readonly")
        mes_ant.set(f"{max(1, datetime.now().month - 1):02d}")
        mes_ant.grid(row=1, column=2, padx=4, pady=(6, 0), sticky="w")
        anio_ant = tk.Entry(top, width=7)
        anio_ant.insert(0, str(datetime.now().year - 1))
        anio_ant.grid(row=1, column=3, padx=4, pady=(6, 0), sticky="w")

        tk.Label(top, text="Fecha corte BG (AAAA-MM-DD):", bg=THEME["bg_content"]).grid(row=1, column=4, columnspan=2, sticky="e", pady=(6, 0))
        fcorte = tk.Entry(top, width=12)
        fcorte.insert(0, datetime.now().strftime("%Y-%m-%d"))
        fcorte.grid(row=1, column=6, padx=4, pady=(6, 0), sticky="w")

        tk.Label(top, text="Flujo desde / hasta:", bg=THEME["bg_content"]).grid(row=2, column=0, sticky="w", pady=(6, 0))
        fi_fl = tk.Entry(top, width=12)
        fi_fl.insert(0, f"{datetime.now().year}-{datetime.now().month:02d}-01")
        fi_fl.grid(row=2, column=1, padx=4, pady=(6, 0), sticky="w")
        ff_fl = tk.Entry(top, width=12)
        ff_fl.insert(0, datetime.now().strftime("%Y-%m-%d"))
        ff_fl.grid(row=2, column=2, padx=4, pady=(6, 0), sticky="w")

        tk.Label(top, text="Moneda:", bg=THEME["bg_content"]).grid(row=2, column=3, pady=(6, 0))
        mon_cb = ttk.Combobox(top, values=self._valores_monedas_activas_catalogo(), width=8, state="readonly")
        mon_cb.set("MXN")
        mon_cb.grid(row=2, column=4, padx=4, pady=(6, 0))
        tk.Label(top, text="TC:", bg=THEME["bg_content"]).grid(row=2, column=5, pady=(6, 0))
        tc_e = tk.Entry(top, width=10)
        tc_e.insert(0, "1.0")
        tc_e.grid(row=2, column=6, padx=4, pady=(6, 0))

        try:
            from backend.modules.centros_costo import CentrosCosto
            _cci = CentrosCosto(db_path=self.polizas.db_path).listar_para_combo() or []
        except Exception:
            _cci = []
        cc_map = {disp: int(_id) for _id, disp in _cci}
        tk.Label(top, text="Departamento:", bg=THEME["bg_content"]).grid(row=2, column=7, padx=(12, 0), pady=(6, 0))
        cc_cb = ttk.Combobox(top, values=["TODOS"] + [d for _, d in _cci], width=28, state="readonly")
        cc_cb.set("TODOS")
        cc_cb.grid(row=2, column=8, padx=4, pady=(6, 0), sticky="w")

        fmt_row = tk.Frame(d, padx=10, pady=4, bg=THEME["bg_sidebar"])
        fmt_row.grid(row=1, column=0, sticky="ew")
        tk.Label(
            fmt_row,
            text="Formato guardado (solo ER):",
            bg=THEME["bg_sidebar"],
            fg=THEME["text_secondary"],
            font=(THEME["font_ui"], 8),
        ).pack(side=tk.LEFT)
        fmt_list = em.formato_listar("ER") or []
        fmt_disp = [f"{x.get('id')}: {x.get('nombre')}" for x in fmt_list]
        fmt_cb = ttk.Combobox(fmt_row, values=["(ninguno)"] + fmt_disp, width=36, state="readonly")
        fmt_cb.set("(ninguno)")
        fmt_cb.pack(side=tk.LEFT, padx=8)

        def _mon_tc():
            mon = (mon_cb.get() or "MXN").strip().upper()
            try:
                tc = float((tc_e.get() or "1").replace(",", ""))
            except Exception:
                tc = 1.0
            if tc <= 0:
                tc = 1.0
            return mon, tc

        def _centro():
            s = (cc_cb.get() or "TODOS").strip()
            if not s or s == "TODOS":
                return None
            return cc_map.get(s)

        def _fmt_cfg():
            sel = fmt_cb.get() or ""
            if sel.startswith("(ninguno)"):
                return None
            try:
                fid = int(sel.split(":", 1)[0].strip())
            except Exception:
                return None
            rec = em.formato_obtener(fid)
            return (rec or {}).get("config") if rec else None

        def _tree_clear(tree_w):
            for i in tree_w.get_children():
                tree_w.delete(i)

        cols_var = {"h": ("Concepto", "Importe"), "wide": ("Concepto", "Actual", "Anterior", "Variación", "Var. %")}

        tree = ttk.Treeview(d, columns=cols_var["h"], show="headings", height=18)
        tree.grid(row=3, column=0, sticky="nsew", padx=10, pady=4)
        sy = ttk.Scrollbar(d, orient=tk.VERTICAL, command=tree.yview)
        sy.grid(row=3, column=1, sticky="ns", pady=4)
        tree.configure(yscrollcommand=sy.set)

        def _config_cols(mode_simple: bool):
            _tree_clear(tree)
            if mode_simple:
                tree.configure(columns=cols_var["h"])
                for c, w in (("Concepto", 320), ("Importe", 140)):
                    tree.heading(c, text=c)
                    tree.column(c, width=w, anchor=("w" if c == "Concepto" else "e"))
            else:
                tree.configure(columns=cols_var["wide"])
                for c, w in (
                    ("Concepto", 220),
                    ("Actual", 100),
                    ("Anterior", 100),
                    ("Variación", 100),
                    ("Var. %", 72),
                ):
                    tree.heading(c, text=c)
                    tree.column(c, width=w, anchor=("w" if c == "Concepto" else "e"))

        _config_cols(True)

        def _set_cache(titulo, headers, filas, subtitulo=""):
            cache["titulo"] = titulo
            cache["headers"] = headers
            cache["filas"] = filas
            cache["subtitulo"] = subtitulo

        def generar():
            try:
                m = int(mes_e.get())
                y = int(anio_e.get().strip())
                ma = int(mes_ant.get())
                ya = int(anio_ant.get().strip())
            except Exception:
                messagebox.showerror("Estados", "Mes o año inválido.")
                return
            mon, tc = _mon_tc()
            cc = _centro()
            sel = tipo_cb.get() or ""
            cfg_fmt = _fmt_cfg()

            def _push_sec(sec: dict, titulo: str, sub=""):
                _config_cols(True)
                rows = []
                orden = list(sec.keys())
                if cfg_fmt and isinstance(cfg_fmt.get("orden_secciones"), list):
                    orden = [k for k in cfg_fmt["orden_secciones"] if k in sec] + [k for k in orden if k not in cfg_fmt["orden_secciones"]]
                etiquetas = (cfg_fmt or {}).get("etiquetas") or {}
                for k in orden:
                    if k not in sec:
                        continue
                    lab = etiquetas.get(k, k.replace("_", " ").title())
                    rows.append((lab, float(sec[k] or 0)))
                for lab, imp in rows:
                    tree.insert("", tk.END, values=(lab, f"{imp:,.2f}"))
                _set_cache(titulo, cols_var["h"], rows, sub)

            if sel == "ER mensual":
                r = em.estado_resultados_mensual(
                    m, y, moneda_reporte=mon, tipo_cambio=tc, centro_costo_id=cc, incluir_detalle_cuentas=False
                )
                if not r.get("exito"):
                    messagebox.showerror("Estados", r.get("error", "Error"))
                    return
                if cfg_fmt:
                    r = em.aplicar_formato_secciones(r, cfg_fmt)
                    sec = r.get("secciones_ordenadas") or r.get("secciones") or {}
                else:
                    sec = r.get("secciones") or {}
                _push_sec(sec, "Estado de resultados (mensual)", f"{r.get('fecha_inicio')} — {r.get('fecha_fin')}")
            elif sel == "ER acumulado (YTD)":
                r = em.estado_resultados_acumulado(
                    m, y, moneda_reporte=mon, tipo_cambio=tc, centro_costo_id=cc, incluir_detalle_cuentas=False
                )
                if not r.get("exito"):
                    messagebox.showerror("Estados", r.get("error", "Error"))
                    return
                if cfg_fmt:
                    r = em.aplicar_formato_secciones(r, cfg_fmt)
                    sec = r.get("secciones_ordenadas") or r.get("secciones") or {}
                else:
                    sec = r.get("secciones") or {}
                _push_sec(sec, "Estado de resultados (acumulado YTD)", f"{r.get('fecha_inicio')} — {r.get('fecha_fin')}")
            elif sel == "Balance general":
                fc = (fcorte.get() or "").strip()[:10]
                r = em.balance_general_detallado(fc, moneda_reporte=mon, tipo_cambio=tc, centro_costo_id=cc)
                if not r.get("exito"):
                    messagebox.showerror("Estados", r.get("error", "Error"))
                    return
                _config_cols(True)
                rows = [
                    ("Activo total", float(r.get("activo_total") or 0)),
                    ("Pasivo total", float(r.get("pasivo_total") or 0)),
                    ("Capital total", float(r.get("capital_total") or 0)),
                    ("Pasivo + Capital", float(r.get("pasivo_mas_capital") or 0)),
                    ("Diferencia (A − (P+C))", float(r.get("diferencia") or 0)),
                    ("Cuadra", "Sí" if r.get("cuadra") else "No"),
                ]
                for a, b in rows:
                    tree.insert("", tk.END, values=(a, b if isinstance(b, str) else f"{float(b):,.2f}"))
                _set_cache("Balance general", cols_var["h"], [(a, b if not isinstance(b, str) else 0.0) for a, b in rows[:5]], fc)
            elif sel == "Flujo efectivo (indirecto)":
                r = em.flujo_efectivo_indirecto(
                    fi_fl.get().strip()[:10], ff_fl.get().strip()[:10], moneda_reporte=mon, tipo_cambio=tc, centro_costo_id=cc
                )
                if not r.get("exito"):
                    messagebox.showerror("Estados", r.get("error", "Error"))
                    return
                _config_cols(True)
                rows = []
                for k, v in (r.get("actividades_operacion") or {}).items():
                    rows.append((k.replace("_", " ").title(), float(v or 0)))
                for k, v in (r.get("actividades_financiamiento") or {}).items():
                    rows.append((k.replace("_", " ").title(), float(v or 0)))
                for k, v in (r.get("reconciliacion_caja") or {}).items():
                    rows.append((k.replace("_", " ").title(), float(v or 0)))
                for lab, imp in rows:
                    tree.insert("", tk.END, values=(lab, f"{imp:,.2f}"))
                _set_cache("Flujo de efectivo (indirecto)", cols_var["h"], rows, f"{r.get('fecha_inicio')} — {r.get('fecha_fin')}")
            elif sel == "Cambios en el capital":
                r = em.cambios_capital_contable(y, 1, m, moneda_reporte=mon, tipo_cambio=tc, centro_costo_id=cc)
                if not r.get("exito"):
                    messagebox.showerror("Estados", r.get("error", "Error"))
                    return
                _config_cols(True)
                keys = (
                    ("capital_inicial", "Capital inicial"),
                    ("mas_aportaciones", "Aportaciones"),
                    ("menos_retiros", "Retiros"),
                    ("mas_resultado_del_periodo", "Resultado del periodo"),
                    ("capital_final_calculado", "Capital final (calculado)"),
                    ("capital_final_balance", "Capital final (balance)"),
                )
                rows = []
                for key, lab in keys:
                    if key in r:
                        rows.append((lab, float(r.get(key) or 0)))
                for lab, imp in rows:
                    tree.insert("", tk.END, values=(lab, f"{imp:,.2f}"))
                _set_cache("Cambios en el capital contable", cols_var["h"], rows, r.get("fecha_fin", ""))
            elif sel.startswith("Comparativo"):
                tipo_map = {
                    "Comparativo — Estado de resultados": "ER",
                    "Comparativo — Balance": "BALANCE",
                    "Comparativo — Flujo operación": "FLUJO",
                    "Comparativo — Capital": "CAPITAL",
                }
                tp = tipo_map.get(sel, "ER")
                r = em.estado_comparativo(
                    tp,
                    mes_actual=m,
                    anio_actual=y,
                    mes_anterior=ma,
                    anio_anterior=ya,
                    moneda_reporte=mon,
                    tipo_cambio=tc,
                    centro_costo_id=cc,
                )
                if not r.get("exito"):
                    messagebox.showerror("Estados", r.get("error", "Error"))
                    return
                _config_cols(False)
                filas = []
                for row in r.get("filas") or []:
                    c = row.get("concepto", "")
                    va = float(row.get("periodo_actual") or 0)
                    vb = float(row.get("periodo_anterior") or 0)
                    dv = float(row.get("variacion") or 0)
                    vp = float(row.get("variacion_pct") or 0)
                    tree.insert("", tk.END, values=(c, f"{va:,.2f}", f"{vb:,.2f}", f"{dv:,.2f}", f"{vp:,.1f}%"))
                    filas.append((c, va, vb, dv, vp))
                _set_cache(f"Comparativo {tp}", cols_var["wide"], filas, f"{r.get('periodo_actual') or ''} vs {r.get('periodo_anterior') or ''}")
            elif sel == "Paquete por departamento (4 estados)":
                if cc is None:
                    messagebox.showwarning("Estados", "Seleccione un departamento / centro de costo.")
                    return
                pk = em.estados_por_centro(cc, m, y, moneda_reporte=mon, tipo_cambio=tc)
                if not pk.get("exito"):
                    messagebox.showerror("Estados", "No se pudo generar el paquete.")
                    return
                _config_cols(True)
                bloques = [
                    ("ER mensual", (pk.get("estado_resultados_mensual") or {}).get("secciones") or {}),
                    ("ER acumulado", (pk.get("estado_resultados_acumulado") or {}).get("secciones") or {}),
                    ("Balance (totales)", {}),
                ]
                rows_out = []
                for tit, sec in bloques[:2]:
                    tree.insert("", tk.END, values=(f"—— {tit} ——", ""))
                    rows_out.append((f"—— {tit} ——", ""))
                    for k, v in (sec or {}).items():
                        lab = k.replace("_", " ").title()
                        tree.insert("", tk.END, values=(lab, f"{float(v or 0):,.2f}"))
                        rows_out.append((lab, float(v or 0)))
                bg = pk.get("balance_general") or {}
                tree.insert("", tk.END, values=("—— Balance ——", ""))
                rows_out.append(("—— Balance ——", ""))
                for lab, key in (
                    ("Activo", "activo_total"),
                    ("Pasivo", "pasivo_total"),
                    ("Capital", "capital_total"),
                ):
                    tree.insert("", tk.END, values=(lab, f"{float(bg.get(key) or 0):,.2f}"))
                    rows_out.append((lab, float(bg.get(key) or 0)))
                _set_cache("Paquete por departamento", cols_var["h"], [(a, b if isinstance(b, (int, float)) else 0) for a, b in rows_out], f"Centro {cc} · {m:02d}/{y}")
            else:
                messagebox.showinfo("Estados", "Seleccione un tipo de informe.")
                return
            self._set_tabla_activa(tree)
            self.set_status(f"Estados financieros: {cache['titulo']}")

        def _export(kind: str):
            if not cache["filas"]:
                messagebox.showwarning("Exportar", "Genere un informe primero.")
                return
            ext = {"pdf": ".pdf", "xlsx": ".xlsx", "docx": ".docx"}[kind]
            ruta = filedialog.asksaveasfilename(
                parent=d,
                defaultextension=ext,
                initialfile=f"{cache['titulo'].replace(' ', '_')[:40]}{ext}",
                filetypes=[(kind.upper(), f"*{ext}")],
            )
            if not ruta:
                return
            headers = cache["headers"]
            filas = cache["filas"]
            tit = cache["titulo"]
            sub = cache["subtitulo"]
            emp = self.empresa_actual or ""
            if kind == "pdf":
                r = export_pdf_tabla(tit, filas, headers, ruta, empresa=emp, subtitulo=sub, rfc_empresa=rfc_exp)
            elif kind == "xlsx":
                r = export_xlsx_tabla(tit, filas, headers, ruta, empresa=emp, rfc_empresa=rfc_exp)
            else:
                r = export_docx_tabla(tit, filas, headers, ruta, empresa=emp, rfc_empresa=rfc_exp)
            if r.get("exito"):
                messagebox.showinfo("Exportar", f"Guardado:\n{r.get('ruta')}")
            else:
                messagebox.showerror("Exportar", r.get("error", "Error"))

        def guardar_formato_er():
            nombre = simpledialog.askstring("Formato ER", "Nombre del formato:", parent=d)
            if not (nombre or "").strip():
                return
            r = em.estado_resultados_mensual(
                int(mes_e.get()), int(anio_e.get().strip()), moneda_reporte=_mon_tc()[0], tipo_cambio=_mon_tc()[1], centro_costo_id=_centro(), incluir_detalle_cuentas=False
            )
            if not r.get("exito"):
                messagebox.showerror("Formato", r.get("error", "Genere un ER válido primero."))
                return
            sec = r.get("secciones") or {}
            cfg = {"orden_secciones": list(sec.keys()), "etiquetas": {}}
            rv = em.formato_guardar(nombre.strip(), "ER", cfg)
            if rv.get("exito"):
                messagebox.showinfo("Formato", "Formato guardado. Vuelva a abrir el combo para verlo.")
                nlist = em.formato_listar("ER") or []
                fmt_cb.configure(values=["(ninguno)"] + [f"{x.get('id')}: {x.get('nombre')}" for x in nlist])
            else:
                messagebox.showerror("Formato", rv.get("error", "No se pudo guardar."))

        bf = tk.Frame(d, padx=10, pady=6, bg=THEME["bg_content"])
        bf.grid(row=4, column=0, columnspan=2, sticky="ew")
        tk.Button(bf, text="Generar", command=generar, bg=THEME["btn_primary_bg"], fg=THEME["btn_primary_fg"], relief=tk.FLAT, padx=12).pack(side=tk.LEFT)
        tk.Button(bf, text="Guardar formato ER", command=guardar_formato_er, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=8).pack(side=tk.LEFT, padx=6)
        tk.Button(bf, text="PDF", command=lambda: _export("pdf"), bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=8).pack(side=tk.LEFT, padx=4)
        tk.Button(bf, text="Excel", command=lambda: _export("xlsx"), bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=8).pack(side=tk.LEFT, padx=2)
        tk.Button(bf, text="Word", command=lambda: _export("docx"), bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=8).pack(side=tk.LEFT, padx=2)
        tk.Button(bf, text="Cerrar", command=d.destroy).pack(side=tk.RIGHT)

        lbl_info = tk.Label(
            d,
            text="Incluye: ER mensual/acumulado (4xx–6xx, utilidad bruta, operación, ISR, neta), balance 1xx–3xx con cuadre, "
            "flujo indirecto, cambios en capital, comparativos año vs año, paquete por centro y formatos ER reutilizables. "
            "PDF/Excel/Word usan nombre de empresa y RFC (Datos de empresa → timbrado).",
            bg=THEME["bg_sidebar"],
            fg=THEME["text_secondary"],
            font=(THEME["font_ui"], 8),
            wraplength=880,
            justify=tk.LEFT,
        )
        lbl_info.grid(row=5, column=0, columnspan=2, sticky="ew", padx=10, pady=(0, 6))

        self._fit_toplevel(d, 0.9, 0.82, 1000, 640)
        generar()

