        def _listar_certificados_csd():
            """Lista archivos .cer y .key en la carpeta csd del proyecto."""
            raiz = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
            csd_dir = os.path.join(raiz, "csd")
            resultado = []
            if not os.path.isdir(csd_dir):
                return resultado
            for root_dir, _, files in os.walk(csd_dir):
                for f in files:
                    low = f.lower()
                    full = os.path.join(root_dir, f)
                    if low.endswith(".cer"):
                        resultado.append({"nombre": f, "ruta": full, "tipo": "cer"})
                    elif low.endswith(".key"):
                        resultado.append({"nombre": f, "ruta": full, "tipo": "key"})
            return resultado

        # Sección Clientes (catálogo local; en Finkok los RFC se administran en el portal)
        frame_clientes = tk.LabelFrame(cert_wrap, text="Clientes (catálogo local)", bg='white')
        frame_clientes.pack(fill=tk.BOTH, expand=True, pady=(12, 6))
        frame_tree_clientes = tk.Frame(frame_clientes, bg='white')
        frame_tree_clientes.pack(fill=tk.BOTH, expand=True, padx=6, pady=(6, 2))
        cols_clientes = ("RFC", "Nombre")
        tree_clientes_cert = ttk.Treeview(frame_tree_clientes, columns=cols_clientes, show="headings", height=6)
        for c in cols_clientes:
            tree_clientes_cert.heading(c, text=c)
            tree_clientes_cert.column(c, width=140 if c == "RFC" else 280)
        tree_clientes_cert.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        sb_clientes = tk.Scrollbar(frame_tree_clientes, orient=tk.VERTICAL, command=tree_clientes_cert.yview)
        sb_clientes.pack(side=tk.RIGHT, fill=tk.Y)
        tree_clientes_cert.configure(yscrollcommand=sb_clientes.set)

        def _refrescar_clientes_cert():
            for iid in tree_clientes_cert.get_children():
                tree_clientes_cert.delete(iid)
            try:
                from backend.models.clientes import CatalogoClientes
                combo_data = CatalogoClientes().listar_para_combo()
                for rfc, disp in combo_data:
                    nombre = disp.split(" - ", 1)[1].strip() if " - " in disp else disp
                    tree_clientes_cert.insert("", tk.END, values=(rfc, nombre))
            except Exception:
                pass

        def _abrir_detalle_cliente():
            sel = tree_clientes_cert.selection()
            if not sel:
                messagebox.showinfo("Detalle", "Seleccione un cliente de la lista.")
                return
            item = tree_clientes_cert.item(sel[0], "values")
            if len(item) < 2:
                return
            rfc_cli = (item[0] or "").strip()
            nombre_cli = (item[1] or "").strip()
            if not rfc_cli:
                messagebox.showinfo("Detalle", "RFC del cliente no disponible.")
                return
            import xml.etree.ElementTree as ET
            from datetime import datetime as dt
            raiz_proy = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
            folder = os.path.join(raiz_proy, "facturas_timbradas")
            csd_dir = os.path.join(raiz_proy, "csd")

            def _find_el(parent, contains):
                for el in parent.iter():
                    if el.tag and contains in el.tag:
                        return el
                return None

            # Recolectar facturas/XML de este cliente (receptor)
            filas = []
            if os.path.isdir(folder):
                for fname in os.listdir(folder):
                    if not fname.lower().endswith(".xml"):
                        continue
                    path = os.path.join(folder, fname)
                    try:
                        with open(path, "r", encoding="utf-8") as fp:
                            xml_str = fp.read()
                        root = ET.fromstring(xml_str)
                        comp = _find_el(root, "Comprobante") or root
                        re = _find_el(comp, "Receptor")
                        if re is None:
                            continue
                        rfc_rep = (re.get("Rfc") or re.get("RFC") or "").strip()
                        if rfc_rep.upper() != rfc_cli.upper():
                            continue
                        tfd = _find_el(comp, "TimbreFiscalDigital") or _find_el(root, "TimbreFiscalDigital")
                        folio = (comp.get("Folio") or "")[:20]
                        fecha_str = (comp.get("Fecha") or "")[:19].replace("T", " ")
                        total = (comp.get("Total") or "0").strip()
                        uuid_val = (tfd.get("UUID") or "").strip() if tfd is not None else ""
                        nom_rep = (re.get("Nombre") or "")[:50]
                        # Para filtro por semana/mes/año
                        fecha_dt = None
                        try:
                            if len(fecha_str) >= 10:
                                fecha_dt = dt.strptime(fecha_str[:10], "%Y-%m-%d")
                        except Exception:
                            pass
                        pdf_path = os.path.join(folder, f"Factura_{uuid_val[:36]}.pdf") if uuid_val else None
                        tiene_pdf = pdf_path and os.path.isfile(pdf_path)
                        filas.append({
                            "archivo": fname, "ruta": path, "folio": folio, "fecha": fecha_str,
                            "uuid": uuid_val, "total": total, "nombre_receptor": nom_rep,
                            "fecha_dt": fecha_dt, "pdf_ruta": pdf_path if tiene_pdf else None, "tiene_pdf": tiene_pdf
                        })
                    except Exception:
                        continue

            # Certificados y llaves de este cliente (ruta o nombre contienen el RFC)
            rfc_upper = rfc_cli.upper()
            todos_certs = _listar_certificados_csd()
            certs_cli = [c for c in todos_certs if rfc_upper in (c.get("ruta") or "").upper() or rfc_upper in (c.get("nombre") or "").upper()]

            # Ventana Detalle (grande, con scroll)
            win = tk.Toplevel(ventana)
            win.title(f"Detalle – {rfc_cli} – {nombre_cli}")
            win.resizable(True, True)
            win.configure(bg='white')

            canvas_det = tk.Canvas(win, bg='white', highlightthickness=0)
            sb_det = tk.Scrollbar(win, orient=tk.VERTICAL, command=canvas_det.yview)
            canvas_det.configure(yscrollcommand=sb_det.set)
            canvas_det.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
            sb_det.pack(side=tk.RIGHT, fill=tk.Y)
            cont_det = tk.Frame(canvas_det, bg='white')
            cont_window_det = canvas_det.create_window((0, 0), window=cont_det, anchor='nw')
            def _config_det_scroll(event=None):
                canvas_det.update_idletasks()
                canvas_det.config(scrollregion=canvas_det.bbox("all"))
            cont_det.bind("<Configure>", _config_det_scroll)
            def _sync_det_width(event=None):
                try:
                    canvas_det.itemconfigure(cont_window_det, width=canvas_det.winfo_width())
                except Exception:
                    pass
            canvas_det.bind("<Configure>", _sync_det_width)
            def _scroll_det(event):
                try:
                    if event.delta:
                        canvas_det.yview_scroll(int(-1 * (event.delta / 120)), "units")
                    else:
                        canvas_det.yview_scroll(-1 if event.num == 4 else 1, "units")
                except Exception:
                    pass
            canvas_det.bind("<MouseWheel>", _scroll_det)
            canvas_det.bind("<Button-4>", _scroll_det)
            canvas_det.bind("<Button-5>", _scroll_det)
            win.bind("<MouseWheel>", _scroll_det)

            tk.Label(cont_det, text=f"Cliente: {nombre_cli}  |  RFC: {rfc_cli}", font=('Arial', 11, 'bold'), bg='white').pack(pady=(10, 4))
            tk.Label(cont_det, text="Certificados, timbres y facturas de este cliente (Finkok)", font=('Arial', 9), bg='white', fg='gray').pack(pady=(0, 10))

            # --- Resumen de timbres + filtro por semana / mes / año ---
            frame_timbres = tk.LabelFrame(cont_det, text="Resumen de timbres (facturas timbradas)", bg='white')
            frame_timbres.pack(fill=tk.X, padx=12, pady=6)
            f_timbres_top = tk.Frame(frame_timbres, bg='white')
            f_timbres_top.pack(fill=tk.X, padx=8, pady=6)
            total_timbres = len(filas)
            lbl_total = tk.Label(f_timbres_top, text=f"Total: {total_timbres} timbre(s)", font=('Arial', 10, 'bold'), bg='white')
            lbl_total.pack(side=tk.LEFT)
            tk.Label(f_timbres_top, text="  Ver por:", bg='white').pack(side=tk.LEFT, padx=(20, 4))
            tree_timbres = ttk.Treeview(frame_timbres, columns=("Periodo", "Cantidad"), show="headings", height=4)
            tree_timbres.heading("Periodo", text="Período")
            tree_timbres.heading("Cantidad", text="Timbres")
            tree_timbres.column("Periodo", width=220)
            tree_timbres.column("Cantidad", width=80)
            tree_timbres.pack(fill=tk.X, padx=8, pady=(0, 8))

            def _actualizar_timbres_por(por):
                for iid in tree_timbres.get_children():
                    tree_timbres.delete(iid)
                if not filas:
                    tree_timbres.insert("", tk.END, values=("Sin facturas", "0"))
                    return
                agrupa = {}
                orden = []
                for r in filas:
                    fd = r.get("fecha_dt")
                    if fd is None:
                        k = "Sin fecha"
                        orden_key = (0, 0)
                    elif por == "semana":
                        año, sem, _ = fd.isocalendar()
                        k = f"{año}-S{sem:02d}"
                        orden_key = (año, sem)
                    elif por == "mes":
                        meses_es = ("Ene","Feb","Mar","Abr","May","Jun","Jul","Ago","Sep","Oct","Nov","Dic")
                        m = fd.month - 1
                        k = f"{meses_es[m]} {fd.year}"
                        orden_key = (fd.year, fd.month)
                    else:
                        k = str(fd.year)
                        orden_key = (fd.year, 0)
                    if k not in agrupa:
                        agrupa[k] = {"count": 0, "orden": orden_key}
                    agrupa[k]["count"] += 1
                entradas = [(agrupa[k]["orden"], k, agrupa[k]["count"]) for k in agrupa]
                entradas.sort(key=lambda x: x[0], reverse=True)
                for _, k, cnt in entradas:
                    tree_timbres.insert("", tk.END, values=(k, str(cnt)))

            tk.Button(f_timbres_top, text="Por semana", command=lambda: _actualizar_timbres_por("semana"), bg='#E0E7FF', fg='#3730A3', relief=tk.FLAT, padx=8, pady=2, cursor='hand2').pack(side=tk.LEFT, padx=2)
            tk.Button(f_timbres_top, text="Por mes", command=lambda: _actualizar_timbres_por("mes"), bg='#E0E7FF', fg='#3730A3', relief=tk.FLAT, padx=8, pady=2, cursor='hand2').pack(side=tk.LEFT, padx=2)
            tk.Button(f_timbres_top, text="Por año", command=lambda: _actualizar_timbres_por("año"), bg='#E0E7FF', fg='#3730A3', relief=tk.FLAT, padx=8, pady=2, cursor='hand2').pack(side=tk.LEFT, padx=2)
            _actualizar_timbres_por("año")

            # --- Certificados y llaves de este cliente ---
            frame_certs_det = tk.LabelFrame(cont_det, text="Certificados y llaves (.cer / .key) de este cliente (carpeta csd)", bg='white')
            frame_certs_det.pack(fill=tk.BOTH, expand=True, padx=12, pady=6)
            cols_cert = ("Archivo", "Tipo", "Ruta")
            tree_certs_det = ttk.Treeview(frame_certs_det, columns=cols_cert, show="headings", height=5)
            for col in cols_cert:
                tree_certs_det.heading(col, text=col)
                tree_certs_det.column(col, width=180 if col == "Archivo" else 50 if col == "Tipo" else 380)
            tree_certs_det.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=6, pady=6)
            sb_cert_det = tk.Scrollbar(frame_certs_det, orient=tk.VERTICAL, command=tree_certs_det.yview)
            sb_cert_det.pack(side=tk.RIGHT, fill=tk.Y, pady=6)
            tree_certs_det.configure(yscrollcommand=sb_cert_det.set)
            for c in certs_cli:
                tree_certs_det.insert("", tk.END, values=(c["nombre"], c["tipo"], c["ruta"]))
            if not certs_cli:
                tree_certs_det.insert("", tk.END, values=("(Ningún .cer/.key con este RFC en nombre o ruta)", "", ""))
            f_btns_cert_det = tk.Frame(frame_certs_det, bg='white')
            f_btns_cert_det.pack(pady=(0, 6))
            def _abrir_cert_det():
                sel = tree_certs_det.selection()
                if not sel or not certs_cli:
                    return
                idx = tree_certs_det.index(sel[0])
                if 0 <= idx < len(certs_cli):
                    ruta = certs_cli[idx]["ruta"]
                    if os.path.isfile(ruta):
                        os.startfile(ruta)
            def _abrir_carpeta_csd_det():
                if os.path.isdir(csd_dir):
                    os.startfile(csd_dir)
            tk.Button(f_btns_cert_det, text="Abrir archivo seleccionado", command=_abrir_cert_det, bg='#D1FAE5', fg='#065F46', relief=tk.FLAT, padx=8, pady=4, cursor='hand2').pack(side=tk.LEFT, padx=4)
            tk.Button(f_btns_cert_det, text="Abrir carpeta csd", command=_abrir_carpeta_csd_det, bg='#E3F2FD', fg='#1565C0', relief=tk.FLAT, padx=8, pady=4, cursor='hand2').pack(side=tk.LEFT, padx=4)

            # --- Facturas / XML y PDF ---
            frame_fact_det = tk.LabelFrame(cont_det, text="Facturas / XML y PDF (receptor RFC: " + rfc_cli + ")", bg='white')
            frame_fact_det.pack(fill=tk.BOTH, expand=True, padx=12, pady=6)
            cols_det = ("Archivo", "Folio", "Fecha", "UUID", "Total", "PDF", "Nombre receptor")
            tree_det = ttk.Treeview(frame_fact_det, columns=cols_det, show="headings", height=10)
            for c in cols_det:
                tree_det.heading(c, text=c)
                w = 100 if c in ("Archivo", "Folio", "Fecha") else 60 if c == "PDF" else 70 if c == "Total" else 120 if c == "Nombre receptor" else 260
                tree_det.column(c, width=w)
            tree_det.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=6, pady=6)
            sb_fact_det = tk.Scrollbar(frame_fact_det, orient=tk.VERTICAL, command=tree_det.yview)
            sb_fact_det.pack(side=tk.RIGHT, fill=tk.Y, pady=6)
            tree_det.configure(yscrollcommand=sb_fact_det.set)
            for r in filas:
                pdf_txt = "Sí" if r.get("tiene_pdf") else "No"
                tree_det.insert("", tk.END, values=(r["archivo"], r["folio"], r["fecha"], r["uuid"], r["total"], pdf_txt, r["nombre_receptor"]))
            if not filas:
                tree_det.insert("", tk.END, values=("No se encontraron facturas para este cliente.", "", "", "", "", "", ""))
            f_btns_det = tk.Frame(frame_fact_det, bg='white')
            f_btns_det.pack(pady=(0, 8))
            def _abrir_xml_seleccionado():
                s = tree_det.selection()
                if not s or not filas:
                    messagebox.showinfo("Abrir", "Seleccione una fila de la tabla.")
                    return
                idx = tree_det.index(s[0])
                if 0 <= idx < len(filas):
                    path_abrir = filas[idx]["ruta"]
                    if os.path.isfile(path_abrir):
                        os.startfile(path_abrir)
            def _abrir_pdf_seleccionado():
                s = tree_det.selection()
                if not s or not filas:
                    messagebox.showinfo("Abrir PDF", "Seleccione una factura que tenga PDF.")
                    return
                idx = tree_det.index(s[0])
                if 0 <= idx < len(filas) and filas[idx].get("pdf_ruta") and os.path.isfile(filas[idx]["pdf_ruta"]):
                    os.startfile(filas[idx]["pdf_ruta"])
                else:
                    messagebox.showinfo("Abrir PDF", "No hay PDF generado para esta factura.")
            def _abrir_carpeta_det():
                if os.path.isdir(folder):
                    os.startfile(folder)
            def _contabilizar_no_contabilizadas():
                try:
                    from backend.modules.contabilizar_xml import contabilizar_carpeta
                    resultados = contabilizar_carpeta(folder)
                    creadas = sum(1 for r in resultados if r.get("exito") and "Ya estaba" not in (r.get("mensaje") or ""))
                    ya_eran = sum(1 for r in resultados if r.get("exito") and "Ya estaba" in (r.get("mensaje") or ""))
                    errores = sum(1 for r in resultados if not r.get("exito"))
                    messagebox.showinfo("Contabilizar", f"Nuevas contabilizadas: {creadas}\nYa contabilizadas: {ya_eran}\nErrores: {errores}")
                    if creadas > 0 and hasattr(self, "actualizar_catalogo"):
                        try:
                            self.actualizar_catalogo()
                        except Exception:
                            pass
                except Exception as ex:
                    messagebox.showerror("Error", str(ex))
            tk.Button(f_btns_det, text="Abrir XML seleccionado", command=_abrir_xml_seleccionado, bg='#2563eb', fg='white', relief=tk.FLAT, padx=10, pady=4, cursor='hand2').pack(side=tk.LEFT, padx=4)
            tk.Button(f_btns_det, text="Abrir PDF seleccionado", command=_abrir_pdf_seleccionado, bg='#22c55e', fg='white', relief=tk.FLAT, padx=10, pady=4, cursor='hand2').pack(side=tk.LEFT, padx=4)
            tk.Button(f_btns_det, text="Abrir carpeta facturas timbradas", command=_abrir_carpeta_det, bg='#E3F2FD', fg='#1565C0', relief=tk.FLAT, padx=10, pady=4, cursor='hand2').pack(side=tk.LEFT, padx=4)
            tk.Button(f_btns_det, text="Contabilizar facturas no contabilizadas", command=_contabilizar_no_contabilizadas, bg='#D1FAE5', fg='#065F46', relief=tk.FLAT, padx=10, pady=4, cursor='hand2').pack(side=tk.LEFT, padx=4)

            tk.Frame(cont_det, height=20, bg='white').pack(fill=tk.X)
            self._fit_toplevel(win, 0.78, 0.76, 640, 480)

        f_btns_clientes = tk.Frame(frame_clientes, bg='white')
        f_btns_clientes.pack(pady=(0, 6))
        btn_actualizar_clientes = tk.Button(f_btns_clientes, text="Actualizar", command=_refrescar_clientes_cert, bg='#E2E8F0', relief=tk.FLAT, padx=10, pady=4, cursor='hand2')
        btn_actualizar_clientes.pack(side=tk.LEFT, padx=4)
        tk.Button(f_btns_clientes, text="Detalle", command=_abrir_detalle_cliente, bg='#DBEAFE', fg='#1D4ED8', relief=tk.FLAT, padx=10, pady=4, cursor='hand2').pack(side=tk.LEFT, padx=4)
        _refrescar_clientes_cert()

        # (Certificados por cliente se ven en Detalle; tabla global eliminada para no duplicar.)

        # ===== PESTAÑA 4: FACTURA REAL (timbrar con cliente y conceptos) =====
        tab_real = tk.Frame(notebook, bg='white')
        notebook.add(tab_real, text="Factura")
        # Scroll vertical (para poder ver todo lo de abajo) + contenido ancho
        canvas_factura = tk.Canvas(tab_real, bg='white', highlightthickness=0)
        sb_factura = tk.Scrollbar(tab_real, orient=tk.VERTICAL, command=canvas_factura.yview)
        canvas_factura.configure(yscrollcommand=sb_factura.set)
        canvas_factura.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        sb_factura.pack(side=tk.RIGHT, fill=tk.Y)

        contenedor_factura = tk.Frame(canvas_factura, bg='white')
        contenedor_window = canvas_factura.create_window((0, 0), window=contenedor_factura, anchor='nw')

        def _config_scroll_region(event=None):
            canvas_factura.update_idletasks()
            canvas_factura.config(scrollregion=canvas_factura.bbox("all"))

        def _sync_width(event=None):
            # Mantener el frame del mismo ancho que el canvas (para que no se "encojan" widgets)
            try:
                canvas_factura.itemconfigure(contenedor_window, width=canvas_factura.winfo_width())
            except Exception:
                pass

        contenedor_factura.bind("<Configure>", _config_scroll_region)
        canvas_factura.bind("<Configure>", _sync_width)

        def _scroll_factura(event):
            try:
                if event.delta:
                    canvas_factura.yview_scroll(int(-1 * (event.delta / 120)), "units")
                else:
                    # Linux
                    canvas_factura.yview_scroll(-1 if event.num == 4 else 1, "units")
            except Exception:
                pass

        # Scroll con rueda: que funcione en TODA la pestaña (no solo sobre el canvas)
        def _bind_wheel(_e=None):
            tab_real.bind_all("<MouseWheel>", _scroll_factura)
            tab_real.bind_all("<Button-4>", _scroll_factura)
            tab_real.bind_all("<Button-5>", _scroll_factura)
        def _unbind_wheel(_e=None):
            try:
                tab_real.unbind_all("<MouseWheel>")
                tab_real.unbind_all("<Button-4>")
                tab_real.unbind_all("<Button-5>")
            except Exception:
                pass
        tab_real.bind("<Enter>", _bind_wheel)
        tab_real.bind("<Leave>", _unbind_wheel)
        tk.Label(contenedor_factura, text="Generar y timbrar factura real (receptor y conceptos)",
                font=('Arial', 12, 'bold'), bg='white').pack(pady=8)
        tk.Label(contenedor_factura, text="El timbre lo genera el PAC al timbrar; no se desarrolla aparte en la app.",
                font=('Arial', 9), bg='white', fg='gray').pack()
        # Ayuda compacta (se puede ocultar)
        frame_ayuda = tk.Frame(contenedor_factura, bg='#F0F9FF', relief=tk.GROOVE, bd=1)
        frame_ayuda.pack(pady=6, padx=20, fill=tk.X)
        txt_ayuda = "Tip: Selecciona cliente → agrega 1 concepto → TIMBRAR. Luego: Descargar XML timbrado / Vista previa y PDF."
        tk.Label(frame_ayuda, text=txt_ayuda, font=('Arial', 8), bg='#F0F9FF', fg='#1e3a5f', justify=tk.LEFT).pack(anchor='w', padx=8, pady=4)
        tk.Button(frame_ayuda, text="Ocultar", command=frame_ayuda.pack_forget, bg='#E0E0E0', relief=tk.FLAT, padx=10, pady=2, cursor='hand2').pack(anchor='e', padx=8, pady=(0,4))
        try:
            from backend.models.clientes import CatalogoClientes
            clientes_combo_real = CatalogoClientes().listar_para_combo()
            valores_real = [disp for _r, disp in clientes_combo_real]
        except Exception:
            clientes_combo_real = []
            valores_real = []
        frame_receptor = tk.Frame(contenedor_factura, bg='white', relief=tk.SUNKEN, bd=1)
        frame_receptor.pack(pady=10, padx=20, fill=tk.X)
        tk.Label(frame_receptor, text="Receptor (cliente): cliente al que se le emite la factura.", font=('Arial', 10, 'bold'), bg='white').pack(anchor='w', padx=10, pady=5)
        f_r = tk.Frame(frame_receptor, bg='white')
        f_r.pack(padx=10, pady=5)
        tk.Label(f_r, text="Cliente:", bg='white').grid(row=0, column=0, sticky='w', padx=5, pady=2)
        combo_cliente_real = ttk.Combobox(f_r, values=valores_real, width=42)
        combo_cliente_real.grid(row=0, column=1, padx=5, pady=2)
        if valores_real:
            combo_cliente_real.set(valores_real[0])
        def _abrir_lista_clientes():
            win = tk.Toplevel(tab_real.winfo_toplevel())
            win.title("Seleccionar cliente")
            win.transient(tab_real.winfo_toplevel())
            lb = tk.Listbox(win, font=('Segoe UI', 10), height=12, yscrollcommand=lambda *a: None)
            sb = tk.Scrollbar(win, orient=tk.VERTICAL, command=lb.yview)
            lb.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
            sb.pack(side=tk.RIGHT, fill=tk.Y)
            lb.configure(yscrollcommand=sb.set)
            for v in valores_real:
                lb.insert(tk.END, v)
            def elegir():
                sel = lb.curselection()
                if sel:
                    combo_cliente_real.set(lb.get(sel[0]))
                    win.destroy()
