    def mostrar_deposito_documentos(self):
        """Depósito de documentos: consulta de archivos y configuración de carpeta."""
        from time import localtime, strftime

        self._sincronizar_panel_lateral_modulo("Depósito de documentos", "deposito")
        self.limpiar_area_trabajo()
        self.set_status("Depósito de documentos")
        from backend.modules.deposito_documentos import (
            obtener_carpeta_deposito,
            guardar_carpeta_deposito,
            listar_archivos,
        )

        main_frame = tk.Frame(self.area_trabajo, bg=THEME["bg_content"])
        main_frame.pack(fill=tk.BOTH, expand=True)
        header = tk.Frame(main_frame, bg=THEME["header_bg"], height=40)
        header.pack(fill=tk.X)
        header.pack_propagate(False)
        tk.Label(
            header, text="DEPÓSITO DE DOCUMENTOS",
            bg=THEME["header_bg"], fg=THEME["header_fg"], font=(THEME["font_ui"], 11, "bold"),
        ).pack(side=tk.LEFT, padx=16, pady=8)

        nb = ttk.Notebook(main_frame)
        nb.pack(fill=tk.BOTH, expand=True, padx=8, pady=8)

        tab_cons = tk.Frame(nb, bg=THEME["bg_content"])
        tab_cfg = tk.Frame(nb, bg=THEME["bg_content"])
        nb.add(tab_cons, text="  Consulta  ")
        nb.add(tab_cfg, text="  Configuración  ")

        cols = ("Archivo", "Tamaño (bytes)", "Modificado")
        fbar = tk.Frame(tab_cons, bg=THEME["bg_sidebar"], pady=6)
        fbar.pack(fill=tk.X)
        lbl_ruta = tk.Label(
            tab_cons, text="", bg=THEME["bg_content"], fg=THEME["text_secondary"],
            font=(THEME["font_ui"], 8), anchor="w",
        )
        lbl_ruta.pack(fill=tk.X, padx=6)
        mid = tk.Frame(tab_cons, bg=THEME["bg_content"])
        mid.pack(fill=tk.BOTH, expand=True)
        tree = ttk.Treeview(mid, columns=cols, show="headings", height=18)
        for c, w in zip(cols, (420, 110, 180)):
            tree.heading(c, text=c)
            tree.column(c, width=w, anchor="w")
        sb = ttk.Scrollbar(mid, orient=tk.VERTICAL, command=tree.yview)
        tree.configure(yscrollcommand=sb.set)
        tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        sb.pack(side=tk.RIGHT, fill=tk.Y)

        def _ref_tabla():
            for i in tree.get_children():
                tree.delete(i)
            lista, carpeta = listar_archivos()
            lbl_ruta.config(text=f"Carpeta: {carpeta}")
            for it in lista:
                m = it.get("modificado") or 0
                try:
                    ftxt = strftime("%d/%m/%Y %H:%M", localtime(m))
                except Exception:
                    ftxt = "—"
                tree.insert("", tk.END, values=(it["nombre"], it.get("tamano", 0), ftxt))

        tk.Button(
            fbar, text="Actualizar lista", command=_ref_tabla,
            bg=THEME["btn_primary_bg"], fg=THEME["btn_primary_fg"], relief=tk.FLAT, padx=10, cursor="hand2",
        ).pack(side=tk.LEFT, padx=6)
        _ref_tabla()

        tk.Label(tab_cfg, text="Carpeta del depósito (XML, PDF, etc.):", bg=THEME["bg_content"], anchor="w").pack(anchor="w", padx=12, pady=(12, 4))
        e_dir = tk.Entry(tab_cfg, width=72, font=(THEME["font_ui"], 9))
        e_dir.pack(fill=tk.X, padx=12, pady=4)
        e_dir.insert(0, obtener_carpeta_deposito())

        def _guardar_dir():
            r = guardar_carpeta_deposito(e_dir.get().strip())
            if r.get("exito"):
                messagebox.showinfo("Depósito", r.get("mensaje", "Guardado."))
                _ref_tabla()
            else:
                messagebox.showerror("Depósito", r.get("error", "Error"))

        def _examinar():
            p = filedialog.askdirectory(title="Carpeta de depósito de documentos")
            if p:
                e_dir.delete(0, tk.END)
                e_dir.insert(0, p)

        bf = tk.Frame(tab_cfg, bg=THEME["bg_content"])
        bf.pack(anchor="w", padx=12, pady=12)
        tk.Button(bf, text="Examinar…", command=_examinar, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=10, cursor="hand2").pack(side=tk.LEFT, padx=4)
        tk.Button(bf, text="Guardar carpeta", command=_guardar_dir, bg=THEME["btn_primary_bg"], fg=THEME["btn_primary_fg"], relief=tk.FLAT, padx=12, cursor="hand2").pack(side=tk.LEFT, padx=4)

    def mostrar_cierre_mensual(self):
        """Cierra el período: recalcula saldos y opcionalmente bloquea el mes."""
        if not self._requiere_permiso("auditoria", "Cierre mensual"):
            return
        from backend.modules.periodos_bloqueados import PeriodosBloqueados

        d = tk.Toplevel(self.root)
        d.title("Cierre mensual")
        d.transient(self.root)
        f = tk.Frame(d, bg=THEME["bg_content"], padx=20, pady=16)
        f.pack(fill=tk.BOTH, expand=True)
        tk.Label(f, text="Período a cerrar", bg=THEME["bg_content"], font=(THEME["font_ui"], 10, "bold")).pack(anchor="w")
        row = tk.Frame(f, bg=THEME["bg_content"])
        row.pack(fill=tk.X, pady=10)
        tk.Label(row, text="Mes:", bg=THEME["bg_content"]).pack(side=tk.LEFT)
        mes_c = ttk.Combobox(row, values=[f"{i:02d}" for i in range(1, 13)], width=5)
        mes_c.set(f"{datetime.now().month:02d}")
        mes_c.pack(side=tk.LEFT, padx=8)
        tk.Label(row, text="Año:", bg=THEME["bg_content"]).pack(side=tk.LEFT, padx=(12, 0))
        anio_e = tk.Entry(row, width=8)
        anio_e.insert(0, str(datetime.now().year))
        anio_e.pack(side=tk.LEFT, padx=8)
        bloq_var = tk.BooleanVar(value=True)
        tk.Checkbutton(
            f, text="Bloquear el período para evitar cambios en pólizas",
            variable=bloq_var, bg=THEME["bg_content"], anchor="w",
        ).pack(fill=tk.X, pady=8)
        tk.Label(
            f,
            text="Antes de cerrar se genera respaldo de la BD; si falla, no se continúa. Requiere confirmación de administrador.",
            bg=THEME["bg_content"],
            fg=THEME["text_secondary"],
            font=(THEME["font_ui"], 8),
            wraplength=420,
            justify=tk.LEFT,
        ).pack(anchor="w", pady=(0, 6))

        def _ejecutar():
            self._refrescar_perfil_usuario()
            try:
                mes = int(mes_c.get())
                anio = int(anio_e.get())
            except ValueError:
                messagebox.showerror("Cierre", "Mes y año numéricos.")
                return

            if not self._perfil_usuario.get("es_admin"):
                messagebox.showerror("Cierre mensual", "Solo un administrador puede ejecutar el cierre mensual.")
                return
            if not messagebox.askyesno(
                "Confirmación de administrador",
                f"¿Confirma el cierre mensual {mes:02d}/{anio} como administrador?",
            ):
                return

            # Validación: si hay pólizas del periodo que NO están afectadas,
            # avisamos antes de recalcular/bloquear.
            try:
                import sqlite3

                with sqlite3.connect(self.polizas.db_path) as conn:
                    cur = conn.cursor()
                    cur.execute(
                        """
                        SELECT COUNT(*) FROM polizas
                        WHERE strftime('%Y', fecha) = ?
                          AND strftime('%m', fecha) = ?
                          AND UPPER(COALESCE(estatus,'C')) <> 'A'
                        """,
                        (str(anio), f"{mes:02d}"),
                    )
                    pendientes = int(cur.fetchone()[0] or 0)
            except Exception:
                pendientes = 0

            if not messagebox.askyesno(
                "Confirmar",
                f"Se recalcularán saldos mensuales y { 'se bloqueará' if bloq_var.get() else 'no se bloqueará' } "
                f"el período {mes:02d}/{anio}. ¿Continuar?",
            ):
                return
            try:
                from backend.modules.db_herramientas import respaldar_sqlite

                rb = respaldar_sqlite(self.polizas.db_path)
                if not rb.get("exito"):
                    messagebox.showerror(
                        "Respaldo obligatorio",
                        f"No se pudo generar el respaldo; el cierre se aborta.\n{rb.get('error', '')}",
                    )
                    return
                self.set_status(f"Respaldo pre-cierre: {rb.get('archivo', '')}")
            except Exception as ex:
                messagebox.showerror("Respaldo obligatorio", f"Error al respaldar: {ex}")
                return
            try:
                self.polizas.recalcular_saldos_mensuales()
            except Exception as ex:
                messagebox.showerror("Cierre", f"Error al recalcular saldos: {ex}")
                return
            msg = "Saldos recalculados."
            if bloq_var.get():
                if pendientes > 0:
                    msg += f"\nAviso: hay {pendientes} póliza(s) en el periodo con estatus distinto de 'A'."
                r = PeriodosBloqueados().bloquear(anio, mes, self.usuario_actual)
                msg += f"\n{r.get('mensaje', '')}" if r.get("exito") else f"\nAviso: {r.get('error')}"
            messagebox.showinfo("Cierre mensual", msg)
            d.destroy()
            self.set_status(f"Cierre mensual {mes:02d}/{anio}")

        tk.Button(f, text="Ejecutar cierre", command=_ejecutar, bg=THEME["btn_primary_bg"], fg=THEME["btn_primary_fg"], relief=tk.FLAT, padx=14, pady=6, cursor="hand2").pack(anchor="w", pady=12)
        self._fit_toplevel(d, 0.35, 0.28, 400, 220)

    def mostrar_cierre_anual(self):
        """Cierre anual completo: respaldo + pólizas + bloqueo."""
        if not self._requiere_permiso("auditoria", "Cierre anual"):
            return
        try:
            from backend.modules.cierre_anual import CierreAnual
        except Exception as e:
            messagebox.showerror("Cierre anual", f"Módulo no disponible: {e}")
            return

        d = tk.Toplevel(self.root)
        d.title("Cierre anual")
        d.transient(self.root)
        d.resizable(True, True)
        try:
            d.minsize(980, 600)
        except Exception:
            pass

        main = tk.Frame(d, bg=THEME["bg_content"], padx=14, pady=12)
        main.grid(row=0, column=0, sticky="nsew")
        d.grid_rowconfigure(0, weight=1)
        d.grid_columnconfigure(0, weight=1)
        main.grid_rowconfigure(3, weight=1)
        main.grid_columnconfigure(0, weight=1)

        top = tk.Frame(main, bg=THEME["bg_content"])
        top.grid(row=0, column=0, sticky="ew")
        tk.Label(top, text="Ejercicio (año):", bg=THEME["bg_content"]).pack(side=tk.LEFT, padx=4)
        anio_e = tk.Entry(top, width=10)
        anio_e.insert(0, str(datetime.now().year))
        anio_e.pack(side=tk.LEFT, padx=4)
        tk.Label(top, text="Cuenta utilidad/pérdida:", bg=THEME["bg_content"]).pack(side=tk.LEFT, padx=(14, 4))
        cb_util = ttk.Combobox(top, width=34)
        cb_util.pack(side=tk.LEFT, padx=4)
        tk.Label(top, text="Fecha cierre:", bg=THEME["bg_content"]).pack(side=tk.LEFT, padx=(14, 4))
        ent_fecha = tk.Entry(top, width=12)
        ent_fecha.insert(0, f"{datetime.now().year}-12-31")
        ent_fecha.pack(side=tk.LEFT, padx=4)

        opts = tk.Frame(main, bg=THEME["bg_content"])
        opts.grid(row=1, column=0, sticky="ew", pady=(10, 8))
        var_block = tk.BooleanVar(value=True)
        tk.Label(opts, text="Respaldo completo: siempre (obligatorio).", bg=THEME["bg_content"], fg=THEME["text_secondary"]).pack(side=tk.LEFT, padx=4)
        tk.Checkbutton(opts, text="Bloquear 12 meses del ejercicio", variable=var_block, bg=THEME["bg_content"]).pack(side=tk.LEFT, padx=(14, 4))
        info = tk.Label(
            main,
            text="Previsualiza: póliza de cierre (cuentas 4/5/6) y póliza de apertura (1/2/3). Se generan CAPTURADAS; luego puedes Verificar/Afectar.",
            bg=THEME["bg_content"],
            fg=THEME["text_secondary"],
            font=(THEME["font_ui"], 8),
            wraplength=920,
            justify=tk.LEFT,
            anchor="w",
        )
        info.grid(row=2, column=0, sticky="ew", pady=(0, 8))

        # Cargar catálogo a combo utilidad
        try:
            vals = []
            for c in self.catalogo.obtener_cuentas(incluir_inactivas=False):
                vals.append(f"{c[0]}  {(c[1] or '')}")
            cb_util["values"] = vals
            if vals:
                cb_util.set(vals[0])
        except Exception:
            pass

        nb = ttk.Notebook(main)
        nb.grid(row=3, column=0, sticky="nsew")

        tab_cierre = tk.Frame(nb, bg=THEME["bg_content"])
        tab_ap = tk.Frame(nb, bg=THEME["bg_content"])
        nb.add(tab_cierre, text="Póliza cierre (resultados)")
        nb.add(tab_ap, text="Póliza apertura (balance)")

        def _mk_tree(parent):
            frame = tk.Frame(parent, bg=THEME["bg_content"])
            frame.pack(fill=tk.BOTH, expand=True)
            frame.grid_rowconfigure(0, weight=1)
            frame.grid_columnconfigure(0, weight=1)
            cols = ("Cuenta", "Concepto", "Cargo", "Abono")
            tree = ttk.Treeview(frame, columns=cols, show="headings", height=14)
            for c in cols:
                tree.heading(c, text=c)
                tree.column(c, width=(120 if c == "Cuenta" else 420 if c == "Concepto" else 140), anchor=("w" if c in ("Cuenta", "Concepto") else "e"))
            ysb = ttk.Scrollbar(frame, orient="vertical", command=tree.yview)
            tree.configure(yscrollcommand=ysb.set)
            tree.grid(row=0, column=0, sticky="nsew")
            ysb.grid(row=0, column=1, sticky="ns")
            return tree

        tree_c = _mk_tree(tab_cierre)
        tree_a = _mk_tree(tab_ap)

        lbl_res = tk.Label(main, text="—", bg=THEME["bg_content"], fg=THEME["text_primary"], anchor="w", justify=tk.LEFT)
        lbl_res.grid(row=4, column=0, sticky="ew", pady=(8, 0))

        ca = CierreAnual(db_path=self.polizas.db_path)
        _prev = {}

        def _extra_num(v: str) -> str:
            return (v or "").strip().split(" ", 1)[0].strip()

        def previsualizar():
            nonlocal _prev
            for i in tree_c.get_children():
                tree_c.delete(i)
            for i in tree_a.get_children():
                tree_a.delete(i)
            try:
                anio = int(anio_e.get().strip())
            except ValueError:
                messagebox.showerror("Cierre anual", "Año inválido.")
                return
            util = _extra_num(cb_util.get())
            if not util:
                messagebox.showerror("Cierre anual", "Seleccione cuenta utilidad/pérdida.")
                return
            fecha = (ent_fecha.get() or "").strip()[:10]
            r = ca.previsualizar(ejercicio=anio, cuenta_utilidad=util, fecha_cierre=fecha)
            if not r.get("exito"):
                messagebox.showerror("Cierre anual", r.get("error", "No se pudo calcular."))
                return
            _prev = r
            for m in (r.get("cierre") or {}).get("movimientos") or []:
                tree_c.insert("", tk.END, values=(m.get("num_cuenta",""), m.get("concepto",""), f"{float(m.get('cargo') or 0):,.2f}" if float(m.get('cargo') or 0) else "", f"{float(m.get('abono') or 0):,.2f}" if float(m.get('abono') or 0) else ""))
            for m in (r.get("apertura") or {}).get("movimientos") or []:
                tree_a.insert("", tk.END, values=(m.get("num_cuenta",""), m.get("concepto",""), f"{float(m.get('cargo') or 0):,.2f}" if float(m.get('cargo') or 0) else "", f"{float(m.get('abono') or 0):,.2f}" if float(m.get('abono') or 0) else ""))
            lbl_res.config(text=f"Utilidad neta estimada: ${float(r.get('utilidad_neta') or 0):,.2f} | Cierre: {len((r.get('cierre') or {}).get('movimientos') or [])} movs | Apertura: {len((r.get('apertura') or {}).get('movimientos') or [])} movs")

        def ejecutar():
            previsualizar()
            if not _prev:
                return
            try:
                anio = int(anio_e.get().strip())
            except ValueError:
                return
            util = _extra_num(cb_util.get())
            fecha = (ent_fecha.get() or "").strip()[:10]
            if not messagebox.askyesno("Confirmar", f"Se ejecutará el cierre anual {anio}.\n\nRespaldo: Sí (obligatorio)\nBloqueo periodos: {'Sí' if var_block.get() else 'No'}\n\n¿Continuar?"):
                return
            r = ca.ejecutar(
                ejercicio=anio,
                cuenta_utilidad=util,
                usuario=self.usuario_actual,
                fecha_cierre=fecha,
                hacer_respaldo=True,
                bloquear_periodos=bool(var_block.get()),
            )
            if not r.get("exito"):
                messagebox.showerror("Cierre anual", str(r.get("error") or "No se pudo ejecutar."))
                return
            msg = f"Listo.\nBackup: {r.get('backup') or '—'}\nPóliza cierre ID: {r.get('poliza_cierre_id')}\nPóliza apertura ID: {r.get('poliza_apertura_id')}\nPeríodos bloqueados: {r.get('periodos_bloqueados')}"
            messagebox.showinfo("Cierre anual", msg)
            try:
                self.actualizar_lista_polizas()
            except Exception:
                pass
            self.set_status(f"Cierre anual completo {anio}")
            d.destroy()

        footer = tk.Frame(main, bg=THEME["bg_content"])
        footer.grid(row=5, column=0, sticky="ew", pady=(10, 0))
        tk.Button(footer, text="Previsualizar", command=previsualizar, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=14, pady=6, cursor="hand2").pack(side=tk.LEFT)
        tk.Button(footer, text="Ejecutar cierre anual", command=ejecutar, bg=THEME["btn_primary_bg"], fg=THEME["btn_primary_fg"], relief=tk.FLAT, padx=14, pady=6, cursor="hand2").pack(side=tk.LEFT, padx=8)
        tk.Button(footer, text="Cerrar", command=d.destroy, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=14, pady=6).pack(side=tk.RIGHT)

        previsualizar()
        self._fit_toplevel(d, 0.92, 0.78, 1180, 700)

        return

    def _dialog_historico_tipos_cambio(self):
        """Histórico: consultas en segundo plano (no bloquean la ventana) + sincronización con catálogo Monedas."""
        from backend.models.monedas_catalogo import CatalogoMonedas
        from backend.modules.tipo_cambio_jobs import (
            ejecutar_fetch_completo_en_hilo,
            ejecutar_una_moneda_en_hilo,
        )

        d = tk.Toplevel(self.root)
        d.title("Histórico de tipos de cambio")
        d.transient(self.root)
        d.configure(bg=THEME["bg_content"])

        bar = tk.Frame(d, bg=THEME["bg_sidebar"], padx=6, pady=6)
        bar.pack(fill=tk.X)
        tk.Label(bar, text="Acciones:", bg=THEME["bg_sidebar"], fg=THEME["text_primary"],
                 font=(THEME["font_ui"], 9, "bold")).pack(side=tk.LEFT, padx=(0, 8))

        body = tk.Frame(d, bg=THEME["bg_content"], padx=12, pady=10)
        body.pack(fill=tk.BOTH, expand=True)

        lbl_estado = tk.Label(
            body, text="", bg=THEME["bg_content"], fg=THEME["accent"],
            font=(THEME["font_ui"], 8), wraplength=480, justify=tk.LEFT,
        )
        lbl_estado.pack(anchor="w", pady=(0, 4))

        tk.Label(body, text="Moneda:", bg=THEME["bg_content"], fg=THEME["text_primary"]).pack(anchor="w")
        mgr_monedas = CatalogoMonedas()
        try:
            _rows_m = mgr_monedas.listar()
            _monedas_disponibles = [str(r.get("nombre") or "").strip() for r in _rows_m if (r.get("nombre") or "").strip()]
            _monedas_disponibles = sorted(set(_monedas_disponibles), key=lambda s: s.lower())
        except Exception:
            _monedas_disponibles = []
        if not _monedas_disponibles:
            _monedas_disponibles = ["Dólar Americano", "Euro", "Libra Esterlina"]
        _default_moneda = "Dólar Americano" if "Dólar Americano" in _monedas_disponibles else _monedas_disponibles[0]
        moneda_var = tk.StringVar(value=_default_moneda)
        cb_moneda = ttk.Combobox(
            body, textvariable=moneda_var,
            values=_monedas_disponibles, width=40, state="readonly",
        )
        cb_moneda.pack(fill=tk.X, pady=(0, 4))
        tk.Label(
            body,
            text="Las consultas a Banxico / referencia web son en segundo plano. La sincronización automática ocurre a las 05:00 y 17:00 "
                 "(vea la barra inferior). Use 🔄 solo si necesita forzar una consulta o otra fecha. "
                 "Al guardar, se actualizan histórico y catálogo Monedas (USD/EUR/GBP).",
            bg=THEME["bg_content"], fg=THEME["text_secondary"], font=(THEME["font_ui"], 8), wraplength=480, justify=tk.LEFT,
        ).pack(anchor="w", pady=(0, 6))

        fecha_row = tk.Frame(body, bg=THEME["bg_content"])
        fecha_row.pack(fill=tk.X, pady=(0, 6))
        tk.Label(fecha_row, text="Fecha (FIX):", bg=THEME["bg_content"], fg=THEME["text_primary"]).pack(side=tk.LEFT, padx=(0, 8))
        try:
            from tkcalendar import DateEntry
            de_fecha = DateEntry(
                fecha_row, width=12, background=THEME["accent"],
                foreground=THEME["header_fg"], borderwidth=2,
                date_pattern="yyyy-mm-dd",
            )
            de_fecha.pack(side=tk.LEFT)
        except Exception:
            de_fecha = None
            ent_fecha = tk.Entry(fecha_row, width=12)
            ent_fecha.insert(0, datetime.now().strftime("%Y-%m-%d"))
            ent_fecha.pack(side=tk.LEFT)

        def _fecha_sel() -> str:
            if de_fecha is not None:
                return de_fecha.get_date().strftime("%Y-%m-%d")
            return (ent_fecha.get() or "").strip()[:10]

        ruta_tc = self._ruta_tipos_cambio_historico()
        db_path = CatalogoMonedas().db_path

        tk.Label(body, text="Tipo de cambio (vs MXN):", bg=THEME["bg_content"], fg=THEME["text_primary"]).pack(anchor="w")
        tc_manual = tk.Entry(body, width=20)
        tc_manual.insert(0, "—")
        tc_manual.pack(anchor="w", pady=(0, 8))

        tk.Label(body, text="Histórico (últimos registros):", bg=THEME["bg_content"], fg=THEME["text_primary"]).pack(anchor="w")
        txt = tk.Text(body, height=10, width=52, font=(THEME["font_ui"], 9), bg="#fff", fg=THEME["text_primary"])
        txt.pack(fill=tk.BOTH, expand=True, pady=(4, 8))

        btn_refs = []

        def refrescar_historico_text():
            txt.delete("1.0", tk.END)
            try:
                if os.path.isfile(ruta_tc):
                    with open(ruta_tc, "r", encoding="utf-8") as f:
                        txt.insert("1.0", f.read()[-4500:])
                else:
                    txt.insert("1.0", "(Sin registros aún; espere la carga automática o use 🔄 / registrar manual.)\n")
            except Exception:
                txt.insert("1.0", "(No se pudo cargar histórico.)\n")

        def _busy(on: bool):
            st = tk.DISABLED if on else tk.NORMAL
            for b in btn_refs:
                try:
                    b.config(state=st)
                except tk.TclError:
                    pass
            cb_moneda.config(state=("disabled" if on else "readonly"))
            tc_manual.config(state=st)
            lbl_estado.config(text=("Consultando en segundo plano… no cierre la ventana." if on else ""))

        def aplicar_valor_moneda_actual():
            tc_manual.delete(0, tk.END)
            tc_manual.insert(0, "…")
            _busy(True)

            def on_one(ok, t, err):
                def ui():
                    _busy(False)
                    if ok and t:
                        val, _iso, _fu = t
                        tc_manual.delete(0, tk.END)
                        tc_manual.insert(0, f"{val:.4f}")
                    else:
                        tc_manual.delete(0, tk.END)
                        tc_manual.insert(0, "—")
                self.root.after(0, ui)

            ejecutar_una_moneda_en_hilo(
                fecha_ui=_fecha_sel(),
                nombre_moneda_ui=moneda_var.get(),
                ruta_config=self._ruta_config_instituto(),
                on_done=on_one,
            )

        def sincronizar_async(silencioso: bool):
            _busy(True)

            def on_done(ok, datos, ncat, err):
                def ui():
                    _busy(False)
                    refrescar_historico_text()
                    if not ok:
                        if not silencioso:
                            messagebox.showerror("Tipo de cambio", str(err))
                        return
                    if ok and datos:
                        try:
                            from backend.models.tipos_cambio_registro import TiposCambioRegistro
                            from backend.modules.tipo_cambio_auto import UI_MONEDA_A_ISO

                            reg = TiposCambioRegistro(db_path=db_path)
                            f_hist = (_fecha_sel() or "")[:10]
                            for nombre_ui, triple in (datos or {}).items():
                                if not triple:
                                    continue
                                val = triple[0]
                                iso = UI_MONEDA_A_ISO.get(str(nombre_ui).strip())
                                if not iso or str(iso).upper()[:3] == "MXN":
                                    continue
                                try:
                                    vv = float(val)
                                except (TypeError, ValueError):
                                    continue
                                if vv > 0:
                                    reg.registrar(f_hist, iso, vv, "Banxico")
                        except Exception:
                            pass
                    if datos:
                        sel = moneda_var.get()
                        if sel in datos:
                            v, _obs, _fu = datos[sel]
                            tc_manual.delete(0, tk.END)
                            tc_manual.insert(0, f"{v:.4f}")
                        self._tc_fix_cache.pop(_fecha_sel(), None)
                    if not silencioso:
                        if datos:
                            messagebox.showinfo(
                                "Listo",
                                f"Monedas actualizadas en red: {len(datos)}. "
                                f"Filas de catálogo Monedas sincronizadas: {ncat}.",
                            )
                        else:
                            messagebox.showwarning(
                                "Tipo de cambio",
                                "No se obtuvo ningún tipo para esa fecha. Compruebe la conexión o pruebe otra fecha.",
                            )
                    cb = getattr(self, "_refrescar_catalogo_monedas", None)
                    if callable(cb):
                        try:
                            cb()
                        except tk.TclError:
                            pass

                self.root.after(0, ui)

            ejecutar_fetch_completo_en_hilo(
                fecha_ui=_fecha_sel(),
                ruta_historico=ruta_tc,
                ruta_config=self._ruta_config_instituto(),
                db_path=db_path,
                on_done=on_done,
            )

        def consultar_boton_actualizar():
            sincronizar_async(silencioso=False)

        b_imp = tk.Button(bar, text="📥", command=lambda: messagebox.showinfo("Importar", "Importación CSV/XML: próximamente."),
                          bg=THEME["btn_secondary_bg"], width=3, cursor="hand2")
        b_imp.pack(side=tk.LEFT, padx=2)
        btn_refs.append(b_imp)
        b_ref = tk.Button(bar, text="🔄", command=consultar_boton_actualizar,
                          bg=THEME["btn_secondary_bg"], width=3, cursor="hand2")
        b_ref.pack(side=tk.LEFT, padx=2)
        btn_refs.append(b_ref)
        tk.Button(bar, text="❓", command=lambda: messagebox.showinfo(
            "Ayuda",
            "Las consultas no bloquean la interfaz. Fuente principal: Banxico; respaldo: DOF (USD). "
            "La actualización manual es por una moneda a la vez. Con 🔄 se ejecuta sincronización automática del catálogo.",
        ), bg=THEME["btn_secondary_bg"], width=3, cursor="hand2").pack(side=tk.LEFT, padx=2)
        tk.Button(bar, text="🚪", command=d.destroy,
                  bg=THEME["btn_secondary_bg"], width=3, cursor="hand2").pack(side=tk.RIGHT, padx=2)

        refrescar_historico_text()

        cb_moneda.bind("<<ComboboxSelected>>", lambda _e: aplicar_valor_moneda_actual())

        def registrar():
            f0 = _fecha_sel()
            try:
                v = float((tc_manual.get() or "0").replace(",", ""))
            except ValueError:
                messagebox.showerror("Error", "Tipo de cambio inválido.")
                return
            line = f"{f0}  {moneda_var.get()[:12]}  {v:.4f}  manual\n"
            try:
                with open(ruta_tc, "a", encoding="utf-8") as f:
                    f.write(line)
                refrescar_historico_text()
                self._tc_fix_cache.pop(f0[:10], None)
                try:
                    from backend.models.tipos_cambio_registro import TiposCambioRegistro
                    from backend.modules.tipo_cambio_auto import UI_MONEDA_A_ISO

                    nom_sel = (moneda_var.get() or "").strip()
                    iso = None
                    for row in mgr_monedas.listar():
                        if (row.get("nombre") or "").strip().lower() == nom_sel.lower():
                            iso = (row.get("clave_fiscal") or "").strip().upper()[:3]
                            break
                    if not iso:
                        iso = UI_MONEDA_A_ISO.get(nom_sel)
                    iso = (iso or "").strip().upper()[:3]
                    if iso and iso != "MXN" and v > 0:
                        TiposCambioRegistro(db_path=db_path).registrar(f0[:10], iso, v, "Manual")
                except Exception:
                    pass
                self.set_status("Tipo de cambio registrado en histórico local")
                messagebox.showinfo("Listo", "Tipo de cambio guardado en el histórico y en la tabla tipos_cambio.")
            except Exception as ex:
                messagebox.showerror("Error", str(ex))

        b_reg = tk.Button(body, text="Registrar en histórico", command=registrar,
                          bg=THEME["btn_primary_bg"], fg=THEME["btn_primary_fg"], relief=tk.FLAT, padx=12, pady=6, cursor="hand2")
        b_reg.pack(anchor="w")
        btn_refs.append(b_reg)

        # La sincronización con red es automática a las 08:00 y 14:00 (barra inferior); aquí use 🔄 si necesita forzar.

        self._fit_toplevel(d, 0.48, 0.62, 520, 440)
    
    def datos_empresa(self):
        dialog = tk.Toplevel(self.root)
        dialog.title("Datos de la empresa")
        dialog.transient(self.root)
        
        tk.Label(dialog, text="DATOS DE LA EMPRESA", font=('Arial', 12, 'bold')).pack(pady=10)
        
        frame = tk.Frame(dialog)
        frame.pack(pady=10, padx=20, fill=tk.BOTH, expand=True)

        # Multiempresa: selector y creación (base)
        try:
            from backend.modules.empresas import EmpresasManager

            em = EmpresasManager()
            info = em.cargar()
            empresas = [str(e.get("nombre") or "").strip() for e in (info.get("EMPRESAS") or []) if (e.get("nombre") or "").strip()]
            if not empresas:
                empresas = [self.empresa_actual]
        except Exception:
            em = None
            empresas = [self.empresa_actual]

        row_emp = tk.Frame(frame)
        row_emp.grid(row=0, column=0, columnspan=2, sticky="w", pady=(0, 10))
        tk.Label(row_emp, text="Empresa activa:", width=14, anchor="w").pack(side=tk.LEFT)
        cb_emp = ttk.Combobox(row_emp, values=empresas, width=34, state="readonly")
        cb_emp.set(self.empresa_actual)
        cb_emp.pack(side=tk.LEFT, padx=5)
        def _cambiar_empresa():
            sel = (cb_emp.get() or "").strip()
            if not sel:
                return
            self.empresa_actual = sel
            try:
                if em is not None:
                    em.seleccionar_empresa(sel)
            except Exception:
                pass
            # Reinstanciar modelos para que tomen la BD activa (get_db_path override)
            try:
                self.catalogo = CatalogoCuentas()
                self.polizas = SistemaPolizas()
                self.reportes = ReportesContables()
                self.bancos = SistemaBancos()
                self.cfdi_dashboard = CFDIDashboard()
                self.contabilidad_service = ContabilidadService()
            except Exception:
                pass
            try:
                self.empresa_label.config(
                    text=f"  Empresa: {self.empresa_actual}  |  Usuario: {self.usuario_actual}  |  Fecha: {datetime.now().strftime('%d/%m/%Y')}  "
                )
            except Exception:
                pass
            try:
                self.mostrar_catalogo()
            except Exception:
                pass
            messagebox.showinfo("Empresa", f"Empresa activa cambiada a: {sel}")

        def _nueva_empresa():
            nombre = simpledialog.askstring("Nueva empresa", "Nombre de la empresa:", parent=dialog)
            if not (nombre or "").strip():
                return
            if em is not None:
                r = em.crear_empresa(nombre.strip())
                if not r.get("exito"):
                    messagebox.showerror("Error", r.get("error", "No se pudo crear"))
                    return
            if nombre.strip() not in empresas:
                empresas.append(nombre.strip())
            cb_emp.config(values=empresas)
            cb_emp.set(nombre.strip())
            _cambiar_empresa()

        tk.Button(row_emp, text="Cambiar", command=_cambiar_empresa, width=10).pack(side=tk.LEFT, padx=6)
        tk.Button(row_emp, text="Nueva…", command=_nueva_empresa, width=10).pack(side=tk.LEFT)

        try:
            from backend.modules.configuracion_general import ConfiguracionGeneral

            _cg = ConfiguracionGeneral(db_path=self.polizas.db_path).obtener()
        except Exception:
            _cg = {}

        campos = [
            ("Razón social (SAT / reportes):", "razon_social", str(_cg.get("razon_social") or self.empresa_actual or "")),
            ("RFC:", "rfc", str(_cg.get("rfc") or "")),
            ("Régimen fiscal:", "regimen_fiscal", str(_cg.get("regimen_fiscal") or "")),
            ("Domicilio fiscal:", "domicilio_fiscal", str(_cg.get("domicilio_fiscal") or "")),
            ("Teléfono:", "telefono", str(_cg.get("telefono") or "")),
            ("Email:", "email", str(_cg.get("email") or "")),
            ("Ruta logotipo (opcional):", "logo_path", str(_cg.get("logo_path") or "")),
        ]
        ent_map = {}
        for i, (label, key, valor) in enumerate(campos):
            tk.Label(frame, text=label).grid(row=i + 1, column=0, sticky="w", pady=2)
            entry = tk.Entry(frame, width=48)
            entry.grid(row=i + 1, column=1, pady=2, padx=5)
            entry.insert(0, valor)
            ent_map[key] = entry

        def _ex_logo():
            p = filedialog.askopenfilename(
                parent=dialog,
                title="Imagen logotipo",
                filetypes=[("Imágenes", "*.png;*.jpg;*.jpeg;*.gif"), ("Todos", "*.*")],
            )
            if p:
                ent_map["logo_path"].delete(0, tk.END)
                ent_map["logo_path"].insert(0, p)

        tk.Button(frame, text="Examinar logo…", command=_ex_logo).grid(row=len(campos) + 1, column=1, sticky="w", pady=6)

        def guardar():
            try:
                from backend.modules.configuracion_general import ConfiguracionGeneral

                ConfiguracionGeneral(db_path=self.polizas.db_path).guardar(
                    {
                        "razon_social": ent_map["razon_social"].get().strip(),
                        "rfc": ent_map["rfc"].get().strip(),
                        "regimen_fiscal": ent_map["regimen_fiscal"].get().strip(),
                        "domicilio_fiscal": ent_map["domicilio_fiscal"].get().strip(),
                        "telefono": ent_map["telefono"].get().strip(),
                        "email": ent_map["email"].get().strip(),
                        "logo_path": ent_map["logo_path"].get().strip(),
                    }
                )
            except Exception as ex:
                messagebox.showerror("Datos de empresa", str(ex))
                return
            messagebox.showinfo("Éxito", "Datos fiscales guardados en la base de la empresa (encabezados y XML SAT).")
            dialog.destroy()
            self.empresa_label.config(
                text=f"  Empresa: {self.empresa_actual}  |  Usuario: {self.usuario_actual}  |  Fecha: {datetime.now().strftime('%d/%m/%Y')}  "
            )

        tk.Button(dialog, text="Guardar", command=guardar, width=15).pack(pady=10)
        self._fit_toplevel(dialog, 0.48, 0.55, 560, 420)
    
    def calcular_dep_mensual(self):
        """Calcula y registra la depreciacion de todos los activos fijos del mes indicado."""
        try:
            from backend.modules.activos_fijos import ActivosFijos
        except ImportError:
            messagebox.showerror("Error", "Modulo activos_fijos no disponible.")
            return
        d = tk.Toplevel(self.root)
        d.title("Depreciacion mensual de activos fijos")
        d.transient(self.root)
        f = tk.Frame(d, padx=20, pady=20)
        f.pack(fill=tk.BOTH, expand=True)
        tk.Label(f, text="Mes:").grid(row=0, column=0, sticky='w', pady=5)
        mes_combo = ttk.Combobox(f, values=[str(i) for i in range(1, 13)], width=5)
        mes_combo.set(str(datetime.now().month))
        mes_combo.grid(row=0, column=1, pady=5, padx=5)
        tk.Label(f, text="Anio:").grid(row=1, column=0, sticky='w', pady=5)
        anio_entry = tk.Entry(f, width=8)
        anio_entry.insert(0, str(datetime.now().year))
        anio_entry.grid(row=1, column=1, pady=5, padx=5)
        def ejecutar():
            try:
                mes = int(mes_combo.get())
                anio = int(anio_entry.get())
                if mes < 1 or mes > 12:
                    messagebox.showerror("Error", "Mes debe ser 1-12")
                    return
                af = ActivosFijos()
                r = af.registrar_depreciacion_mensual(mes, anio, generar_poliza=False)
                if r.get('exito'):
                    messagebox.showinfo("Depreciacion",
                        f"Depreciacion registrada.\nActivos procesados: {r.get('activos_procesados', 0)}\nTotal depreciacion: ${r.get('total_depreciacion', 0):,.2f}")
                    d.destroy()
                    self.set_status("Depreciacion calculada")
                else:
                    messagebox.showerror("Error", r.get('error', 'Error al calcular'))
            except Exception as ex:
                messagebox.showerror("Error", str(ex))
        tk.Button(f, text="Calcular y registrar", command=ejecutar, bg='lightgreen').grid(row=2, column=1, pady=15, padx=5)
        tk.Button(f, text="Cancelar", command=d.destroy).grid(row=2, column=0, pady=15)
        self._fit_toplevel(d, 0.32, 0.22, 320, 160)
    
    def guardar_cambios(self):
        self.set_status("Guardando...")
        self.root.after(500, lambda: self.set_status("Listo"))
        messagebox.showinfo("Guardar", "Cambios guardados correctamente")

    def _refrescar_perfil_usuario(self):
        try:
            self._perfil_usuario = self.usuarios_sistema.permisos_de(self.usuario_actual)
        except Exception:
            self._perfil_usuario = {"activo": True, "es_admin": True, "permisos": []}

    def _requiere_permiso(self, permiso_clave: str, nombre_modulo: str) -> bool:
        self._refrescar_perfil_usuario()
        p = self._perfil_usuario or {}
        if not p.get("activo", True):
            messagebox.showerror("Acceso denegado", "Usuario inactivo.")
            return False
        if p.get("es_admin", False):
            return True
        perms = set(p.get("permisos") or [])
        if permiso_clave in perms:
            return True
        messagebox.showwarning("Sin permiso", f"No tiene permiso para acceder a {nombre_modulo}.")
        return False

    def mostrar_conceptos_poliza(self):
        """Catálogo básico de conceptos de póliza con filtro por texto."""
        if not self._requiere_permiso("catalogo", "Conceptos de póliza"):
            return
        d = tk.Toplevel(self.root)
        d.title("Conceptos de póliza")
        d.transient(self.root)
        d.resizable(True, True)

        top = tk.Frame(d, padx=10, pady=8)
        top.pack(fill=tk.X)
        tk.Label(top, text="Buscar:").pack(side=tk.LEFT)
        txt = tk.Entry(top, width=38)
        txt.pack(side=tk.LEFT, padx=6)

        tree = ttk.Treeview(d, columns=("codigo", "nombre"), show="headings")
        tree.heading("codigo", text="Código")
        tree.heading("nombre", text="Nombre")
        tree.column("codigo", width=140, anchor="center")
        tree.column("nombre", width=420, anchor="w")
        tree.pack(fill=tk.BOTH, expand=True, padx=10, pady=(0, 8))

        def cargar(rows):
            for i in tree.get_children():
                tree.delete(i)
            for r in rows or []:
                tree.insert("", tk.END, values=(r.get("codigo", ""), r.get("nombre", "")))

        def buscar():
            try:
                q = txt.get().strip()
                rows = conceptos_buscar_por_texto(q, limite=500) if q else conceptos_listar_todos()
                cargar(rows)
            except Exception as ex:
                messagebox.showerror("Error", str(ex))

        tk.Button(top, text="Buscar", command=buscar, bg=THEME["btn_secondary_bg"]).pack(side=tk.LEFT, padx=4)
        tk.Button(top, text="Cerrar", command=d.destroy).pack(side=tk.RIGHT, padx=4)
        buscar()
        self._fit_toplevel(d, 0.5, 0.58, 620, 420)

    def mostrar_parametros(self):
        """Configuración general: conexión BD, empresa fiscal, ejercicio, folios, impresión, SAT, mantenimiento."""
        if not self._requiere_permiso("configuracion", "Parámetros"):
            return

        from backend.modules.configuracion_general import ConfiguracionGeneral
        from backend.modules.db_herramientas import compactar_sqlite, motor_bd_actual, respaldar_sqlite, restaurar_sqlite
        from backend.modules.sat_catalogos_descarga import importar_agrupadores_csv, importar_csv_generico, resumen_actualizacion_sat

        p = self.config_parametros.obtener_parametros_db()
        cg = ConfiguracionGeneral(db_path=self.polizas.db_path)
        cfg = cg.obtener()

        d = tk.Toplevel(self.root)
        d.title("Configuración general")
        d.transient(self.root)
        d.resizable(True, True)
        main = tk.Frame(d, padx=10, pady=10, bg=THEME["bg_content"])
        main.pack(fill=tk.BOTH, expand=True)
        nb = ttk.Notebook(main)
        nb.pack(fill=tk.BOTH, expand=True)

        # --- Tab conexión ---
        tab_db = tk.Frame(nb, bg=THEME["bg_content"], padx=10, pady=10)
        nb.add(tab_db, text="Conexión BD")
        form = tk.Frame(tab_db, bg=THEME["bg_content"])
        form.pack(fill=tk.X)

        def _row_db(r: int, label: str, widget):
            tk.Label(form, text=label, anchor="w", bg=THEME["bg_content"]).grid(row=r, column=0, sticky="w", padx=(0, 10), pady=4)
            widget.grid(row=r, column=1, sticky="w", pady=4)

        v_engine = ttk.Combobox(form, values=["sqlite", "sqlserver"], width=12)
        v_engine.set(p.DB_ENGINE or "sqlite")
        _row_db(0, "DB_ENGINE:", v_engine)
        e_host = tk.Entry(form, width=26)
        e_host.insert(0, p.SQLSERVER_HOST or "localhost")
        _row_db(1, "SQLSERVER_HOST:", e_host)
        e_port = tk.Entry(form, width=10)
        e_port.insert(0, p.SQLSERVER_PORT or "")
        _row_db(2, "SQLSERVER_PORT:", e_port)
        e_db = tk.Entry(form, width=18)
        e_db.insert(0, p.SQLSERVER_DB or "contabilidad")
        _row_db(3, "SQLSERVER_DB:", e_db)
        e_user = tk.Entry(form, width=18)
        e_user.insert(0, p.SQLSERVER_USER or "")
        _row_db(4, "SQLSERVER_USER:", e_user)
        e_pass = tk.Entry(form, width=18, show="*")
        _row_db(5, "SQLSERVER_PASSWORD:", e_pass)
        e_driver = tk.Entry(form, width=28)
        e_driver.insert(0, p.SQLSERVER_DRIVER or "ODBC Driver 18 for SQL Server")
        _row_db(6, "SQLSERVER_DRIVER:", e_driver)
        trust_var = tk.BooleanVar(value=str(p.SQLSERVER_TRUST_SERVER_CERT or "yes").lower() in ("yes", "true", "1"))
        trust = ttk.Checkbutton(form, text="TrustServerCertificate", variable=trust_var)
        _row_db(7, "TrustServerCertificate:", trust)

        def guardar_db():
            DB_ENGINE = v_engine.get().strip().lower()
            if DB_ENGINE not in ("sqlite", "sqlserver"):
                messagebox.showerror("Error", "DB_ENGINE inválido.")
                return
            r = self.config_parametros.guardar_db(
                DB_ENGINE=DB_ENGINE,
                SQLSERVER_HOST=e_host.get(),
                SQLSERVER_PORT=e_port.get(),
                SQLSERVER_DB=e_db.get(),
                SQLSERVER_USER=e_user.get(),
                SQLSERVER_PASSWORD=e_pass.get(),
                SQLSERVER_DRIVER=e_driver.get(),
                SQLSERVER_TRUST_SERVER_CERT="yes" if trust_var.get() else "no",
            )
