        def do_backup():
            r = respaldar_sqlite(self.polizas.db_path)
            if r.get("exito"):
                messagebox.showinfo("Respaldo", r.get("archivo", ""))
            else:
                messagebox.showerror("Respaldo", r.get("error", ""))

        def do_restore():
            self._refrescar_perfil_usuario()
            if not self._perfil_usuario.get("es_admin"):
                messagebox.showerror("Restauración", "Solo administrador (superadmin) puede restaurar.")
                return
            if not messagebox.askyesno("Confirmación 1/2", "¿Desea restaurar la base de datos desde un respaldo?"):
                return
            path = filedialog.askopenfilename(parent=d, filetypes=[("SQLite", "*.db"), ("Todos", "*.*")])
            if not path:
                return
            if not messagebox.askyesno(
                "Confirmación 2/2",
                "Se sobrescribirá la base de datos en uso. Cierre otras sesiones. ¿Continuar?",
            ):
                return
            r = restaurar_sqlite(self.polizas.db_path, path)
            if r.get("exito"):
                messagebox.showinfo("Restauración", "Restauración completada. Reinicie la aplicación.")
            else:
                messagebox.showerror("Restauración", r.get("error", ""))

        def do_vacuum():
            r = compactar_sqlite(self.polizas.db_path)
            if r.get("exito"):
                messagebox.showinfo("Mantenimiento", r.get("mensaje", "Listo"))
            else:
                messagebox.showerror("Mantenimiento", r.get("error", ""))

