    def _libro_texto_cfdi_por_partida(self, id_partida: int) -> str:
        """Texto multilínea para panel o ventana emergente (cfdi_poliza por id_partida)."""
        rv = self.libro_contable.cfdi_por_partida(int(id_partida))
        if not rv.get("exito"):
            return str(rv.get("error", "Sin datos CFDI."))
        c = rv.get("cfdi") or {}
        return (
            f"UUID: {c.get('uuid') or '—'}\n"
            f"RFC emisor: {c.get('rfc_emisor') or '—'}\n"
            f"RFC receptor: {c.get('rfc_receptor') or '—'}\n"
            f"Fecha CFDI: {c.get('fecha_cfdi') or '—'}\n"
            f"Tipo: {c.get('tipo_comprobante') or '—'}\n"
            f"Subtotal: {float(c.get('subtotal') or 0):,.2f}\n"
            f"IVA trasladado: {float(c.get('iva_trasladado') or 0):,.2f}\n"
            f"IVA retenido: {float(c.get('iva_retenido') or 0):,.2f}\n"
            f"ISR retenido: {float(c.get('isr_retenido') or 0):,.2f}\n"
            f"Total: {float(c.get('total_cfdi') or 0):,.2f}\n"
            f"Método pago: {c.get('metodo_pago') or '—'}\n"
            f"Forma pago: {c.get('forma_pago') or '—'}"
        )

    def mostrar_libro_mayor(self, cuenta_prefill=None, fecha_ini=None, fecha_fin=None):
        """Libro mayor por cuenta (motor completo): saldo inicial, CFDI por partida, doble clic = detalle."""
        if not self._requiere_permiso("reportes", "Libro mayor"):
            return
        d = tk.Toplevel(self.root)
        d.title("Libro mayor")
        d.transient(self.root)
        d.resizable(True, True)
        try:
            d.minsize(980, 580)
        except Exception:
            pass

        d.grid_rowconfigure(2, weight=1)
        d.grid_columnconfigure(0, weight=1)

        f = tk.Frame(d, padx=10, pady=8, bg=THEME["bg_content"])
        f.grid(row=0, column=0, sticky="ew")

        tk.Label(f, text="Cuenta:", bg=THEME["bg_content"]).grid(row=0, column=0, sticky="w", pady=4)
        cta = tk.Entry(f, width=18)
        cta.grid(row=0, column=1, sticky="w", padx=5, pady=4)
        tk.Label(f, text="Desde (AAAA-MM-DD):", bg=THEME["bg_content"]).grid(row=0, column=2, sticky="w", padx=(16, 0))
        fi = tk.Entry(f, width=12)
        fi.grid(row=0, column=3, sticky="w", padx=5)
        tk.Label(f, text="Hasta:", bg=THEME["bg_content"]).grid(row=0, column=4, sticky="w")
        ff = tk.Entry(f, width=12)
        ff.grid(row=0, column=5, sticky="w", padx=5)
        hoy = datetime.now().strftime("%Y-%m-%d")
        cta.insert(0, (cuenta_prefill or "102").strip() or "102")
        fi.insert(0, (fecha_ini or f"{datetime.now().year}-01-01").strip())
        ff.insert(0, (fecha_fin or hoy).strip())

        hint = tk.Label(
            d,
            text="Seleccione una fila con UUID: el detalle del CFDI aparece abajo. Doble clic también abre ventana emergente.",
            bg=THEME["bg_sidebar"],
            fg=THEME["text_secondary"],
            anchor="w",
            font=(THEME["font_ui"], 8),
        )
        hint.grid(row=1, column=0, sticky="ew", padx=10, pady=(0, 4))

        pv = ttk.Panedwindow(d, orient=tk.VERTICAL)
        pv.grid(row=2, column=0, sticky="nsew", padx=10, pady=0)
        tree_frame = tk.Frame(pv, bg=THEME["bg_content"])
        cfdi_frame = tk.LabelFrame(pv, text="Desglose CFDI (partida con UUID)", padx=8, pady=6, bg=THEME["bg_content"])
        pv.add(tree_frame, weight=4)
        pv.add(cfdi_frame, weight=1)
        tree_frame.grid_rowconfigure(0, weight=1)
        tree_frame.grid_columnconfigure(0, weight=1)

        txt_cfdi = tk.Text(cfdi_frame, height=6, font=(THEME["font_ui"], 9), wrap=tk.WORD, state=tk.DISABLED, bg="#fafafa")
        txt_cfdi.pack(fill=tk.BOTH, expand=True)

        cols = ("fecha", "tp", "np", "cm", "cargo", "abono", "saldo", "uuid", "cfdi_tot")
        tree = ttk.Treeview(tree_frame, columns=cols, show="headings")
        tree.heading("fecha", text="Fecha")
        tree.heading("tp", text="Tipo")
        tree.heading("np", text="#")
        tree.heading("cm", text="Concepto")
        tree.heading("cargo", text="Cargo")
        tree.heading("abono", text="Abono")
        tree.heading("saldo", text="Saldo")
        tree.heading("uuid", text="UUID (inicio)")
        tree.heading("cfdi_tot", text="Total CFDI")
        tree.column("fecha", width=96, anchor="center")
        tree.column("tp", width=64, anchor="center")
        tree.column("np", width=56, anchor="e")
        tree.column("cm", width=320, anchor="w")
        tree.column("cargo", width=100, anchor="e")
        tree.column("abono", width=100, anchor="e")
        tree.column("saldo", width=104, anchor="e")
        tree.column("uuid", width=140, anchor="w")
        tree.column("cfdi_tot", width=100, anchor="e")
        ysb = ttk.Scrollbar(tree_frame, orient="vertical", command=tree.yview)
        xsb = ttk.Scrollbar(tree_frame, orient="horizontal", command=tree.xview)
        tree.configure(yscrollcommand=ysb.set, xscrollcommand=xsb.set)
        tree.grid(row=0, column=0, sticky="nsew")
        ysb.grid(row=0, column=1, sticky="ns")
        xsb.grid(row=1, column=0, sticky="ew")

        tot_var = tk.StringVar(value="Saldo inicial: — | Totales periodo: Cargo 0.00 | Abono 0.00")
        tk.Label(d, textvariable=tot_var, anchor="w", bg=THEME["bg_sidebar"], fg=THEME["text_primary"]).grid(
            row=3, column=0, sticky="ew", padx=10, pady=(0, 8)
        )

        def _cfdi_panel_desde_seleccion(_evt=None):
            txt_cfdi.configure(state=tk.NORMAL)
            txt_cfdi.delete("1.0", tk.END)
            sel = tree.selection()
            if not sel:
                txt_cfdi.insert("1.0", "Seleccione un movimiento del mayor.")
                txt_cfdi.configure(state=tk.DISABLED)
                return
            tags = tree.item(sel[0], "tags") or ()
            pid = None
            for t in tags:
                s = str(t)
                if s.startswith("pp_"):
                    try:
                        pid = int(s[3:])
                    except Exception:
                        pid = None
                    break
            if not pid:
                txt_cfdi.insert("1.0", "Esta línea no tiene partida con UUID / CFDI vinculado.")
            else:
                txt_cfdi.insert("1.0", self._libro_texto_cfdi_por_partida(pid))
            txt_cfdi.configure(state=tk.DISABLED)

        def _mostrar_cfdi_desde_fila(_evt=None):
            sel = tree.selection()
            if not sel:
                return
            tags = tree.item(sel[0], "tags") or ()
            pid = None
            for t in tags:
                s = str(t)
                if s.startswith("pp_"):
                    try:
                        pid = int(s[3:])
                    except Exception:
                        pid = None
                    break
            if not pid:
                messagebox.showinfo("CFDI", "Esta línea no tiene partida con CFDI vinculado.")
                return
            rv = self.libro_contable.cfdi_por_partida(pid)
            if not rv.get("exito"):
                messagebox.showwarning("CFDI", rv.get("error", "Sin datos CFDI."))
                return
            txt = self._libro_texto_cfdi_por_partida(pid)
            w = tk.Toplevel(d)
            w.title("Detalle CFDI (partida)")
            w.transient(d)
            t = tk.Text(w, width=72, height=18, font=(THEME["font_ui"], 9), wrap=tk.WORD)
            t.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
            t.insert("1.0", txt)
            t.configure(state=tk.DISABLED)
            tk.Button(w, text="Cerrar", command=w.destroy).pack(pady=(0, 10))
            self._fit_toplevel(w, 0.45, 0.5, 560, 420)

        tree.bind("<<TreeviewSelect>>", _cfdi_panel_desde_seleccion)
        tree.bind("<Double-1>", _mostrar_cfdi_desde_fila)

        def generar():
            res = self.libro_contable.libro_mayor_cuenta(cta.get().strip(), fi.get().strip(), ff.get().strip())
            if not res.get("exito"):
                messagebox.showerror("Libro mayor", res.get("error", "No se pudo generar."))
                return
            for i in tree.get_children():
                tree.delete(i)
            rows = res.get("lineas") or []
            tc = ta = 0.0
            for r in rows:
                cargo = float(r.get("cargo") or 0)
                abono = float(r.get("abono") or 0)
                tc += cargo
                ta += abono
                uuid = (r.get("uuid") or "").strip()
                uuid_c = (uuid[:13] + "…") if len(uuid) > 13 else uuid
                tot_cfdi = r.get("total_cfdi")
                tot_txt = f"{float(tot_cfdi):,.2f}" if tot_cfdi is not None else "—"
                pid = r.get("id_partida")
                tags = (f"pp_{int(pid)}",) if pid and uuid else ()
                tree.insert(
                    "",
                    tk.END,
                    tags=tags,
                    values=(
                        r.get("fecha", ""),
                        r.get("tipo_poliza", ""),
                        r.get("numero_poliza", ""),
                        (r.get("concepto_mov") or "")[:120],
                        f"{cargo:,.2f}",
                        f"{abono:,.2f}",
                        f"{float(r.get('saldo') or 0):,.2f}",
                        uuid_c or "—",
                        tot_txt,
                    ),
                )
            si = float(res.get("saldo_inicial") or 0.0)
            tot_var.set(
                f"Fuente: {res.get('fuente','')} | Naturaleza: {res.get('naturaleza','')} | "
                f"Saldo inicial (antes del periodo): {si:,.2f} | "
                f"Totales periodo: Cargo {tc:,.2f} | Abono {ta:,.2f} | Movs: {len(rows)}"
            )
            self.set_status(f"Libro mayor: {len(rows)} movimientos")
            self._set_tabla_activa(tree)

        b = tk.Frame(d, padx=10, pady=6, bg=THEME["bg_content"])
        b.grid(row=4, column=0, sticky="ew")
        tk.Button(b, text="Generar", command=generar, bg=THEME["btn_secondary_bg"]).pack(side=tk.LEFT)
        tk.Button(
            b,
            text="Vista previa / PDF",
            command=lambda: self.vista_previa_tabla_visible("Libro mayor"),
            bg=THEME["btn_primary_bg"],
            fg=THEME["btn_primary_fg"],
            relief=tk.FLAT,
            padx=12,
            pady=4,
            cursor="hand2",
        ).pack(side=tk.LEFT, padx=8)
        tk.Button(b, text="Exportar CSV (Excel)", command=self.exportar_excel, bg=THEME["btn_secondary_bg"]).pack(side=tk.LEFT, padx=4)
        tk.Button(b, text="Cerrar", command=d.destroy).pack(side=tk.RIGHT)
        self._fit_toplevel(d, 0.88, 0.72, 1080, 620)
        generar()

