        def _llenar_lineas(_evt=None):
            for x in t_lin.get_children():
                t_lin.delete(x)
            _cfdi_panel_libro_diario()
            sel = t_pol.selection()
            if not sel:
                return
            p = pol_map.get(sel[0])
            if not p:
                return
            for ln in p.get("lineas") or []:
                uuid = (ln.get("uuid") or "").strip()
                uuid_c = (uuid[:13] + "…") if len(uuid) > 13 else (uuid or "—")
                cfdi = ln.get("cfdi") or {}
                tot_cfdi = cfdi.get("total_cfdi")
                tot_txt = f"{float(tot_cfdi):,.2f}" if tot_cfdi is not None else "—"
                pid = ln.get("id_partida")
                tags = (f"pp_{int(pid)}",) if pid is not None and uuid else ()
                t_lin.insert(
                    "",
                    tk.END,
                    tags=tags,
                    values=(
                        ln.get("numero_linea", ""),
                        ln.get("num_cuenta", ""),
                        (ln.get("concepto_linea") or "")[:140],
                        f"{float(ln.get('cargo') or 0):,.2f}",
                        f"{float(ln.get('abono') or 0):,.2f}",
                        uuid_c,
                        tot_txt,
                    ),
                )

        t_pol.bind("<<TreeviewSelect>>", _llenar_lineas)

        def generar():
            nonlocal pol_map
            pol_map = {}
            tip = tipo_cb.get()
            tipos = None if tip == "TODAS" else [tip]
            res = self.libro_contable.libro_diario(fi.get().strip(), ff.get().strip(), tipos_poliza=tipos)
            if not res.get("exito"):
                messagebox.showerror("Libro diario", res.get("error", "Error"))
                return
            for x in t_pol.get_children():
                t_pol.delete(x)
            for x in t_lin.get_children():
                t_lin.delete(x)
            for p in res.get("polizas") or []:
                iid = str(p.get("id_poliza"))
                pol_map[iid] = p
                t_pol.insert(
                    "",
                    tk.END,
                    iid=iid,
                    values=(
                        p.get("fecha"),
                        p.get("tipo_poliza"),
                        p.get("numero_poliza"),
                        (p.get("concepto") or "")[:80],
                        f"{float(p.get('total_cargo') or 0):,.2f}",
                        f"{float(p.get('total_abono') or 0):,.2f}",
                    ),
                )
            tp = res.get("totales_periodo") or {}
            pie.set(
                f"Fuente: {res.get('fuente')} | Pólizas: {len(pol_map)} | "
                f"Total cargo periodo: ${float(tp.get('cargo') or 0):,.2f} | "
                f"Total abono periodo: ${float(tp.get('abono') or 0):,.2f}"
            )
            self._set_tabla_activa(t_pol)
            self.set_status("Libro diario generado")
            _cfdi_panel_libro_diario()

