        tk.Button(bf, text="Vista previa / PDF", command=lambda: self.vista_previa_tabla_visible("Libro diario"), bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=10).pack(side=tk.LEFT, padx=6)
        tk.Button(bf, text="Exportar CSV", command=self.exportar_excel, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=8).pack(side=tk.LEFT)
        tk.Button(bf, text="Cerrar", command=d.destroy).pack(side=tk.RIGHT)
        self._fit_toplevel(d, 0.92, 0.78, 1120, 680)
        generar()

