            if not p:
                return
            for ln in p.get("lineas") or []:
                uuid = (ln.get("uuid") or "").strip()
                uuid_c = (uuid[:11] + "…") if len(uuid) > 11 else (uuid or "—")
                cfdi = ln.get("cfdi") or {}
                tot_cfdi = cfdi.get("total_cfdi")
