            for x in t_res.get_children():
                t_res.delete(x)
            for p in res.get("polizas") or []:
                iid = str(p.get("id_poliza"))
                pol_map[iid] = p
                t_pol.insert(
                    "",
                    tk.END,
                    iid=iid,
                    values=(
                        p.get("fecha"),
                        p.get("tipo_poliza"),
                        p.get("numero_poliza"),
                        (p.get("concepto") or "")[:90],
                        f"{float(p.get('total_cargo') or 0):,.2f}",
                        f"{float(p.get('total_abono') or 0):,.2f}",
                    ),
                )
            tp = res.get("totales_periodo") or {}
            pie.set(
                f"Fuente: {res.get('fuente')} | Pólizas: {len(pol_map)} | "
                f"Cargo: ${float(tp.get('cargo') or 0):,.2f} | Abono: ${float(tp.get('abono') or 0):,.2f}"
            )
            self._set_tabla_activa(t_pol)
            self.set_status("Diario/Mayor integrado generado")

