        def _hub_subtitulo() -> str:
            try:
                e, p = _periodo()
                rfc = rfc_e.get().strip().upper()
                return f"Periodo {p:02d}/{e}  RFC: {rfc}"
            except Exception:
                return ""

        def _hub_vista_previa():
            idx = nb.index(nb.select())
            tr = tab_trees[idx]
            headers, rows = self._treeview_encabezados_y_filas(tr)
            if not rows:
                messagebox.showwarning("Vista previa", "Use Generar en esta pestaña primero.")
                return
            self.impresion.vista_previa_reportes_avanzados(
                self.root,
                hub_titles[idx],
                rows,
                columnas=headers,
                empresa=self.empresa_actual,
            )

        def _hub_guardar_pdf():
            idx = nb.index(nb.select())
            tr = tab_trees[idx]
            headers, rows = self._treeview_encabezados_y_filas(tr)
            if not rows:
                messagebox.showwarning("PDF", "Use Generar en esta pestaña primero.")
                return
            try:
                from tkinter import filedialog

                from backend.modules.export_estados_libros import export_pdf_tabla
            except Exception as ex:
                messagebox.showerror("PDF", str(ex))
                return
            safe = "".join(c if c.isalnum() else "_" for c in hub_titles[idx])[:40]
            fn = f"Fiscal_{safe}_{anio_e.get().strip()}_{mes_cb.get()}.pdf"
            path = filedialog.asksaveasfilename(
                defaultextension=".pdf",
                initialfile=fn,
                filetypes=[("PDF", "*.pdf"), ("Todos", "*.*")],
            )
            if not path:
                return
            r = export_pdf_tabla(
                hub_titles[idx],
                rows,
                headers,
                path,
                empresa=self.empresa_actual or "",
                subtitulo=_hub_subtitulo(),
                rfc_empresa=(self._rfc_empresa_para_xml() or "").strip(),
            )
            if r.get("exito"):
                messagebox.showinfo("PDF", f"Guardado:\n{r.get('ruta')}")
            else:
                messagebox.showerror("PDF", r.get("error", "Error"))

        tk.Label(d, textvariable=cuadre_var, anchor="w", justify=tk.LEFT, wraplength=880, fg=THEME["text_primary"]).grid(
            row=1, column=0, sticky="ew", padx=10, pady=4
        )

        bf = tk.Frame(d, padx=8, pady=6)
        bf.grid(row=3, column=0, sticky="ew")

        def _export():
            idx = nb.index(nb.select())
            self._set_tabla_activa(tab_trees[idx])
            self.exportar_excel()

