        tk.Button(bf, text="Guardar PDF (pestaña actual)", command=_hub_guardar_pdf, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=10).pack(side=tk.LEFT, padx=6)
        tk.Button(bf, text="Exportar CSV (pestaña actual)", command=_export, bg=THEME["btn_secondary_bg"], relief=tk.FLAT, padx=10).pack(side=tk.LEFT, padx=6)
        tk.Button(bf, text="Cerrar", command=d.destroy).pack(side=tk.RIGHT)
        self._sincronizar_panel_lateral_modulo("Reportes fiscales SAT", "fiscal_sat")
