                        f"{float(x.get('iva_trasladado') or 0):,.2f}",
                        f"{float(x.get('iva_retenido') or 0):,.2f}",
                        f"{float(x.get('isr_retenido') or 0):,.2f}",
                        f"{float(x.get('total') or 0):,.2f}",
