    def mostrar_diot(self):
        """DIOT (base): resumen por proveedor desde cfdi_poliza (pólizas afectadas)."""
        if not self._requiere_permiso("fiscal", "DIOT"):
            return
        try:
            from backend.modules.diot import DiotManager
        except Exception:
            messagebox.showerror("Error", "Módulo DIOT no disponible.")
            return

        dm = DiotManager()
        d = tk.Toplevel(self.root)
        d.title("DIOT (Proveedores)")
        d.transient(self.root)
        d.resizable(True, True)
        try:
            d.minsize(760, 520)
        except Exception:
            pass

        main = tk.Frame(d, padx=12, pady=12)
        main.grid(row=0, column=0, sticky="nsew")
        d.grid_rowconfigure(0, weight=1)
        d.grid_columnconfigure(0, weight=1)
        main.grid_rowconfigure(2, weight=1)  # tree
        main.grid_columnconfigure(0, weight=1)

        top = tk.Frame(main)
        top.grid(row=0, column=0, sticky="ew")
        tk.Label(top, text="Mes:").pack(side=tk.LEFT, padx=4)
        mes = ttk.Combobox(top, values=[f"{i:02d}" for i in range(1, 13)], width=6, state="readonly")
        mes.set(f"{datetime.now().month:02d}")
        mes.pack(side=tk.LEFT, padx=4)
        tk.Label(top, text="Año:").pack(side=tk.LEFT, padx=(12, 4))
        anio = tk.Entry(top, width=8)
        anio.insert(0, str(datetime.now().year))
        anio.pack(side=tk.LEFT, padx=4)

        var_filtrar_empresa = tk.BooleanVar(value=True)
        rfc_emp = (self._rfc_empresa_para_xml() or "").strip().upper()
        tk.Checkbutton(
            top,
            text=f"Solo CFDI recibidos (RFC receptor = {rfc_emp or '—'})",
            variable=var_filtrar_empresa,
        ).pack(side=tk.LEFT, padx=(16, 0))

        resumen_lbl = tk.Label(main, text="", fg=THEME["text_primary"], anchor="w", justify=tk.LEFT)
        resumen_lbl.grid(row=1, column=0, sticky="ew", pady=(10, 8))

        cols = ("RFC proveedor", "CFDI", "Subtotal", "IVA trasladado", "IVA retenido", "ISR retenido", "Total")
        tree_frame = tk.Frame(main)
        tree_frame.grid(row=2, column=0, sticky="nsew")
        tree_frame.grid_rowconfigure(0, weight=1)
        tree_frame.grid_columnconfigure(0, weight=1)
        tree = ttk.Treeview(tree_frame, columns=cols, show="headings", height=10)
        for c in cols:
            tree.heading(c, text=c)
            w = 90 if c == "CFDI" else 140 if c != "RFC proveedor" else 160
            tree.column(c, width=w, anchor="e" if c != "RFC proveedor" else "w")
        ysb = ttk.Scrollbar(tree_frame, orient="vertical", command=tree.yview)
        tree.configure(yscrollcommand=ysb.set)
        tree.grid(row=0, column=0, sticky="nsew")
        ysb.grid(row=0, column=1, sticky="ns")
        tree.bind("<FocusIn>", lambda _e: self._set_tabla_activa(tree))

        def generar():
            try:
                p = int(mes.get())
                e = int(anio.get().strip())
            except Exception:
                messagebox.showerror("Error", "Mes/Año inválidos.")
                return
            filtro_rfc = rfc_emp if (var_filtrar_empresa.get() and rfc_emp) else ""
            rows = dm.resumen_periodo(e, p, rfc_empresa=filtro_rfc, max_rows=2000)
            for i in tree.get_children():
                tree.delete(i)
            ts = ti = tir = tisr = tt = 0.0
            for r in rows:
                ts += float(r.get("subtotal") or 0)
                ti += float(r.get("iva_trasladado") or 0)
                tir += float(r.get("iva_retenido") or 0)
                tisr += float(r.get("isr_retenido") or 0)
                tt += float(r.get("total") or 0)
                tree.insert(
                    "",
                    tk.END,
                    values=(
                        r.get("rfc_proveedor", "") or "",
                        r.get("cfdi", 0),
                        f"{float(r.get('subtotal') or 0):,.2f}",
                        f"{float(r.get('iva_trasladado') or 0):,.2f}",
                        f"{float(r.get('iva_retenido') or 0):,.2f}",
                        f"{float(r.get('isr_retenido') or 0):,.2f}",
                        f"{float(r.get('total') or 0):,.2f}",
                    ),
                )
            resumen_lbl.config(
                text=(
                    f"Periodo {p:02d}/{e}  |  Proveedores: {len(rows)}\n"
                    f"Subtotal: ${ts:,.2f}   IVA trasladado: ${ti:,.2f}   IVA retenido: ${tir:,.2f}   ISR retenido: ${tisr:,.2f}\n"
                    f"Total: ${tt:,.2f}"
                )
            )
            self.set_status(f"DIOT: {len(rows)} proveedor(es) para {p:02d}/{e}")

        bf = tk.Frame(main)
        bf.grid(row=3, column=0, sticky="ew", pady=(10, 0))
        tk.Button(
            bf,
            text="Generar",
            command=generar,
            bg=THEME["btn_primary_bg"],
            fg=THEME["btn_primary_fg"],
            relief=tk.FLAT,
            padx=12,
            pady=6,
            cursor="hand2",
        ).pack(side=tk.LEFT)
        tk.Button(
            bf,
            text="Vista previa / PDF",
            command=lambda: (self._set_tabla_activa(tree), self.vista_previa_tabla_visible("DIOT (proveedores)")),
            bg=THEME["btn_secondary_bg"],
            relief=tk.FLAT,
            padx=12,
            pady=6,
            cursor="hand2",
        ).pack(side=tk.LEFT, padx=8)
        tk.Button(bf, text="Exportar CSV (Excel)", command=lambda: (self._set_tabla_activa(tree), self.exportar_excel()), bg=THEME["btn_secondary_bg"]).pack(side=tk.LEFT, padx=4)
        def _exportar_diot_txt():
            try:
                p = int(mes.get())
                e = int(anio.get().strip())
            except Exception:
                messagebox.showerror("Error", "Mes/Año inválidos.")
                return
            filtro_rfc = rfc_emp if (var_filtrar_empresa.get() and rfc_emp) else ""
            from tkinter import filedialog
            ruta = filedialog.asksaveasfilename(
                title="Guardar DIOT (TXT layout SAT)",
                defaultextension=".txt",
                initialfile=f"DIOT_{e}{p:02d}.txt",
                filetypes=[("TXT", "*.txt"), ("Todos", "*.*")],
            )
            if not ruta:
                return
            r = dm.export_layout_txt_2025(e, p, rfc_empresa=filtro_rfc, output_path=ruta)
            if not r.get("exito"):
                messagebox.showerror("Error", r.get("error", "No se pudo exportar DIOT."))
                return
            messagebox.showinfo("DIOT", f"Archivo generado:\n{ruta}\nProveedores: {r.get('proveedores')}")

        tk.Button(bf, text="Exportar DIOT .txt", command=_exportar_diot_txt, bg=THEME["btn_secondary_bg"]).pack(side=tk.LEFT, padx=4)
        tk.Button(bf, text="Cerrar", command=d.destroy).pack(side=tk.RIGHT)

        generar()
        self._fit_toplevel(d, 0.78, 0.72, 980, 640)

    def mostrar_usuarios(self):
        """Gestión de usuarios con permisos por módulo."""
        if not self._requiere_permiso("configuracion", "Usuarios"):
            return
        d = tk.Toplevel(self.root)
        d.title("Usuarios y permisos")
        d.transient(self.root)
        d.resizable(True, True)

        top = tk.Frame(d, padx=10, pady=8)
        top.pack(fill=tk.X)
        tk.Label(top, text="Usuario:").grid(row=0, column=0, sticky="w")
        e_usuario = tk.Entry(top, width=18)
        e_usuario.grid(row=0, column=1, padx=4)
        tk.Label(top, text="Nombre:").grid(row=0, column=2, sticky="w", padx=(12, 0))
        e_nombre = tk.Entry(top, width=34)
        e_nombre.grid(row=0, column=3, padx=4)

        var_activo = tk.BooleanVar(value=True)
        var_admin = tk.BooleanVar(value=False)
        tk.Checkbutton(top, text="Activo", variable=var_activo).grid(row=1, column=0, columnspan=2, sticky="w", pady=3)
        tk.Checkbutton(top, text="Administrador", variable=var_admin).grid(row=1, column=2, columnspan=2, sticky="w", pady=3)

        pf = tk.LabelFrame(d, text="Permisos por módulo", padx=8, pady=6)
        pf.pack(fill=tk.X, padx=10, pady=(0, 8))
        vars_perm = {}
        for i, (k, nom) in enumerate(PERMISOS_DISPONIBLES):
            vv = tk.BooleanVar(value=False)
            vars_perm[k] = vv
            tk.Checkbutton(pf, text=nom, variable=vv).grid(row=i // 2, column=i % 2, sticky="w", padx=4, pady=2)

        tree = ttk.Treeview(d, columns=("usuario", "nombre", "activo", "admin"), show="headings")
        for c, t, w in (
            ("usuario", "Usuario", 140),
            ("nombre", "Nombre", 320),
            ("activo", "Activo", 90),
            ("admin", "Admin", 90),
        ):
            tree.heading(c, text=t)
            tree.column(c, width=w, anchor="center" if c != "nombre" else "w")
        tree.pack(fill=tk.BOTH, expand=True, padx=10, pady=(0, 8))

        def _limpiar_form():
            e_usuario.delete(0, tk.END)
            e_nombre.delete(0, tk.END)
            var_activo.set(True)
            var_admin.set(False)
            for k in vars_perm:
                vars_perm[k].set(False)

        def _cargar_tabla():
            for i in tree.get_children():
                tree.delete(i)
            for u in self.usuarios_sistema.listar():
                tree.insert(
                    "",
                    tk.END,
                    values=(
                        u.get("usuario", ""),
                        u.get("nombre", ""),
                        "Sí" if u.get("activo") else "No",
                        "Sí" if u.get("es_admin") else "No",
                    ),
                )

        def _desde_seleccion(_ev=None):
            sel = tree.selection()
            if not sel:
                return
            vals = tree.item(sel[0], "values")
            u = str(vals[0])
            reg = self.usuarios_sistema.obtener(u)
            if not reg:
                return
            e_usuario.delete(0, tk.END)
            e_usuario.insert(0, reg.get("usuario", ""))
            e_nombre.delete(0, tk.END)
            e_nombre.insert(0, reg.get("nombre", ""))
            var_activo.set(bool(reg.get("activo")))
            var_admin.set(bool(reg.get("es_admin")))
            perms = set(reg.get("permisos") or [])
            for k in vars_perm:
                vars_perm[k].set(k in perms)

        def _guardar():
            perms = [k for k, v in vars_perm.items() if v.get()]
            r = self.usuarios_sistema.crear_o_actualizar(
                usuario=e_usuario.get().strip(),
                nombre=e_nombre.get().strip(),
                activo=var_activo.get(),
                es_admin=var_admin.get(),
                permisos=perms,
            )
            if not r.get("exito"):
                messagebox.showerror("Error", r.get("error", "No se pudo guardar"))
                return
            _cargar_tabla()
            if (e_usuario.get().strip().upper() == self.usuario_actual.strip().upper()):
                self._refrescar_perfil_usuario()
            messagebox.showinfo("Usuarios", "Usuario guardado.")

        def _eliminar():
            u = e_usuario.get().strip().upper()
            if not u:
                messagebox.showinfo("Info", "Seleccione un usuario.")
                return
            if not messagebox.askyesno("Confirmar", f"¿Eliminar usuario {u}?"):
                return
            r = self.usuarios_sistema.eliminar(u)
            if not r.get("exito"):
                messagebox.showerror("Error", r.get("error", "No se pudo eliminar"))
                return
            _limpiar_form()
            _cargar_tabla()

        tree.bind("<<TreeviewSelect>>", _desde_seleccion)
        b = tk.Frame(d, padx=10, pady=6)
        b.pack(fill=tk.X)
        tk.Button(b, text="Nuevo", command=_limpiar_form).pack(side=tk.LEFT)
        tk.Button(b, text="Guardar", command=_guardar, bg=THEME["btn_secondary_bg"]).pack(side=tk.LEFT, padx=6)
        tk.Button(b, text="Eliminar", command=_eliminar).pack(side=tk.LEFT)
        tk.Button(
            b,
            text="Vista previa / PDF",
            command=lambda: self.vista_previa_tabla_visible("Usuarios y permisos"),
            bg=THEME["btn_primary_bg"],
            fg=THEME["btn_primary_fg"],
            relief=tk.FLAT,
            padx=12,
            cursor="hand2",
        ).pack(side=tk.LEFT, padx=8)
        tk.Button(b, text="Exportar CSV (Excel)", command=self.exportar_excel, bg=THEME["btn_secondary_bg"]).pack(side=tk.LEFT, padx=4)
        tk.Button(b, text="Cerrar", command=d.destroy).pack(side=tk.RIGHT)

        _cargar_tabla()
        self._fit_toplevel(d, 0.62, 0.72, 860, 560)

    def mostrar_reporte_presupuesto_centros(self):
        """Comparativo presupuesto anual por cuenta/centro vs cargos ejecutados YTD."""
        if not self._requiere_permiso("reportes", "Real vs presupuesto por centro"):
            return
        try:
            from backend.modules.presupuesto_centro_costo import PresupuestoCentroCosto
        except Exception as e:
            messagebox.showerror("Reporte", str(e))
            return
        pm = PresupuestoCentroCosto(db_path=self.polizas.db_path)
        d = tk.Toplevel(self.root)
